# OEM multi-select pill dropdown controls
$btn_OEMToggle = $Window.FindName('btn_OEMToggle')
$txt_OEMDisplay = $Window.FindName('txt_OEMDisplay')
$popup_OEM = $Window.FindName('popup_OEM')
$script:OEMCheckboxes = @{
    'Acer'      = $Window.FindName('chk_OEM_Acer')
    'Dell'      = $Window.FindName('chk_OEM_Dell')
    'HP'        = $Window.FindName('chk_OEM_HP')
    'Lenovo'    = $Window.FindName('chk_OEM_Lenovo')
    'Microsoft' = $Window.FindName('chk_OEM_Microsoft')
}
$script:OEMBorders = @{
    'Acer'      = $Window.FindName('border_OEM_Acer')
    'Dell'      = $Window.FindName('border_OEM_Dell')
    'HP'        = $Window.FindName('border_OEM_HP')
    'Lenovo'    = $Window.FindName('border_OEM_Lenovo')
    'Microsoft' = $Window.FindName('border_OEM_Microsoft')
}

function Get-DATSelectedOEMs {
    $selected = @()
    foreach ($entry in $script:OEMCheckboxes.GetEnumerator()) {
        if ($entry.Value.IsChecked -eq $true) { $selected += $entry.Key }
    }
    return $selected
}

function Update-DATOEMDisplayText {
    $selected = Get-DATSelectedOEMs
    if ($selected.Count -eq 0) {
        $txt_OEMDisplay.Text = 'Select OEMs...'
    } elseif ($selected.Count -le 3) {
        $txt_OEMDisplay.Text = $selected -join ', '
    } else {
        $txt_OEMDisplay.Text = "$($selected.Count) selected"
    }
}

function Update-DATOEMSelectionHighlight {
    $brushSelected = $Window.FindResource('ButtonPrimary')
    $brushTransparent = [System.Windows.Media.Brushes]::Transparent
    foreach ($entry in $script:OEMCheckboxes.GetEnumerator()) {
        $border = $script:OEMBorders[$entry.Key]
        if ($null -ne $border) {
            $border.Background = if ($entry.Value.IsChecked -eq $true) { $brushSelected } else { $brushTransparent }
        }
    }
}

# Wire checkbox change events to update display text and highlight.
# Model refresh is deferred until the OEM popup closes (see popup_OEM.Closed
# handler below) so toggling multiple OEMs doesn't trigger repeated refreshes.
$script:OEMSelectionDirty = $false
$oemSelectionChangedHandler = {
    Update-DATOEMDisplayText
    Update-DATOEMSelectionHighlight
    if (-not $script:SuppressModelRefresh) {
        $script:OEMSelectionDirty = $true
    }
}
foreach ($chk in $script:OEMCheckboxes.Values) {
    $chk.Add_Checked($oemSelectionChangedHandler)
    $chk.Add_Unchecked($oemSelectionChangedHandler)
}

# When the OEM popup closes, refresh the model list if any OEMs were toggled.
$popup_OEM.Add_Closed({
    if (-not $script:OEMSelectionDirty) { return }
    $script:OEMSelectionDirty = $false
    # Persist OEM selection to registry immediately
    $currentOEMs = Get-DATSelectedOEMs
    Set-DATRegistryValue -Name "SelectedOEMs" -Value ($currentOEMs -join ',') -Type String
    if ($script:SuppressModelRefresh) { return }
    if ((Get-DATSelectedOEMs).Count -gt 0 -and (Get-DATSelectedOSes).Count -gt 0) {
        if ($script:ModelData.Count -gt 0) { Save-DATModelSelections }
        Invoke-DATRefreshModelsClick
    } else {
        # No OEMs selected (or no OS) -- clear the model grid
        if ($script:ModelData.Count -gt 0) {
            Save-DATModelSelections
            $script:ModelData.Clear()
        }
    }
})

# OS multi-select pill dropdown controls
$btn_OSToggle = $Window.FindName('btn_OSToggle')
$txt_OSDisplay = $Window.FindName('txt_OSDisplay')
$popup_OS = $Window.FindName('popup_OS')
$script:OSCheckboxes = [ordered]@{
    'Windows 11 25H2' = $Window.FindName('chk_OS_Win11_25H2')
    'Windows 11 24H2' = $Window.FindName('chk_OS_Win11_24H2')
    'Windows 11 23H2' = $Window.FindName('chk_OS_Win11_23H2')
    'Windows 11 22H2' = $Window.FindName('chk_OS_Win11_22H2')
    'Windows 11 21H2' = $Window.FindName('chk_OS_Win11_21H2')
}
$script:OSBorders = [ordered]@{
    'Windows 11 25H2' = $Window.FindName('border_OS_Win11_25H2')
    'Windows 11 24H2' = $Window.FindName('border_OS_Win11_24H2')
    'Windows 11 23H2' = $Window.FindName('border_OS_Win11_23H2')
    'Windows 11 22H2' = $Window.FindName('border_OS_Win11_22H2')
    'Windows 11 21H2' = $Window.FindName('border_OS_Win11_21H2')
}

# Backing store for selected OS values -- survives regardless of popup/checkbox state
$script:SelectedOSValues = [System.Collections.Generic.List[string]]::new()

function Get-DATSelectedOSes {
    # Use Write-Output -NoEnumerate so callers always receive an array, even when
    # only a single OS is selected. Without this, PowerShell unwraps the single-element
    # array at the function boundary and the caller gets a bare string -- then
    # $selectedOSes[0] returns the first CHARACTER (e.g. 'W' from "Windows 11"), which
    # has previously caused ConfigMgr package folder paths like "Packages\Dell\Latitude 5400\W\x64\A00".
    Write-Output -NoEnumerate @($script:SelectedOSValues)
}

function Update-DATOSDisplayText {
    # Force [array] so that a single-OS result is never unwrapped to a bare string by PowerShell's
    # pipeline. Without this, $selected[0] on a bare string returns the first character ('W'),
    # causing the display to show "W" instead of the full OS name.
    [array]$selected = Get-DATSelectedOSes
    if ($selected.Count -eq 0) {
        $txt_OSDisplay.Text = 'Select OS...'
    } elseif ($selected.Count -eq 1) {
        # Show the full OS name for a single selection (e.g. "Windows 11 25H2")
        $txt_OSDisplay.Text = $selected[0]
    } else {
        $txt_OSDisplay.Text = "$($selected.Count) selected"
    }
}

function Update-DATOSSelectionHighlight {
    $brushSelected = $Window.FindResource('ButtonPrimary')
    $brushTransparent = [System.Windows.Media.Brushes]::Transparent
    foreach ($entry in $script:OSCheckboxes.GetEnumerator()) {
        $border = $script:OSBorders[$entry.Key]
        if ($null -ne $border) {
            $border.Background = if ($entry.Value.IsChecked -eq $true) { $brushSelected } else { $brushTransparent }
        }
    }
}

# Wire OS checkbox change events -- deferred refresh on popup close (like OEM)
$script:OSSelectionDirty = $false
$osSelectionChangedHandler = {
    if ($script:SuppressOSSync) { return }
    # Rebuild backing store from checkbox state
    $script:SelectedOSValues.Clear()
    foreach ($entry in $script:OSCheckboxes.GetEnumerator()) {
        if ($null -ne $entry.Value -and $entry.Value.IsChecked -eq $true) {
            $script:SelectedOSValues.Add($entry.Key)
        }
    }
    Update-DATOSDisplayText
    Update-DATOSSelectionHighlight
    if (-not $script:SuppressModelRefresh) {
        $script:OSSelectionDirty = $true
    }
}
foreach ($chk in $script:OSCheckboxes.Values) {
    if ($null -ne $chk) {
        $chk.Add_Checked($osSelectionChangedHandler)
        $chk.Add_Unchecked($osSelectionChangedHandler)
    }
}

# Sync checkboxes from backing store when popup opens (ensures UI matches state)
$script:SuppressOSSync = $false
$popup_OS.Add_Opened({
    $script:SuppressOSSync = $true
    foreach ($entry in $script:OSCheckboxes.GetEnumerator()) {
        if ($null -ne $entry.Value) {
            $entry.Value.IsChecked = ($script:SelectedOSValues -contains $entry.Key)
        }
    }
    $script:SuppressOSSync = $false
    Update-DATOSSelectionHighlight
})

# When the OS popup closes, refresh the model list if any OS values were toggled.
$popup_OS.Add_Closed({
    if (-not $script:OSSelectionDirty) { return }
    $script:OSSelectionDirty = $false
    # Persist OS selection to registry immediately
    $currentOSes = Get-DATSelectedOSes
    Set-DATRegistryValue -Name "OS" -Value ($currentOSes -join ';') -Type String
    if ($script:SuppressModelRefresh) { return }
    if ((Get-DATSelectedOEMs).Count -gt 0 -and (Get-DATSelectedOSes).Count -gt 0) {
        if ($script:ModelData.Count -gt 0) { Save-DATModelSelections }
        Invoke-DATRefreshModelsClick
    } else {
        if ($script:ModelData.Count -gt 0) {
            Save-DATModelSelections
            $script:ModelData.Clear()
        }
    }
})

# Check for HP CMSL module availability
$script:HPCMSLAvailable = $null -ne (Get-Module -ListAvailable -Name HPCMSL -ErrorAction SilentlyContinue)
if (-not $script:HPCMSLAvailable) {
    $script:OEMCheckboxes['HP'].IsEnabled = $false
    $script:OEMCheckboxes['HP'].IsChecked = $false
    $script:OEMCheckboxes['HP'].Content = 'HP (CMSL not installed)'
    $script:OEMCheckboxes['HP'].ToolTip = 'Install the HPCMSL module to enable HP support: Install-Module HPCMSL'
    Write-DATActivityLog "HP CMSL module not found. HP device support is disabled. Install with: Install-Module HPCMSL" -Level Warn
    Write-DATLogEntry -Value "[Warning] - HP CMSL module (HPCMSL) not found. HP OEM selection disabled. Install with: Install-Module HPCMSL" -Severity 2
}

$script:ModelData = [System.Collections.ObjectModel.ObservableCollection[ModelItem]]::new()
$grid_Models.ItemsSource = $script:ModelData

# Toggle Selected on a ModelItem. Because ModelItem implements INotifyPropertyChanged,
# setting .Selected automatically notifies WPF and the bound CheckBox updates instantly --
# no visual-tree walking, no UpdateLayout() calls needed.
function Set-DATModelItemToggle {
    param($item)
    if ($null -eq $item) { return }
    $item.Selected = -not $item.Selected
    Update-DATBuildButtonState
    Save-DATModelSelections
}

# Mouse click: walk up to the DataGridRow and toggle.
$grid_Models.Add_PreviewMouseLeftButtonDown({
    param($s, $e)
    $dep = $e.OriginalSource
    while ($null -ne $dep -and $dep -isnot [System.Windows.Controls.DataGridRow]) {
        if ($dep -is [System.Windows.Controls.Primitives.DataGridColumnHeader]) { return }
        $dep = [System.Windows.Media.VisualTreeHelper]::GetParent($dep)
    }
    if ($null -eq $dep) { return }
    Set-DATModelItemToggle -item ($dep.DataContext -as [ModelItem])
})

# Space bar: toggle the currently selected row.
$grid_Models.Add_PreviewKeyDown({
    param($s, $e)
    if ($e.Key -ne [System.Windows.Input.Key]::Space) { return }
    Set-DATModelItemToggle -item ($grid_Models.SelectedItem -as [ModelItem])
    $e.Handled = $true  # prevent DataGrid's default Space behaviour (cell editing)
})

# Checkbox column sorting: checked items first on initial click
$grid_Models.Add_Sorting({
    param($s, $e)
    if ($e.Column.SortMemberPath -ne 'Selected') { return }
    $e.Handled = $true
    $view = [System.Windows.Data.CollectionViewSource]::GetDefaultView($script:ModelData)
    $view.SortDescriptions.Clear()

    # Toggle direction; default to descending (checked first)
    $currentDir = $e.Column.SortDirection
    if ($currentDir -eq [System.ComponentModel.ListSortDirection]::Descending) {
        $newDir = [System.ComponentModel.ListSortDirection]::Ascending
    } else {
        $newDir = [System.ComponentModel.ListSortDirection]::Descending
    }
    $view.SortDescriptions.Add([System.ComponentModel.SortDescription]::new('Selected', $newDir))
    $view.SortDescriptions.Add([System.ComponentModel.SortDescription]::new('OEM', [System.ComponentModel.ListSortDirection]::Ascending))
    $view.SortDescriptions.Add([System.ComponentModel.SortDescription]::new('Model', [System.ComponentModel.ListSortDirection]::Ascending))
    $e.Column.SortDirection = $newDir
})

# Model detail panel: show package details when a row is selected
$grid_Models.Add_SelectionChanged({
    param($s, $e)
    $item = $grid_Models.SelectedItem -as [ModelItem]
    if ($null -eq $item) {
        $panel_ModelDetail.Visibility = 'Collapsed'
        return
    }
    $txt_ModelDetail_OEM.Text        = $item.OEM
    $txt_ModelDetail_Model.Text      = $item.Model
    $txt_ModelDetail_OS.Text         = $item.OS
    $txt_ModelDetail_Build.Text      = $item.Build
    $txt_ModelDetail_Baseboards.Text = if ($item.Baseboards) { $item.Baseboards } else { '--' }

    # Known Model indicator -- check Intune and ConfigMgr known device lists
    $isKnown = $false
    $gridMake = ConvertTo-DATNormalizedMake -Make $item.OEM
    $gridModel = ConvertTo-DATNormalizedModel -Make $item.OEM -Model $item.Model
    if ($script:IntuneKnownDevices -and @($script:IntuneKnownDevices).Count -gt 0) {
        foreach ($device in $script:IntuneKnownDevices) {
            if (Test-DATKnownDeviceMatch -GridMake $gridMake -GridModel $gridModel -GridBaseboards $item.Baseboards `
                    -DeviceMake $device.Make -DeviceModel $device.Model -DeviceBaseboard $device.Baseboard) {
                $isKnown = $true; break
            }
        }
    }
    if (-not $isKnown -and $script:ConfigMgrKnownDevices -and @($script:ConfigMgrKnownDevices).Count -gt 0) {
        foreach ($device in $script:ConfigMgrKnownDevices) {
            if (Test-DATKnownDeviceMatch -GridMake $gridMake -GridModel $gridModel -GridBaseboards $item.Baseboards `
                    -DeviceMake $device.Make -DeviceModel $device.Model -DeviceBaseboard $device.Baseboard) {
                $isKnown = $true; break
            }
        }
    }
    if ($isKnown) {
        $txt_ModelDetail_KnownModel.Text       = 'Yes'
        $txt_ModelDetail_KnownModel.Foreground = [System.Windows.Media.SolidColorBrush]::new(
            [System.Windows.Media.ColorConverter]::ConvertFromString(
                (Get-DATTheme -ThemeName $script:CurrentTheme)['StatusSuccess']))
    } else {
        $txt_ModelDetail_KnownModel.Text       = 'No'
        $txt_ModelDetail_KnownModel.Foreground = $txt_ModelDetail_OEM.TryFindResource('InputPlaceholder')
    }
    $isBIOSOnly = try { [bool]$item.BIOSOnly } catch { $false }
    if ($isBIOSOnly) {
        $txt_ModelDetail_Version.Text       = 'N/A'
        $noPackBrush = $txt_ModelDetail_OEM.TryFindResource('DriverNoPackForeground')
        if ($noPackBrush) { $txt_ModelDetail_Version.Foreground = $noPackBrush }
    } else {
        $txt_ModelDetail_Version.Text       = if ($item.Version) { $item.Version } else { '--' }
        $txt_ModelDetail_Version.Foreground = $txt_ModelDetail_OEM.Foreground
    }
    try { $txt_ModelDetail_BIOS.Text = if ($item.BIOSVersion) { $item.BIOSVersion } else { '--' } } catch { $txt_ModelDetail_BIOS.Text = '--' }

    # NVIDIA GFX indicator
    if ($item.HasGFX) {
        $txt_ModelDetail_GFX.Text       = $item.GFXBrand
        $txt_ModelDetail_GFX.Foreground = [System.Windows.Media.BrushConverter]::new().ConvertFrom('#76B900')
    } else {
        $txt_ModelDetail_GFX.Text       = 'None'
        $txt_ModelDetail_GFX.Foreground = $txt_ModelDetail_OEM.TryFindResource('InputPlaceholder')
    }

    # Custom drivers path
    $txt_ModelDetail_CustomPath.Text = if (-not [string]::IsNullOrEmpty($item.CustomDriverPath)) { $item.CustomDriverPath } else { 'None' }

    $panel_ModelDetail.Visibility = 'Visible'
})

# Context menu: Add Custom Drivers
$ctx_AddCustomDrivers = $grid_Models.ContextMenu.Items | Where-Object { $_.Name -eq 'ctx_AddCustomDrivers' }
$ctx_ClearCustomDrivers = $grid_Models.ContextMenu.Items | Where-Object { $_.Name -eq 'ctx_ClearCustomDrivers' }
$ctx_ForcePackageUpdate = $grid_Models.ContextMenu.Items | Where-Object { $_.Name -eq 'ctx_ForcePackageUpdate' }

$ctx_AddCustomDrivers.Add_Click({
    $selectedItem = $grid_Models.SelectedItem
    if ($null -eq $selectedItem) { return }
    $result = Show-DATCustomDriverDialog -ModelName $selectedItem.Model -ExistingPath $selectedItem.CustomDriverPath
    if ($null -ne $result) {
        $selectedItem.CustomDriverPath = $result
        $txt_ModelDetail_CustomPath.Text = $result
        Write-DATActivityLog "Custom drivers set for $($selectedItem.OEM) $($selectedItem.Model): $result" -Level Info
    }
})

$ctx_ClearCustomDrivers.Add_Click({
    $selectedItem = $grid_Models.SelectedItem
    if ($null -eq $selectedItem) { return }
    if (-not [string]::IsNullOrEmpty($selectedItem.CustomDriverPath)) {
        $selectedItem.CustomDriverPath = $null
        $txt_ModelDetail_CustomPath.Text = 'None'
        Write-DATActivityLog "Custom drivers cleared for $($selectedItem.OEM) $($selectedItem.Model)" -Level Info
    }
})

$ctx_ForcePackageUpdate.Add_Click({
    $selectedItem = $grid_Models.SelectedItem
    if ($null -eq $selectedItem) { return }

    $selectedPlatform = if ($null -ne $cmb_Platform.SelectedItem) { $cmb_Platform.SelectedItem.Content } else { 'Download Only' }

    $confirmMsg = "Force update will replace the existing package for:`n`n$($selectedItem.OEM) $($selectedItem.Model)`n`nPlatform: $selectedPlatform`n`nThis will overwrite the current package content and redistribute."
    $result = Show-DATConfirmDialog -Title "Confirm Force Package Update" -Message $confirmMsg -ConfirmLabel "Yes, Continue"
    if (-not $result) { return }

    # Tag the model for force update
    if (-not ($selectedItem.PSObject.Properties.Name -contains 'ForceUpdate')) {
        $selectedItem | Add-Member -NotePropertyName 'ForceUpdate' -NotePropertyValue $true -Force
    } else {
        $selectedItem.ForceUpdate = $true
    }

    # Ensure model is selected
    $selectedItem.Selected = $true

    Write-DATActivityLog "Force update queued for $($selectedItem.OEM) $($selectedItem.Model) on $selectedPlatform" -Level Info
    $txt_Status.Text = "Force update queued -- click Build Package to proceed."
    $txt_Status.Foreground = [System.Windows.Media.SolidColorBrush]::new(
        [System.Windows.Media.ColorConverter]::ConvertFromString(
            (Get-DATTheme -ThemeName $script:CurrentTheme)['StatusWarning']))
    $txt_Status.Tag = 'StatusWarning'
    Update-DATBuildButtonState
})

# Enable/disable Clear option based on whether the right-clicked model has a custom path
$grid_Models.ContextMenu.Add_Opened({
    # Sync theme resources into the ContextMenu (separate visual tree from Window)
    $ctxMenu = $grid_Models.ContextMenu
    $themeDict = Get-DATThemeResourceDictionary -ThemeName $script:CurrentTheme
    $ctxMenu.Resources.MergedDictionaries.Clear()
    $ctxMenu.Resources.MergedDictionaries.Add($themeDict)

    $selectedItem = $grid_Models.SelectedItem
    $hasCDP = ($null -ne $selectedItem) -and -not [string]::IsNullOrEmpty($selectedItem.CustomDriverPath)
    $ctx_ClearCustomDrivers.IsEnabled = $hasCDP
    if ($hasCDP) {
        $ctx_ClearCustomDrivers.Header = "Clear Custom Drivers ($($selectedItem.CustomDriverPath))"
    } else {
        $ctx_ClearCustomDrivers.Header = "Clear Custom Drivers"
    }

    # Enable Force Update when a model is selected (works on any platform)
    $ctx_ForcePackageUpdate.IsEnabled = ($null -ne $selectedItem)
    if ($selectedItem -and $selectedItem.ForceUpdate -eq $true) {
        $ctx_ForcePackageUpdate.Header = "Force Existing Package Update (queued)"
    } else {
        $ctx_ForcePackageUpdate.Header = "Force Existing Package Update"
    }

    # Set DAT logo on the context menu header
    $headerLogo = $grid_Models.ContextMenu.Items[0].Template.FindName('ctx_HeaderLogo', $grid_Models.ContextMenu.Items[0])
    if ($null -ne $headerLogo -and $null -ne $script:bitmapImage) {
        $headerLogo.Source = $script:bitmapImage
    }
})

# Suppress auto-refresh during initial load/restore
$script:SuppressModelRefresh = $true

# Save Package Type immediately on change so the selection persists across restarts.
# Refresh the model list because BIOS / All shows additional BIOS-only models from
# the BIOS catalog that don't have a driver pack for the selected OS/build.
$cmb_PackageType.Add_SelectionChanged({
    if ($script:SuppressModelRefresh) { return }
    $selected = if ($null -ne $cmb_PackageType.SelectedItem) { $cmb_PackageType.SelectedItem.Content } else { 'Drivers' }
    Set-DATRegistryValue -Name "PackageType" -Value "$selected" -Type String
})

# Helper to programmatically invoke the Refresh Models button click
function Invoke-DATRefreshModelsClick {
    $peer = New-Object System.Windows.Automation.Peers.ButtonAutomationPeer($btn_RefreshModels)
    $invokeProvider = $peer.GetPattern([System.Windows.Automation.Peers.PatternInterface]::Invoke)
    $invokeProvider.Invoke()
}

# Refresh models when Architecture selection changes
$cmb_Architecture.Add_SelectionChanged({
    if ($script:SuppressModelRefresh) { return }
    if ((Get-DATSelectedOEMs).Count -gt 0 -and (Get-DATSelectedOSes).Count -gt 0) {
        # Save current selections before refresh clears the model list
        if ($script:ModelData.Count -gt 0) { Save-DATModelSelections }
        Invoke-DATRefreshModelsClick
    }
})

$btn_RefreshModels.Add_Click({
    # Capture selections on UI thread
    $selectedOEMs = Get-DATSelectedOEMs
    $selectedOSes = Get-DATSelectedOSes
    $selectedOS = $selectedOSes -join ';'
    $selectedArch = if ($null -ne $cmb_Architecture.SelectedItem) { $cmb_Architecture.SelectedItem.Content } else { "x64" }

    $selectedPlatformValue = if ($null -ne $cmb_Platform.SelectedItem) { $cmb_Platform.SelectedItem.Content } else { "Download Only" }

    # Save selections to registry for next launch
    Set-DATRegistryValue -Name "SelectedOEMs" -Value ($selectedOEMs -join ',') -Type String
    Set-DATRegistryValue -Name "OS" -Value "$selectedOS" -Type String
    Set-DATRegistryValue -Name "Architecture" -Value "$selectedArch" -Type String
    Set-DATRegistryValue -Name "Platform" -Value "$selectedPlatformValue" -Type String
    $selectedPackageType = if ($null -ne $cmb_PackageType.SelectedItem) { $cmb_PackageType.SelectedItem.Content } else { 'Drivers' }
    Set-DATRegistryValue -Name "PackageType" -Value "$selectedPackageType" -Type String

    Write-DATActivityLog "Selected OEMs: $($selectedOEMs -join ', ')" -Level Info
    Write-DATActivityLog "OS: $($selectedOSes -join ', ') | Architecture: $selectedArch | Platform: $selectedPlatformValue" -Level Info

    if ($selectedOEMs.Count -eq 0 -or $selectedOSes.Count -eq 0) {
        Write-DATActivityLog "Validation failed - select at least one OEM and an OS." -Level Warn
        $txt_Status.Text = "Please select at least one OEM and an operating system."
        return
    }

    # Update UI state
    $txt_Status.Text = "Refreshing models..."
    $progress_Job.Visibility = 'Visible'
    $progress_Job.IsIndeterminate = $true
    $btn_RefreshModels.IsEnabled = $false
    $script:ModelData.Clear()

    # Reset previous build status indicators so they don't persist across refreshes
    $pill_BuildStatus.Visibility = 'Collapsed'
    $txt_BuildElapsed.Visibility = 'Collapsed'
    $panel_BuildProgress.Visibility = 'Collapsed'

    Write-DATActivityLog "Starting model refresh..." -Level Info

    # Show the Loading Sources modal -- OEMs sorted A-Z
    Show-DATLoadingSourcesModal -OEMs ($selectedOEMs | Sort-Object)

    # Create background runspace with shared log queue
    $script:RefreshRunspace = [runspacefactory]::CreateRunspace()
    $script:RefreshRunspace.ApartmentState = 'STA'
    $script:RefreshRunspace.Open()

    # Pass the log queue into the runspace so it can post messages
    $script:RefreshRunspace.SessionStateProxy.SetVariable('LogQueue', $script:LogQueue)

    $script:RefreshPS = [powershell]::Create()
    $script:RefreshPS.Runspace = $script:RefreshRunspace
    # Resolve temp storage path from registry (same as build runspace) with fallback to app Temp folder
    $regConfig = Get-ItemProperty -Path $global:RegPath -ErrorAction SilentlyContinue
    $refreshTempDir = if ($regConfig -and -not [string]::IsNullOrEmpty($regConfig.TempStoragePath)) { $regConfig.TempStoragePath } else { Join-Path $global:ScriptDirectory 'Temp' }

    [void]$script:RefreshPS.AddScript({
        param($CoreModulePath, $RequiredOEMs, $OS, $Architecture, $PackageType, $TempDir, $UseDATAPICatalog, $WebRequestTimeoutSec, $HPDriverPackSource)

        function Write-Log {
            param([string]$Message, [string]$Level = 'Info')
            $ts = Get-Date -Format 'HH:mm:ss'
            $pfx = switch ($Level) { 'Info' { '[INFO]' } 'Warn' { '[WARN]' } 'Error' { '[ERROR]' } 'Success' { '[OK]' } default { '[INFO]' } }
            $LogQueue.Enqueue("$ts $pfx $Message")
            # Also write to the log file via the core module
            $severity = switch ($Level) { 'Error' { '3' } 'Warn' { '2' } default { '1' } }
            try { Write-DATLogEntry -Value $Message -Severity $severity } catch { }
        }

        # Cache freshness check -- returns $true if the file exists and was modified within $MaxAgeHours
        function Test-CatalogFresh {
            param([string]$FilePath, [int]$MaxAgeHours = 24)
            if (-not (Test-Path $FilePath)) { return $false }
            $age = (Get-Date) - (Get-Item $FilePath).LastWriteTime
            return $age.TotalHours -lt $MaxAgeHours
        }

        try {
            Write-Log "Importing core module..."
            Import-Module $CoreModulePath -Force -ErrorAction Stop
            Write-Log "Core module loaded successfully." -Level Success
        } catch {
            Write-Log "Failed to import module: $($_.Exception.Message)" -Level Error
            return @([PSCustomObject]@{ _Error = $_.Exception.Message })
        }

        # Use the configured temp storage path passed from the UI thread
        if (-not (Test-Path $TempDir)) { New-Item -Path $TempDir -ItemType Directory -Force | Out-Null }

        $OEMLinksURL = "https://raw.githubusercontent.com/maurice-daly/DriverAutomationTool/master/Data/OEMLinks.xml"
        $OEMLinksCache = Join-Path $TempDir "OEMLinks.xml"

        try {
            [Net.ServicePointManager]::SecurityProtocol = (
                [Net.ServicePointManager]::SecurityProtocol -bor
                [Net.SecurityProtocolType]::Tls12
            )
            try {
                if ([Enum]::IsDefined([Net.SecurityProtocolType], 12288)) {
                    [Net.ServicePointManager]::SecurityProtocol = (
                        [Net.ServicePointManager]::SecurityProtocol -bor
                        ([Net.SecurityProtocolType]12288)
                    )
                }
            } catch { }
            $proxyParams = Get-DATWebRequestProxy
            if ($proxyParams -isnot [hashtable]) { $proxyParams = @{} }

            # ── DAT API connectivity check ──
            $LogQueue.Enqueue('[SOURCE:DATAPI:Loading]')
            $datApiUrl = 'https://api.driverautomationtool.com/api/health'
            try {
                $apiResponse = Invoke-RestMethod -Uri $datApiUrl -UseBasicParsing -TimeoutSec $WebRequestTimeoutSec -ErrorAction Stop @proxyParams
                Write-Log "DAT API health check passed (api.driverautomationtool.com)" -Level Success
                $LogQueue.Enqueue('[SOURCE:DATAPI:OK:Connected]')
            } catch {
                Write-Log "DAT API unreachable: $($_.Exception.Message)" -Level Warn
                $LogQueue.Enqueue('[SOURCE:DATAPI:Error:Unreachable -- check firewall/proxy]')
            }

            # ── DAT API Catalog Mode: skip individual OEM sources ──
            if ($UseDATAPICatalog) {
                Write-Log "DAT API catalog mode enabled -- fetching models from API instead of individual OEM sources..."
                $LogQueue.Enqueue('[SOURCE:DATAPI:Loading driver catalog]')
                try {
                    $driverCatalogRaw = Get-DATDriverCatalog

                    $OSList = $OS -split ';' | Where-Object { $_ }
                    $OEMSupportedModels = @()

                    foreach ($entry in $driverCatalogRaw) {
                        # Filter by selected OEMs
                        if ($entry.Manufacturer -notin $RequiredOEMs) { continue }

                        # Filter by architecture (normalize amd64 -> x64)
                        $entryArch = $entry.SupportedArchitecture
                        if ($entryArch) {
                            $normalizedArch = $entryArch -replace 'amd64', 'x64'
                            if ($normalizedArch -notmatch [regex]::Escape($Architecture)) { continue }
                        }

                        # Match OS: API returns various formats like "win11 25H2", "Windows 11 64-bit, 25H2", "Windows11", "Windows 11"
                        $entryOS = $entry.SupportedOS

                        # Empty SupportedOS with a valid download: treat as matching all selected OS builds
                        # Empty SupportedOS without download: skip (incomplete placeholder entry)
                        if ([string]::IsNullOrEmpty($entryOS)) {
                            if ([string]::IsNullOrEmpty($entry.DownloadURL)) { continue }
                            # Dell is build-agnostic -- single row with Build='All'
                            if ($entry.Manufacturer -eq 'Dell') {
                                $firstOS = ($OSList | Select-Object -First 1).Split(" ")
                                $dellVer = ''
                                if (-not [string]::IsNullOrEmpty($entry.Version) -and $entry.Version -notmatch '^\d+H\d+$') { $dellVer = $entry.Version }
                                elseif (-not [string]::IsNullOrEmpty($entry.ReleaseDate)) { $dellVer = $entry.ReleaseDate }
                                $OEMSupportedModels += [PSCustomObject]@{
                                    OEM        = 'Dell'
                                    Model      = $entry.DisplayName.Trim()
                                    Baseboards = if ($entry.SupportedDevices) { $entry.SupportedDevices } else { '' }
                                    OS         = "$($firstOS[0]) $($firstOS[1])"
                                    'OS Build' = 'All'
                                    Version    = $dellVer
                                    DownloadURL = if ($entry.DownloadURL) { $entry.DownloadURL } else { '' }
                                }
                                continue
                            }
                            foreach ($SingleOS in $OSList) {
                                $osParts = $SingleOS.Split(" ")
                                $WindowsVersion = "$($osParts[0]) $($osParts[1])"
                                $WindowsBuild = if ($osParts.Count -ge 3) { $osParts[2] } else { '' }
                                $displayVersion = ''
                                $hpPackVersion = ''
                                if ($entry.Manufacturer -eq 'HP') {
                                    # HP DriverPack mode shows the catalog version (e.g. "4.00 A 1");
                                    # SoftPaq mode uses a date stamp (real version is fingerprint-based).
                                    if (-not [string]::IsNullOrEmpty($entry.Version) -and $entry.Version -notmatch '^\d+H\d+$') { $hpPackVersion = $entry.Version }
                                    $displayVersion = if ($HPDriverPackSource -eq 'DriverPack' -and -not [string]::IsNullOrEmpty($hpPackVersion)) { $hpPackVersion } else { (Get-Date -Format 'ddMMyyyy') }
                                } elseif ($entry.Manufacturer -eq 'Acer') {
                                    $displayVersion = (Get-Date -Format 'ddMMyyyy')
                                } elseif (-not [string]::IsNullOrEmpty($entry.Version) -and $entry.Version -notmatch '^\d+H\d+$') {
                                    $displayVersion = $entry.Version
                                } elseif (-not [string]::IsNullOrEmpty($entry.ReleaseDate)) {
                                    $displayVersion = $entry.ReleaseDate
                                }
                                $OEMSupportedModels += [PSCustomObject]@{
                                    OEM        = $entry.Manufacturer
                                    Model      = $entry.DisplayName.Trim()
                                    Baseboards = if ($entry.SupportedDevices) { $entry.SupportedDevices } else { '' }
                                    OS         = $WindowsVersion
                                    'OS Build' = $WindowsBuild
                                    Version    = $displayVersion
                                    DriverPackVersion = $hpPackVersion
                                    DownloadURL = if ($entry.DownloadURL) { $entry.DownloadURL } else { '' }
                                }
                            }
                            continue
                        }

                        $matched = $false
                        foreach ($SingleOS in $OSList) {
                            $osParts = $SingleOS.Split(" ")
                            $WindowsVersion = "$($osParts[0]) $($osParts[1])"  # "Windows 11"
                            $WindowsBuild = if ($osParts.Count -ge 3) { $osParts[2] } else { '' }  # "25H2"
                            $winNum = $osParts[1]  # "11" or "10"

                            # Normalize the API OS value and check for match
                            $osMatch = $false
                            if ($WindowsBuild) {
                                # Exact build match patterns
                                $osMatch = (
                                    $entryOS -eq $SingleOS -or                                          # "Windows 11 25H2"
                                    $entryOS -eq "win${winNum} ${WindowsBuild}" -or                     # "win11 25H2"
                                    $entryOS -match "Windows\s+${winNum}.*${WindowsBuild}" -or          # "Windows 11 64-bit, 25H2"
                                    ($entryOS -eq "win${winNum} *") -or                                 # "win10 *" (wildcard)
                                    ($entryOS -eq "Windows ${winNum}" -and $WindowsBuild) -or           # "Windows 11" (generic, matches any build)
                                    ($entryOS -eq "Windows${winNum}" -and $WindowsBuild)                # "Windows11" (no space, generic)
                                )
                            } else {
                                # No build specified -- match any entry for that Windows version
                                $osMatch = $entryOS -match "(?:Windows\s*${winNum}|win${winNum})"
                            }

                            if ($osMatch) {
                                $matched = $true
                                # Dell is build-agnostic -- emit one row with Build='All' and stop iterating OS list
                                if ($entry.Manufacturer -eq 'Dell') { break }
                                # Determine display version per OEM convention
                                $displayVersion = ''
                                $hpPackVersion = ''
                                if ($entry.Manufacturer -eq 'HP') {
                                    # HP DriverPack mode shows the catalog version (e.g. "4.00 A 1");
                                    # SoftPaq mode uses a date stamp (real version is fingerprint-based).
                                    if (-not [string]::IsNullOrEmpty($entry.Version) -and $entry.Version -notmatch '^\d+H\d+$') { $hpPackVersion = $entry.Version }
                                    $displayVersion = if ($HPDriverPackSource -eq 'DriverPack' -and -not [string]::IsNullOrEmpty($hpPackVersion)) { $hpPackVersion } else { (Get-Date -Format 'ddMMyyyy') }
                                } elseif ($entry.Manufacturer -eq 'Acer') {
                                    # Acer uses current date as version (matches OEM XML method)
                                    $displayVersion = (Get-Date -Format 'ddMMyyyy')
                                } elseif (-not [string]::IsNullOrEmpty($entry.Version) -and $entry.Version -notmatch '^\d+H\d+$') {
                                    $displayVersion = $entry.Version
                                } elseif (-not [string]::IsNullOrEmpty($entry.ReleaseDate)) {
                                    $displayVersion = $entry.ReleaseDate
                                }
                                $OEMSupportedModels += [PSCustomObject]@{
                                    OEM        = $entry.Manufacturer
                                    Model      = $entry.DisplayName.Trim()
                                    Baseboards = if ($entry.SupportedDevices) { $entry.SupportedDevices } else { '' }
                                    OS         = $WindowsVersion
                                    'OS Build' = $WindowsBuild
                                    Version    = $displayVersion
                                    DriverPackVersion = $hpPackVersion
                                    DownloadURL = if ($entry.DownloadURL) { $entry.DownloadURL } else { '' }
                                }
                            }
                        }

                        # Dell: emit a single build-agnostic row after the OS loop
                        if ($entry.Manufacturer -eq 'Dell' -and $matched) {
                            $firstOS = ($OSList | Select-Object -First 1).Split(" ")
                            $dellDisplayVersion = ''
                            if (-not [string]::IsNullOrEmpty($entry.Version) -and $entry.Version -notmatch '^\d+H\d+$') {
                                $dellDisplayVersion = $entry.Version
                            } elseif (-not [string]::IsNullOrEmpty($entry.ReleaseDate)) {
                                $dellDisplayVersion = $entry.ReleaseDate
                            }
                            $OEMSupportedModels += [PSCustomObject]@{
                                OEM        = 'Dell'
                                Model      = $entry.DisplayName.Trim()
                                Baseboards = if ($entry.SupportedDevices) { $entry.SupportedDevices } else { '' }
                                OS         = "$($firstOS[0]) $($firstOS[1])"
                                'OS Build' = 'All'
                                Version    = $dellDisplayVersion
                                DownloadURL = if ($entry.DownloadURL) { $entry.DownloadURL } else { '' }
                            }
                        }
                    }

                    # Report per-OEM counts
                    foreach ($OEM in $RequiredOEMs) {
                        $oemCount = @($OEMSupportedModels | Where-Object { $_.OEM -eq $OEM } | Select-Object -Property Model -Unique).Count
                        Write-Log "${OEM}: $oemCount unique models from DAT API." -Level Success
                        $LogQueue.Enqueue("[SOURCE:${OEM}:OK:${oemCount} models (API)]")
                    }

                    $totalCount = @($OEMSupportedModels).Count
                    Write-Log "=== DAT API Catalog: $totalCount total models found ===" -Level Success
                    $LogQueue.Enqueue('[SOURCE:DATAPI:OK:Catalog loaded]')
                } catch {
                    Write-Log "DAT API driver catalog failed: $($_.Exception.Message)" -Level Error
                    $LogQueue.Enqueue('[SOURCE:DATAPI:Error:Driver catalog unavailable]')
                    return @([PSCustomObject]@{ _Error = "DAT API driver catalog unavailable: $($_.Exception.Message)" })
                }

                # ── BIOS version lookup (same as standard path) ──
                if ($totalCount -gt 0) {
                    Write-Log "Looking up BIOS versions for $totalCount models..."
                    $LogQueue.Enqueue('[SOURCE:BIOS:Loading]')
                    try {
                        $biosCatalog = Get-DATBiosCatalog
                        if ($null -eq $biosCatalog -or @($biosCatalog).Count -eq 0) {
                            Write-Log "BIOS catalog returned empty" -Level Warn
                            $LogQueue.Enqueue('[SOURCE:BIOS:Error:API unavailable]')
                            $biosCatalog = @()
                        } else {
                            $LogQueue.Enqueue("[SOURCE:BIOS:OK:$(@($biosCatalog).Count) entries]")
                        }
                    } catch {
                        Write-Log "Failed to fetch BIOS catalog: $($_.Exception.Message)" -Level Warn
                        $LogQueue.Enqueue('[SOURCE:BIOS:Error:API unavailable]')
                        $biosCatalog = @()
                    }

                    # Build device lookup maps
                    $biosDeviceMap = @{}
                    $biosNameMap = @{}
                    foreach ($bEntry in $biosCatalog) {
                        if ([string]::IsNullOrEmpty($bEntry.DownloadURL)) { continue }
                        if ([string]::IsNullOrEmpty($bEntry.SupportedDevices)) {
                            if (-not [string]::IsNullOrEmpty($bEntry.DisplayName)) {
                                $biosNameMap["$($bEntry.Manufacturer)|$($bEntry.DisplayName.Trim())"] = $bEntry
                            }
                            continue
                        }
                        # Acer model names contain spaces (e.g. "TravelMate P214-42") -- don't split on whitespace
                        $devices = if ($bEntry.Manufacturer -eq 'Acer') {
                            @($bEntry.SupportedDevices.Trim().ToUpper())
                        } else {
                            $bEntry.SupportedDevices -split '[;\s]+' | ForEach-Object { $_.Trim().ToUpper() } | Where-Object { $_ }
                        }
                        foreach ($dev in $devices) {
                            $bKey = "$($bEntry.Manufacturer)|$dev"
                            if (-not $biosDeviceMap.ContainsKey($bKey)) { $biosDeviceMap[$bKey] = $bEntry }
                            else {
                                try { if ([datetime]$bEntry.ReleaseDate -gt [datetime]$biosDeviceMap[$bKey].ReleaseDate) { $biosDeviceMap[$bKey] = $bEntry } } catch { }
                            }
                        }
                    }

                    $biosMatched = 0
                    foreach ($model in $OEMSupportedModels) {
                        try {
                            if ($model.OEM -eq 'Microsoft') {
                                if (-not [string]::IsNullOrEmpty($model.Version)) {
                                    $model | Add-Member -NotePropertyName 'BIOSVersion' -NotePropertyValue $model.Version -Force
                                    $biosMatched++
                                }
                                continue
                            }
                            if ($model.OEM -eq 'Acer') {
                                # Acer SupportedDevices == model name; look up by uppercased model name
                                $biosEntry = $biosDeviceMap["Acer|$($model.Model.ToUpper())"]
                                if ($null -eq $biosEntry) {
                                    # Fallback: DisplayName-keyed map (legacy entries without SupportedDevices)
                                    $biosEntry = $biosNameMap["Acer|$($model.Model)"]
                                }
                            } else {
                                $biosEntry = $null
                                $boards = $model.Baseboards -split '[,;\s]+' | ForEach-Object { $_.Trim().ToUpper() } | Where-Object { $_ }
                                foreach ($board in $boards) {
                                    $biosEntry = $biosDeviceMap["$($model.OEM)|$board"]
                                    if ($null -ne $biosEntry) { break }
                                }
                            }
                            if ($null -ne $biosEntry -and -not [string]::IsNullOrEmpty($biosEntry.Version)) {
                                $model | Add-Member -NotePropertyName 'BIOSVersion' -NotePropertyValue $biosEntry.Version -Force
                                $biosMatched++
                            }
                        } catch { }
                    }
                    Write-Log "BIOS: Matched versions for $biosMatched of $totalCount models." -Level Success
                }

                return $OEMSupportedModels
            }

            $LogQueue.Enqueue('[SOURCE:OEMLinks:Loading]')
            if (Test-CatalogFresh -FilePath $OEMLinksCache) {
                Write-Log "Using cached OEM catalog (less than 24h old)."
                [xml]$OEMLinks = Get-Content -Path $OEMLinksCache -Raw
                $LogQueue.Enqueue('[SOURCE:OEMLinks:Cached]')
            } else {
                Write-Log "Downloading OEM catalog from GitHub..."
                $webResponse = $null
                for ($retryAttempt = 1; $retryAttempt -le 3; $retryAttempt++) {
                    try {
                        $webResponse = Invoke-WebRequest -Uri $OEMLinksURL -UseBasicParsing -TimeoutSec $WebRequestTimeoutSec @proxyParams
                        break
                    } catch {
                        if ($retryAttempt -lt 3) {
                            Write-Log "OEM catalog download attempt $retryAttempt failed: $($_.Exception.Message). Retrying in 5s..." -Level Warn
                            Start-Sleep -Seconds 5
                    } else {
                        throw
                    }
                }
                }
                # Save to cache for future freshness checks
                $webResponse.Content | Set-Content -Path $OEMLinksCache -Force
                [xml]$OEMLinks = $webResponse.Content
                Write-Log "OEM catalog loaded (version $($OEMLinks.OEM.Version))." -Level Success
                $LogQueue.Enqueue('[SOURCE:OEMLinks:OK]')
            }
        } catch {
            Write-Log "Failed to download OEM catalog: $($_.Exception.Message)" -Level Error
            $LogQueue.Enqueue('[SOURCE:OEMLinks:Error]')
            return @([PSCustomObject]@{ _Error = "Cannot download OEM catalog: $($_.Exception.Message)" })
        }

        # Support multiple OS values separated by semicolons
        $OSList = $OS -split ';' | Where-Object { $_ }
        $OEMSupportedModels = @()

        foreach ($OEM in $RequiredOEMs) {
            Write-Log "--- Processing $OEM ---"
            $LogQueue.Enqueue("[SOURCE:${OEM}:Loading]")
            switch ($OEM) {
                "HP" {
                    $HPLink = ($OEMLinks.OEM.Manufacturer | Where-Object { $_.Name -match "HP" }).Link | Where-Object { $_.Type -eq "XMLCabinetSource" } | Select-Object -ExpandProperty URL -First 1
                    if ([string]::IsNullOrEmpty($HPLink)) {
                        Write-Log "No HP XMLCabinetSource URL found in OEM catalog." -Level Error
                        $LogQueue.Enqueue('[SOURCE:HP:Error:No catalog URL]')
                        continue
                    }
                    Write-Log "HP catalog URL: $HPLink"
                    $HPCabFile = [string]($HPLink | Split-Path -Leaf)
                    $HPXMLFile = $HPCabFile.TrimEnd(".cab") + ".xml"
                    try {
                        $HPCabPath = Join-Path $TempDir $HPCabFile
                        $HPXMLPath = Join-Path $TempDir $HPXMLFile
                        Write-Log "[HP] CAB download path: $HPCabPath"
                        Write-Log "[HP] XML extract path: $HPXMLPath"
                        if (Test-CatalogFresh -FilePath $HPXMLPath) {
                            Write-Log "Using cached HP catalog (less than 24h old)."
                            $LogQueue.Enqueue('[SOURCE:HP:Cached]')
                        } else {
                            Write-Log "Downloading HP driver pack catalog..."
                            $proxyParams = Get-DATWebRequestProxy
                            Invoke-WebRequest -Uri $HPLink -OutFile $HPCabPath -UseBasicParsing -TimeoutSec $WebRequestTimeoutSec @proxyParams
                            Write-Log "Extracting $HPCabFile to $TempDir..."
                            & expand.exe "$HPCabPath" -F:* "$TempDir" -R 2>&1 | Out-Null
                        }
                        if (-not (Test-Path $HPXMLPath)) {
                            Write-Log "Extracted XML not found at $HPXMLPath" -Level Error
                            $LogQueue.Enqueue('[SOURCE:HP:Error:XML not found]')
                            continue
                        }
                        [xml]$HPModelXML = Get-Content -Path $HPXMLPath -Raw
                        $HPPacks = $HPModelXML.NewDataSet.HPClientDriverPackCatalog.ProductOSDriverPackList.ProductOSDriverPack
                        # ProductOSDriverPack nodes carry no Version -- the driver pack version lives
                        # in the separate <SoftPaqList> section keyed by SoftPaqId. Build a lookup map.
                        $hpVersionMap = @{}
                        foreach ($sp in $HPModelXML.NewDataSet.HPClientDriverPackCatalog.SoftPaqList.SoftPaq) {
                            if ($sp.Id) { $hpVersionMap[$sp.Id] = $sp.Version }
                        }
                        $totalPacks = @($HPPacks).Count
                        foreach ($SingleOS in $OSList) {
                            $WindowsBuild = $($SingleOS).Split(" ")[2]
                            $WindowsVersion = $SingleOS.Replace(" $WindowsBuild", "").TrimEnd()
                            Write-Log "[HP] Filtering for $WindowsVersion build $WindowsBuild (total packs: $totalPacks)"
                            $HPMatches = $HPPacks | Where-Object { $_.OSName -match $WindowsVersion -and $_.OSName -match $WindowsBuild }
                            $count = @($HPMatches).Count
                            if ($count -eq 0 -and $totalPacks -gt 0) {
                                $sampleOSNames = @($HPPacks | Select-Object -ExpandProperty OSName -Unique | Select-Object -First 10)
                                Write-Log "[HP] 0 matches for $SingleOS -- sample OSName values: $($sampleOSNames -join '; ')" -Level Warn
                            }
                            Write-Log "HP: Found $count matching driver packs for $SingleOS." -Level Success
                            foreach ($Model in $HPMatches) {
                                $modelName = ($Model.SystemName -replace '^HP\s+', '').Trim()
                                # HP catalog provides a real DriverPack version (e.g. "7.00 A 1")
                                # via the SoftPaqList section, looked up by the pack's SoftPaqId.
                                # SCCM DriverPack mode shows it; SoftPaq mode uses a date stamp
                                # (its definitive version is computed from the SoftPaq fingerprint).
                                $hpDriverPackVersion = if ($Model.SoftPaqId -and $hpVersionMap.ContainsKey($Model.SoftPaqId)) { $hpVersionMap[$Model.SoftPaqId] } else { '' }
                                $hpDisplayVersion = if ($HPDriverPackSource -eq 'DriverPack' -and -not [string]::IsNullOrEmpty($hpDriverPackVersion)) {
                                    $hpDriverPackVersion
                                } else {
                                    (Get-Date -Format 'ddMMyyyy')
                                }
                                $OEMSupportedModels += [PSCustomObject]@{
                                    OEM               = "HP"
                                    Model             = $modelName
                                    Baseboards        = $Model.SystemId
                                    OS                = $WindowsVersion
                                    'OS Build'        = $WindowsBuild
                                    Version           = $hpDisplayVersion
                                    DriverPackVersion = $hpDriverPackVersion
                                }
                            }
                        }
                        $uniqueCount = @($OEMSupportedModels | Where-Object { $_.OEM -eq 'HP' } | Select-Object -Property Model -Unique).Count
                        Write-Log "HP: $uniqueCount unique models across all selected OS versions." -Level Success
                        $LogQueue.Enqueue("[SOURCE:HP:OK:$uniqueCount models]")
                    } catch {
                        Write-Log "HP processing failed: $($_.Exception.Message)" -Level Error
                        $LogQueue.Enqueue('[SOURCE:HP:Error]')
                    }
                }
                "Dell" {
                    $DellLink = ($OEMLinks.OEM.Manufacturer | Where-Object { $_.Name -match "Dell" }).Link | Where-Object { $_.Type -eq "XMLCabinetSource" } | Select-Object -ExpandProperty URL -First 1
                    if ([string]::IsNullOrEmpty($DellLink)) {
                        Write-Log "No Dell XMLCabinetSource URL found in OEM catalog." -Level Error
                        $LogQueue.Enqueue('[SOURCE:Dell:Error:No catalog URL]')
                        continue
                    }
                    Write-Log "Dell catalog URL: $DellLink"
                    $DellCabFile = [string]($DellLink | Split-Path -Leaf)
                    $DellXMLFile = $DellCabFile.TrimEnd(".cab") + ".xml"
                    try {
                        $DellCabPath = Join-Path $TempDir $DellCabFile
                        $DellXMLPath = Join-Path $TempDir $DellXMLFile
                        if (Test-CatalogFresh -FilePath $DellXMLPath) {
                            Write-Log "Using cached Dell catalog (less than 24h old)."
                            $LogQueue.Enqueue('[SOURCE:Dell:Cached]')
                        } elseif (-not (Test-Path $DellCabPath) -or -not (Test-CatalogFresh -FilePath $DellCabPath)) {
                            Write-Log "Downloading Dell driver pack catalog..."
                            $proxyParams = Get-DATWebRequestProxy
                            Invoke-WebRequest -Uri $DellLink -OutFile $DellCabPath -UseBasicParsing -TimeoutSec $WebRequestTimeoutSec @proxyParams
                            Write-Log "Extracting $DellCabFile..."
                            & expand.exe "$DellCabPath" -F:* "$TempDir" -R 2>&1 | Out-Null
                        } else {
                            Write-Log "Extracting cached $DellCabFile..."
                            & expand.exe "$DellCabPath" -F:* "$TempDir" -R 2>&1 | Out-Null
                        }
                        if (-not (Test-Path $DellXMLPath)) {
                            Write-Log "Extracted Dell XML not found at $DellXMLPath" -Level Error
                            $LogQueue.Enqueue('[SOURCE:Dell:Error:XML not found]')
                            continue
                        }
                        [xml]$DellModelXML = Get-Content -Path $DellXMLPath -Raw
                        $DellPkgs = $DellModelXML.driverpackmanifest.driverpackage
                        # Dell does not use build-specific packages -- process only the first OS
                        # to get the Windows version (e.g. "Windows11") and deduplicate
                        $DellFirstOS = $OSList | Select-Object -First 1
                        $WindowsBuild = $($DellFirstOS).Split(" ")[2]
                        $WindowsVersion = $DellFirstOS.Replace(" $WindowsBuild", "").TrimEnd()
                        $DellWindowsVersion = $WindowsVersion.Replace(" ", "")
                        Write-Log "[Dell] Filtering for $DellWindowsVersion arch $Architecture (build-agnostic)"
                        $DellMatchingPkgs = $DellPkgs | Where-Object {
                            ($_.SupportedOperatingSystems.OperatingSystem.osCode -eq "$DellWindowsVersion") -and
                            ($_.SupportedOperatingSystems.OperatingSystem.osArch -match $Architecture)
                        }
                            $DellModels = $DellMatchingPkgs | Select-Object @{ Name = "SystemName"; Expression = { $_.SupportedSystems.Brand.Model.name | Select-Object -First 1 } },
                            @{ Name = "SystemID"; Expression = { $_.SupportedSystems.Brand.Model.SystemID } },
                            @{ Name = "DellVersion"; Expression = { $_.dellVersion } } -Unique |
                            Where-Object { $_.SystemName -gt $null }
                            # Deduplicate short-name variants (e.g. "7060" vs "OptiPlex 7060") sharing overlapping baseboards
                            $DellModels = @($DellModels | Where-Object {
                                $current = $_
                                $currentIds = @($current.SystemID | Where-Object { $_ } | Select-Object -Unique)
                                $dominated = $DellModels | Where-Object {
                                    $_.SystemName -ne $current.SystemName -and
                                    $_.SystemName.Length -gt $current.SystemName.Length -and
                                    $_.SystemName -like "*$($current.SystemName)*" -and
                                    @($_.SystemID | Where-Object { $_ -and $_ -in $currentIds }).Count -gt 0
                                }
                                $null -eq $dominated
                            })
                            $count = @($DellModels).Count
                            Write-Log "Dell: Found $count unique models (build-agnostic)." -Level Success
                            foreach ($Model in $DellModels) {
                                $sysIds = $Model.SystemID | Where-Object { $_ } | Select-Object -Unique
                                $OEMSupportedModels += [PSCustomObject]@{
                                    OEM        = "Dell"
                                    Model      = $Model.SystemName
                                    Baseboards = $(if ($sysIds) { $sysIds -join "," } else { "" })
                                    OS         = $WindowsVersion
                                    'OS Build' = 'All'
                                    Version    = $Model.DellVersion
                                }
                            }
                        $uniqueCount = @($OEMSupportedModels | Where-Object { $_.OEM -eq 'Dell' } | Select-Object -Property Model -Unique).Count
                        Write-Log "Dell: $uniqueCount unique models." -Level Success
                        $LogQueue.Enqueue("[SOURCE:Dell:OK:$uniqueCount models]")
                    } catch {
                        Write-Log "Dell processing failed: $($_.Exception.Message)" -Level Error
                        $LogQueue.Enqueue('[SOURCE:Dell:Error]')
                    }
                }
                "Lenovo" {
                    $LenovoLink = ($OEMLinks.OEM.Manufacturer | Where-Object { $_.Name -match "Lenovo" }).Link | Where-Object { $_.Type -eq "XMLSource" } | Select-Object -ExpandProperty URL -First 1
                    if ([string]::IsNullOrEmpty($LenovoLink)) {
                        Write-Log "No Lenovo XMLSource URL found in OEM catalog." -Level Error
                        $LogQueue.Enqueue('[SOURCE:Lenovo:Error:No catalog URL]')
                        continue
                    }
                    Write-Log "Lenovo catalog URL: $LenovoLink"
                    $LenovoFile = [string]($LenovoLink | Split-Path -Leaf)
                    try {
                        $LenovoFilePath = Join-Path $TempDir $LenovoFile
                        if (Test-CatalogFresh -FilePath $LenovoFilePath) {
                            Write-Log "Using cached Lenovo catalog (less than 24h old)."
                            $LogQueue.Enqueue('[SOURCE:Lenovo:Cached]')
                        } else {
                            Write-Log "Downloading Lenovo model catalog..."
                            $proxyParams = Get-DATWebRequestProxy
                            Invoke-WebRequest -Uri $LenovoLink -OutFile $LenovoFilePath -UseBasicParsing -TimeoutSec $WebRequestTimeoutSec @proxyParams
                        }
                        [xml]$LenovoModelXML = Get-Content -Path $LenovoFilePath
                        $LenovoDrivers = $LenovoModelXML.ModelList.Model
                        foreach ($SingleOS in $OSList) {
                            $WindowsBuild = $($SingleOS).Split(" ")[2]
                            $WindowsVersion = $SingleOS.Replace(" $WindowsBuild", "").TrimEnd()
                            $WinVer = "Win" + "$($WindowsVersion.Split(' ')[1])"
                            Write-Log "Filtering Lenovo models for $WinVer build $WindowsBuild..."
                            $LenovoModels = ($LenovoDrivers | Where-Object {
                                ($_.SCCM.Version -eq $WindowsBuild -and $_.SCCM.OS -eq $WinVer)
                            } | Sort-Object).Name
                            $count = @($LenovoModels).Count
                            Write-Log "Lenovo: Found $count matching models for $SingleOS." -Level Success
                            foreach ($Model in $LenovoModels) {
                                $modelNode = $LenovoDrivers | Where-Object { $_.Name -eq $Model } | Select-Object -First 1
                                $baseboards = $modelNode.Types.Type
                                $baseboardStr = if ($null -ne $baseboards) { ([string]$baseboards).Replace(" ", ",").Trim() } else { "" }
                                # Get driver pack date from the matching SCCM node
                                $sccmNode = $modelNode.SCCM | Where-Object { $_.Version -eq $WindowsBuild -and $_.OS -eq $WinVer } | Select-Object -First 1
                                $lenovoDate = if ($sccmNode.date) { $sccmNode.date } else { '' }
                                # Check for supplemental NVIDIA GFX driver package
                                $gfxNode = $modelNode.GFX | Where-Object { $_.os -eq $WinVer -and $_.version -eq $WindowsBuild } | Select-Object -First 1
                                $hasGFX = $null -ne $gfxNode
                                $gfxBrand = if ($hasGFX) { $gfxNode.brand } else { $null }
                                if ($hasGFX) { Write-Log "Lenovo: $Model has supplemental $gfxBrand GFX driver package" }
                                $OEMSupportedModels += [PSCustomObject]@{
                                    OEM        = "Lenovo"
                                    Model      = $Model
                                    Baseboards = $baseboardStr
                                    OS         = $WindowsVersion
                                    'OS Build' = $WindowsBuild
                                    HasGFX     = $hasGFX
                                    GFXBrand   = $gfxBrand
                                    Version    = $lenovoDate
                                }
                            }
                        }
                        $uniqueCount = @($OEMSupportedModels | Where-Object { $_.OEM -eq 'Lenovo' } | Select-Object -Property Model -Unique).Count
                        Write-Log "Lenovo: $uniqueCount unique models across all selected OS versions." -Level Success
                        $LogQueue.Enqueue("[SOURCE:Lenovo:OK:$uniqueCount models]")
                    } catch {
                        Write-Log "Lenovo processing failed: $($_.Exception.Message)" -Level Error
                        $LogQueue.Enqueue('[SOURCE:Lenovo:Error]')
                    }
                }
                "Microsoft" {
                    $MSArchFilter = if ($Architecture -eq 'Arm64') { 'arm64' } else { 'amd64' }
                    # Track model names added from the DAT API so the OSD catalog can fill gaps
                    $DATMSModelNames = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)

                    # --- Step 1: DAT API catalog (always try first, mirrors core module behaviour) ---
                    try {
                        Write-Log "Microsoft: querying DAT API catalog..."
                        $DATCatalog = Get-DATDriverCatalog
                        if ($DATCatalog -and @($DATCatalog).Count -gt 0) {
                            foreach ($SingleOS in $OSList) {
                                $WindowsBuild   = $($SingleOS).Split(" ")[2]
                                $WindowsVersion = $SingleOS.Replace(" $WindowsBuild", "").TrimEnd()
                                $DATMSFiltered  = $DATCatalog | Where-Object {
                                    $_.Manufacturer -eq 'Microsoft' -and
                                    $_.SupportedOS  -match $WindowsVersion -and
                                    $_.SupportedArchitecture -eq $MSArchFilter
                                }
                                foreach ($entry in ($DATMSFiltered | Group-Object -Property DisplayName)) {
                                    $latestEntry = $entry.Group | Sort-Object { try { [datetime]$_.ReleaseDate } catch { [datetime]::MinValue } } -Descending | Select-Object -First 1
                                    $OEMSupportedModels += [PSCustomObject]@{
                                        OEM         = "Microsoft"
                                        Model       = $entry.Name
                                        Baseboards  = if ($latestEntry.SupportedDevices) { $latestEntry.SupportedDevices } else { $entry.Name }
                                        OS          = $WindowsVersion
                                        'OS Build'  = $WindowsBuild
                                        Version     = if ($latestEntry.ReleaseDate) { $latestEntry.ReleaseDate } else { '' }
                                        DownloadURL = if ($latestEntry.DownloadURL) { $latestEntry.DownloadURL } else { '' }
                                    }
                                    [void]$DATMSModelNames.Add($entry.Name)
                                }
                            }
                            $datCount = $DATMSModelNames.Count
                            Write-Log "Microsoft: DAT API catalog returned $datCount unique model(s)." -Level Success
                        } else {
                            Write-Log "Microsoft: DAT API catalog returned no results -- OSD catalog will supply all models." -Level Warn
                        }
                    } catch {
                        Write-Log "Microsoft: DAT API catalog unavailable ($($_.Exception.Message)) -- OSD catalog will supply all models." -Level Warn
                    }

                    # --- Step 2: OSD catalog (supplement with models not already in API results) ---
                    $MSLink = "https://raw.githubusercontent.com/maurice-daly/DriverAutomationTool/master/Data/OSDCatalogMicrosoftDriverPack.json"
                    try {
                        $MSFilePath = Join-Path $TempDir "OSDCatalogMicrosoftDriverPack.json"
                        if (Test-CatalogFresh -FilePath $MSFilePath) {
                            Write-Log "Using cached Microsoft OSD catalog (less than 24h old)."
                        } else {
                            Write-Log "Downloading Microsoft OSD catalog to $MSFilePath..."
                            $proxyParams = Get-DATWebRequestProxy
                            Invoke-WebRequest -Uri $MSLink -OutFile $MSFilePath -UseBasicParsing -TimeoutSec $WebRequestTimeoutSec @proxyParams
                            Write-Log "Microsoft OSD catalog downloaded successfully." -Level Success
                        }
                        $MSModelList  = Get-Content -Path $MSFilePath -Raw | ConvertFrom-Json
                        $MSModelTotal = @($MSModelList).Count
                        Write-Log "Microsoft OSD catalog: $MSModelTotal total entries."
                        foreach ($SingleOS in $OSList) {
                            $WindowsBuild   = $($SingleOS).Split(" ")[2]
                            $WindowsVersion = $SingleOS.Replace(" $WindowsBuild", "").TrimEnd()
                            $MSFiltered = $MSModelList | Where-Object { $_.OperatingSystem -match $WindowsVersion -and $_.OSArchitecture -eq $MSArchFilter }
                            $MSModels   = $MSFiltered | Group-Object -Property Model
                            $count      = @($MSModels).Count
                            Write-Log "Microsoft OSD: $count matching model(s) for $SingleOS." -Level $(if ($count -gt 0) { 'Success' } else { 'Warn' })
                            foreach ($MSModelGroup in $MSModels) {
                                # Skip models already supplied by the DAT API
                                if ($DATMSModelNames.Contains($MSModelGroup.Name)) { continue }
                                $products    = ($MSModelGroup.Group | ForEach-Object { $_.SystemId } | Select-Object -Unique) -join ','
                                $latestEntry = $MSModelGroup.Group | Sort-Object { try { [datetime]$_.ReleaseDate } catch { [datetime]::MinValue } } -Descending | Select-Object -First 1
                                $OEMSupportedModels += [PSCustomObject]@{
                                    OEM         = "Microsoft"
                                    Model       = $MSModelGroup.Name
                                    Baseboards  = $products
                                    OS          = $WindowsVersion
                                    'OS Build'  = $WindowsBuild
                                    Version     = if ($latestEntry.ReleaseDate) { $latestEntry.ReleaseDate } else { '' }
                                    DownloadURL = if ($latestEntry.Url) { $latestEntry.Url } else { '' }
                                }
                            }
                        }
                        $uniqueCount = @($OEMSupportedModels | Where-Object { $_.OEM -eq 'Microsoft' } | Select-Object -Property Model -Unique).Count
                        Write-Log "Microsoft: $uniqueCount unique models total (DAT API + OSD catalog)." -Level Success
                        $LogQueue.Enqueue("[SOURCE:Microsoft:OK:$uniqueCount models]")
                    } catch {
                        if ($DATMSModelNames.Count -gt 0) {
                            # API models loaded fine -- report partial success
                            $uniqueCount = @($OEMSupportedModels | Where-Object { $_.OEM -eq 'Microsoft' } | Select-Object -Property Model -Unique).Count
                            Write-Log "Microsoft OSD catalog failed ($($_.Exception.Message)) -- using $uniqueCount model(s) from DAT API only." -Level Warn
                            $LogQueue.Enqueue("[SOURCE:Microsoft:OK:$uniqueCount models (API only)]")
                        } else {
                            Write-Log "Microsoft processing failed: $($_.Exception.Message)" -Level Error
                            $LogQueue.Enqueue('[SOURCE:Microsoft:Error]')
                        }
                    }
                }
                "Acer" {
                    $AcerLink = ($OEMLinks.OEM.Manufacturer | Where-Object { $_.Name -match "Acer" }).Link | Where-Object { $_.Type -eq "XMLSource" } | Select-Object -ExpandProperty URL -First 1
                    if ([string]::IsNullOrEmpty($AcerLink)) {
                        Write-Log "No Acer XMLSource URL found in OEM catalog." -Level Error
                        $LogQueue.Enqueue('[SOURCE:Acer:Error:No catalog URL]')
                        continue
                    }
                    Write-Log "Acer catalog URL: $AcerLink"
                    $AcerFile = [string]($AcerLink | Split-Path -Leaf)
                    try {
                        $AcerFilePath = Join-Path $TempDir $AcerFile
                        if (Test-CatalogFresh -FilePath $AcerFilePath) {
                            Write-Log "Using cached Acer catalog (less than 24h old)."
                            $LogQueue.Enqueue('[SOURCE:Acer:Cached]')
                        } else {
                            Write-Log "Downloading Acer model catalog..."
                            $proxyParams = Get-DATWebRequestProxy
                            Invoke-WebRequest -Uri $AcerLink -OutFile $AcerFilePath -UseBasicParsing -TimeoutSec $WebRequestTimeoutSec @proxyParams
                        }
                        [xml]$AcerModelXML = Get-Content -Path $AcerFilePath
                        $AcerDrivers = $AcerModelXML.ModelList.Model
                        $allAcerDriverModels = @()
                        foreach ($SingleOS in $OSList) {
                            $WindowsBuild = $($SingleOS).Split(" ")[2]
                            $WindowsVersion = $SingleOS.Replace(" $WindowsBuild", "").TrimEnd()
                            $WinVer = "Win" + "$($WindowsVersion.Split(' ')[1])"
                            $AcerModels = ($AcerDrivers | Where-Object {
                                ($_.SCCM.Version -eq $WindowsBuild -and $_.SCCM.OS -eq $WinVer)
                            } | Sort-Object).Name
                            $count = @($AcerModels).Count
                            Write-Log "Acer: Found $count matching models for $SingleOS." -Level Success
                            $allAcerDriverModels += @($AcerModels)
                            foreach ($Model in $AcerModels) {
                                $OEMSupportedModels += [PSCustomObject]@{
                                    OEM        = "Acer"
                                    Model      = $Model
                                    Baseboards = $Model
                                    OS         = $WindowsVersion
                                    'OS Build' = $WindowsBuild
                                    Version    = (Get-Date -Format 'ddMMyyyy')
                                }
                            }
                        }

                        # Acer BIOS lives in the Acer XML catalog (not the JSON BIOS catalog).
                        # When BIOS or All is selected, include all Acer models from the XML catalog
                        # that don't already have a driver pack for any selected OS/build.
                        if ($PackageType -in @('BIOS', 'All', 'BIOS Pilot', 'All Pilot')) {
                            $existingAcerNames = @($allAcerDriverModels) | Select-Object -Unique
                            $allAcerNames = ($AcerDrivers | Where-Object { $_.Name -gt $null } | Sort-Object).Name | Select-Object -Unique
                            # Use the first OS for BIOS-only entries (BIOS is OS-agnostic)
                            $firstOS = $OSList | Select-Object -First 1
                            $firstWindowsBuild = $($firstOS).Split(" ")[2]
                            $firstWindowsVersion = $firstOS.Replace(" $firstWindowsBuild", "").TrimEnd()
                            foreach ($extraModel in $allAcerNames) {
                                if ($extraModel -notin $existingAcerNames) {
                                    $OEMSupportedModels += [PSCustomObject]@{
                                        OEM        = "Acer"
                                        Model      = $extraModel
                                        Baseboards = $extraModel
                                        OS         = $firstWindowsVersion
                                        'OS Build' = $firstWindowsBuild
                                        Version    = ''
                                        BIOSOnly   = $true
                                    }
                                }
                            }
                        }
                        $uniqueCount = @($OEMSupportedModels | Where-Object { $_.OEM -eq 'Acer' } | Select-Object -Property Model -Unique).Count
                        Write-Log "Acer: $uniqueCount unique models across all selected OS versions." -Level Success
                        $LogQueue.Enqueue("[SOURCE:Acer:OK:$uniqueCount models]")
                    } catch {
                        Write-Log "Acer processing failed: $($_.Exception.Message)" -Level Error
                        $LogQueue.Enqueue('[SOURCE:Acer:Error]')
                    }
                }
            }
        } # end foreach ($OEM in $RequiredOEMs)

        $totalCount = @($OEMSupportedModels).Count
        Write-Log "=== Complete: $totalCount total models found ===" -Level Success

        # ── BIOS version lookup: always enrich models with BIOS version from catalog ──
        if ($totalCount -gt 0) {
            Write-Log "Looking up BIOS versions for $totalCount models..."
            $LogQueue.Enqueue('[SOURCE:BIOS:Loading]')
            $biosCatalogFailed = $false
            try {
                $biosCatalog = Get-DATBiosCatalog
                if ($null -eq $biosCatalog -or @($biosCatalog).Count -eq 0) {
                    $biosCatalogFailed = $true
                    Write-Log "BIOS catalog returned empty -- API may be blocked or unavailable" -Level Warn
                }
            } catch {
                Write-Log "Failed to fetch BIOS catalog: $($_.Exception.Message)" -Level Warn
                $biosCatalog = @()
                $biosCatalogFailed = $true
            }

            if ($biosCatalogFailed) {
                $LogQueue.Enqueue('[SOURCE:BIOS:Error:API unavailable -- check firewall/proxy]')
            }

            # Pre-build a device→entry hashtable for fast O(1) lookups instead of scanning per model
            $biosDeviceMap = @{}
            $biosNameMap = @{}  # Acer: keyed by "Manufacturer|DisplayName" (no SupportedDevices)
            foreach ($entry in $biosCatalog) {
                if ([string]::IsNullOrEmpty($entry.DownloadURL)) { continue }
                if ([string]::IsNullOrEmpty($entry.SupportedDevices)) {
                    # Acer entries have no SupportedDevices -- use DisplayName for matching
                    if (-not [string]::IsNullOrEmpty($entry.DisplayName)) {
                        $nameKey = "$($entry.Manufacturer)|$($entry.DisplayName.Trim())"
                        $biosNameMap[$nameKey] = $entry
                    }
                    continue
                }
                # Acer model names contain spaces (e.g. "TravelMate P214-42") -- don't split on whitespace
                $devices = if ($entry.Manufacturer -eq 'Acer') {
                    @($entry.SupportedDevices.Trim().ToUpper())
                } else {
                    $entry.SupportedDevices -split '[;\s]+' | ForEach-Object { $_.Trim().ToUpper() } | Where-Object { $_ }
                }
                foreach ($dev in $devices) {
                    $key = "$($entry.Manufacturer)|$dev"
                    $existing = $biosDeviceMap[$key]
                    if ($null -eq $existing) {
                        $biosDeviceMap[$key] = $entry
                    } else {
                        # Keep the entry with the latest release date
                        try {
                            if ([datetime]$entry.ReleaseDate -gt [datetime]$existing.ReleaseDate) {
                                $biosDeviceMap[$key] = $entry
                            }
                        } catch { }
                    }
                }
            }

            $biosMatched = 0
            foreach ($model in $OEMSupportedModels) {
                try {
                    # Microsoft Surface BIOS is updated via driver injection -- use driver version as BIOS version
                    if ($model.OEM -eq 'Microsoft') {
                        if (-not [string]::IsNullOrEmpty($model.Version)) {
                            $model | Add-Member -NotePropertyName 'BIOSVersion' -NotePropertyValue $model.Version -Force
                            $biosMatched++
                        }
                        continue
                    }
                    if ($model.OEM -eq 'Acer') {
                        # Acer SupportedDevices == model name; look up by uppercased model name
                        $biosEntry = $biosDeviceMap["Acer|$($model.Model.ToUpper())"]
                        if ($null -eq $biosEntry) {
                            # Fallback: DisplayName-keyed map (legacy entries without SupportedDevices)
                            $biosEntry = $biosNameMap["Acer|$($model.Model)"]
                        }
                    } else {
                        # Fast hashtable lookup for Dell/HP/Lenovo/Microsoft
                        $biosEntry = $null
                        $boards = $model.Baseboards -split '[,;\s]+' | ForEach-Object { $_.Trim().ToUpper() } | Where-Object { $_ }
                        foreach ($board in $boards) {
                            $biosEntry = $biosDeviceMap["$($model.OEM)|$board"]
                            if ($null -ne $biosEntry) { break }
                        }
                    }
                    if ($null -ne $biosEntry -and -not [string]::IsNullOrEmpty($biosEntry.Version)) {
                        $model | Add-Member -NotePropertyName 'BIOSVersion' -NotePropertyValue $biosEntry.Version -Force
                        $biosMatched++
                    }
                } catch {
                    # Silently skip models with no BIOS match
                }
            }
            Write-Log "BIOS version lookup complete. Matched $biosMatched of $totalCount models." -Level Success
            if (-not $biosCatalogFailed) {
                $LogQueue.Enqueue("[SOURCE:BIOS:OK:$biosMatched matched]")
            }

            # ── BIOS-only models (BIOS or All package type only) ──
            # BIOS packages are OS-agnostic. Add an entry for every BIOS catalog model
            # that isn't already represented in the driver-pack-derived list.
            if ($PackageType -in @('BIOS', 'All', 'BIOS Pilot', 'All Pilot') -and -not $biosCatalogFailed -and @($biosCatalog).Count -gt 0) {
                # Build a set of OEM|Model keys already present (case-insensitive).
                # Also build a normalised-key set for fuzzy HP matching (HP driver
                # catalog strips manufacturer prefix AND common suffixes like
                # "Desktop PC", "Notebook PC", etc.)
                $existingKeys = New-Object System.Collections.Generic.HashSet[string] ([System.StringComparer]::OrdinalIgnoreCase)
                $existingNorm = New-Object System.Collections.Generic.HashSet[string] ([System.StringComparer]::OrdinalIgnoreCase)
                foreach ($m in $OEMSupportedModels) {
                    [void]$existingKeys.Add("$($m.OEM)|$($m.Model)")
                    # Normalised key: strip common suffixes for HP so BIOS catalog
                    # entries (which lack these suffixes) match existing driver entries
                    $normName = $m.Model
                    if ($m.OEM -eq 'HP') {
                        $normName = $normName -replace '\s+2-in-1\s+Notebook\s+PC$', ''
                        $normName = $normName -replace '\s+Mobile\s+Workstation\s+PC$', ''
                        $normName = $normName -replace '\s+Notebook\s+PC$', ''
                        $normName = $normName -replace '\s+Desktop\s+PC$', ''
                        $normName = $normName -replace '\s+All-in-One$', ''
                        $normName = $normName -replace '\s+Mobile\s+Workstation$', ''
                        $normName = $normName -replace '\s+PC$', ''
                        $normName = $normName.Trim()
                    }
                    [void]$existingNorm.Add("$($m.OEM)|$normName")
                }

                # Group BIOS catalog by Manufacturer + DisplayName, taking the latest entry
                # (by ReleaseDate) and aggregating all SupportedDevices
                $biosOnlyAdded = 0
                $biosGroups = $biosCatalog |
                    Where-Object { -not [string]::IsNullOrEmpty($_.Manufacturer) -and -not [string]::IsNullOrEmpty($_.DisplayName) -and $_.Manufacturer -in $RequiredOEMs } |
                    Group-Object { "$($_.Manufacturer)|$($_.DisplayName)" }

                foreach ($grp in $biosGroups) {
                    # Pick the latest entry by ReleaseDate
                    $latest = $grp.Group | Sort-Object {
                        try { [datetime]$_.ReleaseDate } catch { [datetime]::MinValue }
                    } -Descending | Select-Object -First 1

                    # Normalise DisplayName: strip manufacturer prefix for HP
                    # (driver catalog entries drop the HP/Hewlett-Packard prefix)
                    $displayName = $latest.DisplayName
                    if ($latest.Manufacturer -eq 'HP') {
                        $displayName = $displayName -replace '^(HP|Hewlett-Packard|COMPAQ|Compaq)\s+', ''
                    }

                    $key = "$($latest.Manufacturer)|$displayName"
                    if ($existingKeys.Contains($key) -or $existingNorm.Contains($key)) { continue }

                    # Aggregate all SupportedDevices across the group (deduped)
                    $allBoards = @()
                    foreach ($e in $grp.Group) {
                        if (-not [string]::IsNullOrEmpty($e.SupportedDevices)) {
                            $allBoards += ($e.SupportedDevices -split '[;,\s]+' | ForEach-Object { $_.Trim() } | Where-Object { $_ })
                        }
                    }
                    $boardsCsv = ($allBoards | Select-Object -Unique) -join ','

                    # Skip if a longer-named model already exists with overlapping baseboards
                    # (e.g. BIOS catalog has "7060" but driver catalog already has "OptiPlex 7060")
                    $biosBoards = @($allBoards | Select-Object -Unique | ForEach-Object { $_.ToUpper() } | Sort-Object)
                    $isDuplicate = $false
                    if ($biosBoards.Count -gt 0) {
                        foreach ($existing in $OEMSupportedModels) {
                            if ($existing.OEM -ne $latest.Manufacturer) { continue }
                            if ($existing.Model.Length -le $displayName.Length) { continue }
                            if ($existing.Model -notlike "*$displayName*") { continue }
                            # Check if any BIOS board appears in the existing model's boards
                            $existBoards = @($existing.Baseboards -split ',' | ForEach-Object { $_.Trim().ToUpper() } | Where-Object { $_ })
                            if ($existBoards.Count -gt 0) {
                                $overlap = $biosBoards | Where-Object { $_ -in $existBoards }
                                if (@($overlap).Count -gt 0) {
                                    $isDuplicate = $true
                                    break
                                }
                            }
                        }
                    }
                    if ($isDuplicate) { continue }

                    $OEMSupportedModels += [PSCustomObject]@{
                        OEM         = $latest.Manufacturer
                        Model       = $displayName
                        Baseboards  = $boardsCsv
                        OS          = $WindowsVersion
                        'OS Build'  = $WindowsBuild
                        Version     = ''
                        BIOSVersion = $latest.Version
                        BIOSOnly    = $true
                    }
                    [void]$existingKeys.Add($key)
                    $biosOnlyAdded++
                }

                if ($biosOnlyAdded -gt 0) {
                    Write-Log "Added $biosOnlyAdded BIOS-only models from BIOS catalog (no driver package for selected OS/build)." -Level Info
                    $LogQueue.Enqueue("[SOURCE:BIOS:OK:$biosOnlyAdded BIOS-only added]")
                }
                $totalCount = @($OEMSupportedModels).Count
            }
        }

        return $OEMSupportedModels
    })
    [void]$script:RefreshPS.AddArgument($CoreModulePath)
    [void]$script:RefreshPS.AddArgument($selectedOEMs)
    [void]$script:RefreshPS.AddArgument($selectedOS)
    [void]$script:RefreshPS.AddArgument($selectedArch)
    [void]$script:RefreshPS.AddArgument($selectedPackageType)
    [void]$script:RefreshPS.AddArgument($refreshTempDir)
    [void]$script:RefreshPS.AddArgument(($chk_UseDATAPICatalog.IsChecked -eq $true))
    [void]$script:RefreshPS.AddArgument($script:WebRequestTimeoutSec)
    $hpSourceMode = (Get-ItemProperty -Path $global:RegPath -Name 'HPDriverPackSource' -ErrorAction SilentlyContinue).HPDriverPackSource
    if ([string]::IsNullOrEmpty($hpSourceMode)) { $hpSourceMode = 'DriverPack' }
    [void]$script:RefreshPS.AddArgument($hpSourceMode)

    $script:RefreshAsyncResult = $script:RefreshPS.BeginInvoke()

    # Poll for completion + drain log queue (keeps UI responsive)
    $script:RefreshTimer = New-Object System.Windows.Threading.DispatcherTimer
    $script:RefreshTimer.Interval = [TimeSpan]::FromMilliseconds(250)
    $script:RefreshTimer.Add_Tick({
        # Drain any pending log messages from the background thread
        Invoke-DATLogQueueDrain

        if ($script:RefreshAsyncResult.IsCompleted) {
            $script:RefreshTimer.Stop()

            # Final drain
            Invoke-DATLogQueueDrain

            try {
                $models = $script:RefreshPS.EndInvoke($script:RefreshAsyncResult)
                $streamErrors = $script:RefreshPS.Streams.Error

                # Show any stream errors in the activity log
                foreach ($streamErr in $streamErrors) {
                    Write-DATActivityLog "Stream error: $($streamErr.Exception.Message)" -Level Error
                }

                # Check for returned error object
                $errorResult = $models | Where-Object { $_ -is [PSCustomObject] -and $_._Error }
                if ($errorResult) {
                    Write-DATActivityLog "Fatal error: $($errorResult._Error)" -Level Error
                    $txt_Status.Text = "Error: $($errorResult._Error)"
                } else {
                    foreach ($model in ($models | Sort-Object OEM, Model)) {
                        if ($null -ne $model -and -not [string]::IsNullOrEmpty($model.Model) -and $null -eq $model._Error) {
                            $modelItem = [ModelItem]@{
                                Selected   = $false
                                OEM        = $model.OEM
                                Model      = $model.Model
                                OS         = $model.OS
                                Build      = $model.'OS Build'
                                Baseboards = $model.Baseboards
                                HasGFX     = if ($model.HasGFX) { $true } else { $false }
                                GFXBrand   = if ($model.GFXBrand) { $model.GFXBrand } else { '' }
                                Version    = if ($model.Version) { $model.Version } else { '' }
                            }
                            # BIOSVersion / BIOSOnly / DownloadURL set separately -- property may not exist on stale cached type
                            try { $modelItem.BIOSVersion = if ($model.BIOSVersion) { $model.BIOSVersion } else { '' } } catch { }
                            try { $modelItem.BIOSOnly = if ($model.BIOSOnly) { $true } else { $false } } catch { }
                            try { $modelItem.DownloadURL = if ($model.DownloadURL) { $model.DownloadURL } else { '' } } catch { }
                            try { $modelItem.DriverPackVersion = if ($model.DriverPackVersion) { $model.DriverPackVersion } else { '' } } catch { }
                            $script:ModelData.Add($modelItem)
                        }
                    }

                    $txt_ModelCount.Text = "$($script:ModelData.Count) models"
                    if ($script:ModelData.Count -gt 0) {
                        $txt_Status.Text = "Loaded $($script:ModelData.Count) supported models."
                        $txt_Status.Foreground = [System.Windows.Media.SolidColorBrush]::new(
                            [System.Windows.Media.ColorConverter]::ConvertFromString(
                                (Get-DATTheme -ThemeName $script:CurrentTheme)['WindowForeground']))
                        $txt_Status.Tag = 'WindowForeground'
                        Write-DATActivityLog "Populated grid with $($script:ModelData.Count) models." -Level Success

                        # Log a per-OEM summary (counts only -- individual models go to the log file)
                        $oemGroups = $script:ModelData | Group-Object -Property OEM | Sort-Object Name
                        foreach ($grp in $oemGroups) {
                            Write-DATActivityLog "  $($grp.Name): $($grp.Count) model(s)" -Level Info
                        }

                        # Auto-select models matching known Intune devices
                        Update-DATKnownModelSelection
                        # Auto-select models matching known ConfigMgr devices
                        Update-DATConfigMgrKnownModelSelection
                        # Refresh the 'Select Known Models' button visibility now that the grid is populated
                        Update-DATSelectKnownModelsVisibility
                        # Restore previously saved model selections
                        Restore-DATModelSelections
                        # Persist the merged selection state (saved JSON + known models) immediately
                        Save-DATModelSelections

                        # Warn if BIOS catalog was unavailable (no models have BIOS versions)
                        $biosPopulated = @($script:ModelData | Where-Object { -not [string]::IsNullOrEmpty($_.BIOSVersion) })
                        $nonMicrosoftModels = @($script:ModelData | Where-Object { $_.OEM -ne 'Microsoft' })
                        if ($nonMicrosoftModels.Count -gt 0 -and $biosPopulated.Count -eq 0) {
                            Write-DATActivityLog "WARNING: BIOS catalog API was unreachable -- no BIOS versions available. Check firewall/proxy settings for api.driverautomationtool.com" -Level Warn
                        }
                    } else {
                        $txt_Status.Text = "No models found for the selected criteria."
                        Write-DATActivityLog "No models matched the selected criteria." -Level Warn
                    }
                }
            } catch {
                $txt_Status.Text = "Error processing results: $($_.Exception.Message)"
                Write-DATActivityLog "Result processing error: $($_.Exception.Message)" -Level Error
            } finally {
                $script:RefreshPS.Dispose()
                $script:RefreshRunspace.Dispose()
                $progress_Job.Visibility = 'Collapsed'
                $progress_Job.IsIndeterminate = $false
                $btn_RefreshModels.IsEnabled = $true
                Update-DATBuildButtonState
                # Auto-close the Loading Sources modal after a brief delay so users can see final status
                $script:SourceCloseTimer = [System.Windows.Threading.DispatcherTimer]::new()
                $script:SourceCloseTimer.Interval = [TimeSpan]::FromMilliseconds(1200)
                $script:SourceCloseTimer.Add_Tick({
                    $script:SourceCloseTimer.Stop()
                    Close-DATLoadingSourcesModal
                })
                $script:SourceCloseTimer.Start()
            }
        }
    })
    $script:RefreshTimer.Start()
})

# Model search filter - uses CollectionView to preserve sort state
$txt_ModelSearch.Add_TextChanged({
    $searchText = $txt_ModelSearch.Text
    $view = [System.Windows.Data.CollectionViewSource]::GetDefaultView($script:ModelData)
    if ([string]::IsNullOrEmpty($searchText)) {
        $view.Filter = $null
    } else {
        $view.Filter = [System.Predicate[object]]{
            param($item)
            $item.Model -like "*$searchText*" -or $item.OEM -like "*$searchText*" -or $item.Baseboards -like "*$searchText*"
        }
    }
    $grid_Models.ItemsSource = $view
})

$btn_SelectKnownModels = $Window.FindName('btn_SelectKnownModels')

function ConvertTo-DATNormalizedMake {
    <#
    .SYNOPSIS
        Normalizes a device manufacturer name to match OEM catalog conventions.
        E.g. "Dell Inc." -> "Dell", "Hewlett-Packard" -> "HP", "LENOVO" -> "Lenovo".
    #>
    param ([string]$Make)
    if ([string]::IsNullOrWhiteSpace($Make)) { return $Make }
    $m = $Make.Trim()
    if ($m -match '^Dell') { return 'Dell' }
    if ($m -match '^(HP|Hewlett-Packard|COMPAQ|Compaq)') { return 'HP' }
    if ($m -match '^Lenovo$') { return 'Lenovo' }
    if ($m -match '^Microsoft') { return 'Microsoft' }
    if ($m -match '^Acer') { return 'Acer' }
    return $m
}

function ConvertTo-DATNormalizedModel {
    <#
    .SYNOPSIS
        Normalizes a device model name to match OEM catalog conventions.
        Strips manufacturer prefixes and common device-type suffixes that
        appear in Intune/WMI data but not in OEM driver catalogs.
    #>
    param ([string]$Make, [string]$Model)
    if ([string]::IsNullOrWhiteSpace($Model)) { return $Model }
    $m = $Model.Trim()
    # HP: strip manufacturer prefix and common suffixes (matches catalog regex strip)
    if ($Make -match '^(HP|Hewlett-Packard|COMPAQ|Compaq)') {
        $m = $m -replace '^(HP|Hewlett-Packard|COMPAQ|Hp|Compaq)\s*', ''
        $m = $m -replace '\s+2-in-1\s+Notebook\s+PC$', ''
        $m = $m -replace '\s+Mobile\s+Workstation\s+PC$', ''
        $m = $m -replace '\s+Notebook\s+PC$', ''
        $m = $m -replace '\s+Desktop\s+PC$', ''
        $m = $m -replace '\s+All-in-One$', ''
        $m = $m -replace '\s+Mobile\s+Workstation$', ''
        $m = $m -replace '\s+PC$', ''
        $m = $m -replace '\sSFF\b', ' Small Form Factor'
        $m = $m -replace '\sUSDT\b', ' Desktop'
        $m = $m -replace '\sTWR\b', ' Tower'
        $m = $m -replace '\s*35W$', ''
    }
    # Dell: strip a leading manufacturer prefix and trailing desktop form-factor descriptors
    # that Intune/WMI include but the OEM catalog omits (e.g. Intune "Dell Latitude 5550" or
    # "Precision 3660 Tower" vs catalog "Latitude 5550" / "Precision 3660"). Both the catalog
    # grid model and the device model pass through this normalization, so stripping the same
    # tokens from each lets them match. Name fallback only -- baseboard/SKU stays primary.
    if ($Make -match '^Dell') {
        $m = $m -replace '^(Dell\s+Inc\.?|Dell)\s+', ''
        $m = $m -replace '\s+(Tower|SFF|MFF|Small\s+Form\s+Factor|Micro\s+Form\s+Factor)$', ''
    }
    return $m.Trim()
}

function Test-DATKnownDeviceMatch {
    <#
    .SYNOPSIS
        Returns $true when a catalog grid item matches a known device.
        Baseboard is the primary match when available on both sides;
        name-based matching is used as a fallback.
    .NOTES
        Baseboard sources by OEM:
          HP/Dell/Lenovo/Acer: Win32_BaseBoard.Product
          Microsoft Surface:   MS_SystemInformation.SystemSKU
    #>
    param (
        [string]$GridMake,
        [string]$GridModel,
        [string]$GridBaseboards,   # comma-separated catalog baseboard IDs
        [string]$DeviceMake,
        [string]$DeviceModel,
        [string]$DeviceBaseboard   # single baseboard value from inventory ($null if not collected)
    )

    # --- Baseboard-primary match ---
    # Only attempt if the inventory device has a baseboard value AND the catalog
    # entry has at least one baseboard value. Both sides must be non-empty.
    if (-not [string]::IsNullOrWhiteSpace($DeviceBaseboard) -and -not [string]::IsNullOrWhiteSpace($GridBaseboards)) {
        $normDeviceMake = ConvertTo-DATNormalizedMake -Make $DeviceMake
        if ($normDeviceMake -eq $GridMake) {
            $devBoard = $DeviceBaseboard.Trim().ToUpper()
            $catalogBoards = $GridBaseboards -split '[,;\s]+' | ForEach-Object { $_.Trim().ToUpper() } | Where-Object { $_ }
            if ($catalogBoards -contains $devBoard) { return $true }
        }
    }

    # --- Name-based fallback ---
    $normDeviceMake  = ConvertTo-DATNormalizedMake  -Make $DeviceMake
    $normDeviceModel = ConvertTo-DATNormalizedModel -Make $DeviceMake -Model $DeviceModel

    if ($GridModel -eq $normDeviceModel -or "$GridMake|$GridModel" -eq "$normDeviceMake|$normDeviceModel") {
        return $true
    }

    # --- HP prefix match (Intune returns full names with suffixes like "Notebook PC") ---
    # Intune model: "HP EliteBook 840 14 inch G11 Notebook PC"
    # Catalog model: "EliteBook 840 14 inch G11"
    # Strip the manufacturer prefix from the Intune name, then check if the catalog
    # model name appears at the start of the Intune name (followed by space or end).
    if ($normDeviceMake -eq 'HP' -and $GridMake -eq 'HP') {
        $hpStripped = ($DeviceModel -replace '^(HP|Hewlett-Packard|COMPAQ|Compaq)\s+', '').Trim()
        if ($hpStripped -eq $GridModel -or $hpStripped -like "$GridModel *") {
            return $true
        }
    }

    # --- Microsoft Surface prefix match (fallback when SystemSKU is unavailable) ---
    # WMI returns the base model name (e.g. "Surface Laptop 4") while the catalog may
    # append a CPU qualifier (e.g. "Surface Laptop 4 AMD"). If baseboard/SKU matching
    # did not fire (no baseboard data on either side), use prefix matching as a last resort.
    if ($normDeviceMake -eq 'Microsoft' -and $GridMake -eq 'Microsoft') {
        return ($GridModel -like "$normDeviceModel *")
    }

    return $false
}

function Update-DATSelectKnownModelsVisibility {
    <#
    .SYNOPSIS
        Shows or hides the 'Select Known Models' button. The button is shown when
        either known-model lookup option (ConfigMgr or Intune) is enabled -- even
        when no known devices were discovered -- or when known device data exists.
    #>
    $optionEnabled = ($null -ne $chk_KnownModels -and $chk_KnownModels.IsChecked) -or
                     ($null -ne $chk_IntuneKnownModels -and $chk_IntuneKnownModels.IsChecked)
    $hasKnown = ($script:IntuneKnownDevices -and @($script:IntuneKnownDevices).Count -gt 0) -or
                ($script:ConfigMgrKnownDevices -and @($script:ConfigMgrKnownDevices).Count -gt 0)
    $btn_SelectKnownModels.Visibility = if ($optionEnabled -or $hasKnown) { 'Visible' } else { 'Collapsed' }
}

$btn_SelectKnownModels.Add_Click({
    # Deselect all first so only known models end up selected
    foreach ($item in $script:ModelData) { $item.Selected = $false }

    # Apply Intune known model selection
    if ($script:IntuneKnownDevices -and @($script:IntuneKnownDevices).Count -gt 0) {
        foreach ($item in $script:ModelData) {
            $gridMake  = ConvertTo-DATNormalizedMake  -Make $item.OEM
            $gridModel = ConvertTo-DATNormalizedModel -Make $item.OEM -Model $item.Model
            foreach ($device in $script:IntuneKnownDevices) {
                if (Test-DATKnownDeviceMatch -GridMake $gridMake -GridModel $gridModel -GridBaseboards $item.Baseboards `
                        -DeviceMake $device.Make -DeviceModel $device.Model -DeviceBaseboard $device.Baseboard) {
                    $item.Selected = $true; break
                }
            }
        }
    }

    # Apply ConfigMgr known model selection
    if ($script:ConfigMgrKnownDevices -and @($script:ConfigMgrKnownDevices).Count -gt 0) {
        foreach ($item in $script:ModelData) {
            if (-not $item.Selected) {
                $gridMake  = ConvertTo-DATNormalizedMake  -Make $item.OEM
                $gridModel = ConvertTo-DATNormalizedModel -Make $item.OEM -Model $item.Model
                foreach ($device in $script:ConfigMgrKnownDevices) {
                    if (Test-DATKnownDeviceMatch -GridMake $gridMake -GridModel $gridModel -GridBaseboards $item.Baseboards `
                            -DeviceMake $device.Make -DeviceModel $device.Model -DeviceBaseboard $device.Baseboard) {
                        $item.Selected = $true; break
                    }
                }
            }
        }
    }

    $selectedCount = ($script:ModelData | Where-Object { $_.Selected }).Count
    Write-DATActivityLog "Selected $selectedCount known models from Intune/ConfigMgr device data" -Level Success

    # Sort so selected models appear at the top
    $view = [System.Windows.Data.CollectionViewSource]::GetDefaultView($script:ModelData)
    $view.SortDescriptions.Clear()
    $view.SortDescriptions.Add([System.ComponentModel.SortDescription]::new('Selected', [System.ComponentModel.ListSortDirection]::Descending))
    $view.SortDescriptions.Add([System.ComponentModel.SortDescription]::new('OEM', [System.ComponentModel.ListSortDirection]::Ascending))
    $view.SortDescriptions.Add([System.ComponentModel.SortDescription]::new('Model', [System.ComponentModel.ListSortDirection]::Ascending))
    foreach ($col in $grid_Models.Columns) {
        if ($col.SortMemberPath -eq 'Selected') {
            $col.SortDirection = [System.ComponentModel.ListSortDirection]::Descending
        } else {
            $col.SortDirection = $null
        }
    }

    Update-DATBuildButtonState
    Save-DATModelSelections
})

$btn_SelectAll.Add_Click({
    # Only select items visible in the current filtered view
    $view = [System.Windows.Data.CollectionViewSource]::GetDefaultView($script:ModelData)
    foreach ($item in $view) { $item.Selected = $true }
    Update-DATBuildButtonState
    Save-DATModelSelections
})

$btn_DeselectAll.Add_Click({
    # Only deselect items visible in the current filtered view
    $view = [System.Windows.Data.CollectionViewSource]::GetDefaultView($script:ModelData)
    foreach ($item in $view) { $item.Selected = $false }
    Update-DATBuildButtonState
    Save-DATModelSelections
})

function Update-DATBuildButtonState {
    $selectedCount = ($script:ModelData | Where-Object { $_.Selected }).Count
    $btn_Build.IsEnabled = ($selectedCount -gt 0)
    $btn_Schedule.IsEnabled = ($selectedCount -gt 0)
    if ($script:ModelData.Count -gt 0) {
        $txt_ModelCount.Text = "$selectedCount of $($script:ModelData.Count) selected"
    }
}

function Save-DATModelSelections {
    <#
    .SYNOPSIS
        Persists the currently selected models to a JSON file in Settings\.
        Called when a build starts so selections are remembered across sessions.
        Stores OEM, Model and Baseboards so selections can be restored by baseboard
        match even when the model list changes (e.g. after an OS change).
    #>
    $settingsDir = Join-Path $global:ScriptDirectory 'Settings'
    if (-not (Test-Path $settingsDir)) { New-Item -Path $settingsDir -ItemType Directory -Force | Out-Null }
    $jsonPath = Join-Path $settingsDir 'SelectedModels.json'

    $selections = @($script:ModelData | Where-Object { $_.Selected } | ForEach-Object {
        @{ OEM = $_.OEM; Model = $_.Model; Baseboards = $_.Baseboards; OS = $_.OS; Build = $_.Build }
    })
    $json = if ($selections.Count -eq 0) { '[]' } else { $selections | ConvertTo-Json -Depth 2 -Compress }
    Set-Content -Path $jsonPath -Value $json -Encoding UTF8 -Force
}

function Restore-DATModelSelections {
    <#
    .SYNOPSIS
        Restores previously selected models from the JSON file after a model refresh.
        First matches on OEM + Model name, then falls back to OEM + Baseboards overlap
        so selections survive OS changes where model names may differ but hardware IDs stay the same.
    #>
    $jsonPath = Join-Path $global:ScriptDirectory 'Settings\SelectedModels.json'
    if (-not (Test-Path $jsonPath)) { return }

    try {
        $saved = Get-Content -Path $jsonPath -Raw -ErrorAction Stop | ConvertFrom-Json -ErrorAction Stop
        if (-not $saved -or $saved.Count -eq 0) { return }

        # Build lookup sets. New-format entries include OS + Build so a model selected for a
        # specific Windows build (e.g. HP "Windows 11 25H2") only re-selects that build row
        # rather than every available build for the model. Legacy entries (no Build) fall back
        # to OEM|Model matching for backward compatibility. (#785)
        $savedExactSet  = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)  # OEM|Model|OS|Build
        $savedLegacySet = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)  # OEM|Model
        $savedBoardsByKey = @{}   # build-aware key: "OEM|OS|Build"; legacy key: "OEM"
        foreach ($entry in $saved) {
            $hasBuild = -not [string]::IsNullOrEmpty($entry.Build)
            if ($hasBuild) {
                [void]$savedExactSet.Add("$($entry.OEM)|$($entry.Model)|$($entry.OS)|$($entry.Build)")
                $bbKey = "$($entry.OEM)|$($entry.OS)|$($entry.Build)"
            } else {
                [void]$savedLegacySet.Add("$($entry.OEM)|$($entry.Model)")
                $bbKey = $entry.OEM
            }
            if (-not [string]::IsNullOrEmpty($entry.Baseboards)) {
                if (-not $savedBoardsByKey.ContainsKey($bbKey)) {
                    $savedBoardsByKey[$bbKey] = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
                }
                foreach ($bb in ($entry.Baseboards -split '[,;]+')) {
                    $bb = $bb.Trim()
                    if ($bb -ne '') { [void]$savedBoardsByKey[$bbKey].Add($bb) }
                }
            }
        }

        $matchCount = 0
        foreach ($item in $script:ModelData) {
            # Primary (new format): exact OEM + Model + OS + Build match
            if ($savedExactSet.Contains("$($item.OEM)|$($item.Model)|$($item.OS)|$($item.Build)")) {
                $item.Selected = $true
                $matchCount++
                continue
            }

            # Legacy format: OEM + Model match (re-selects all build rows for the model)
            if ($savedLegacySet.Contains("$($item.OEM)|$($item.Model)")) {
                $item.Selected = $true
                $matchCount++
                continue
            }

            # Fallback: baseboard overlap. Build-aware entries match only the same OS/Build;
            # legacy entries match on OEM alone so selections survive model-name drift.
            if (-not [string]::IsNullOrEmpty($item.Baseboards)) {
                $bbKeys = @("$($item.OEM)|$($item.OS)|$($item.Build)", $item.OEM)
                $itemBoards = $item.Baseboards -split '[,;]+' | ForEach-Object { $_.Trim() } | Where-Object { $_ -ne '' }
                $matched = $false
                foreach ($bbKey in $bbKeys) {
                    if (-not $savedBoardsByKey.ContainsKey($bbKey)) { continue }
                    foreach ($bb in $itemBoards) {
                        if ($savedBoardsByKey[$bbKey].Contains($bb)) {
                            $item.Selected = $true
                            $matchCount++
                            $matched = $true
                            break
                        }
                    }
                    if ($matched) { break }
                }
            }
        }

        if ($matchCount -gt 0) {
            Write-DATActivityLog "Restored $matchCount previously selected models" -Level Success
            Update-DATBuildButtonState
        }
    } catch {
        Write-DATActivityLog "Could not restore model selections: $($_.Exception.Message)" -Level Warn
    }
}

#endregion Model Selection Logic

#region Selection Profiles

# Saved selection profiles let the user capture the OEM/OS/Architecture/Platform/PackageType
# filters plus the selected models under a named profile, then reload them later.
$script:SuppressProfileSelect = $false

$cmb_Profiles      = $Window.FindName('cmb_Profiles')
$btn_SaveProfile   = $Window.FindName('btn_SaveProfile')
$btn_SaveAsProfile = $Window.FindName('btn_SaveAsProfile')
$btn_RenameProfile = $Window.FindName('btn_RenameProfile')
$btn_DeleteProfile = $Window.FindName('btn_DeleteProfile')

function Get-DATProfilesPath {
    # Resolve at call time -- $global:ScriptDirectory may not be set when this region loads.
    return (Join-Path $global:ScriptDirectory 'Settings\Profiles.json')
}

function Get-DATProfiles {
    # Returns a flat array of profile objects (empty array when none/invalid).
    $profilesPath = Get-DATProfilesPath
    if (-not (Test-Path $profilesPath)) { return @() }
    try {
        $raw = Get-Content -Path $profilesPath -Raw -ErrorAction Stop
        if ([string]::IsNullOrWhiteSpace($raw)) { return @() }
        # IMPORTANT: Windows PowerShell 5.1's ConvertFrom-Json returns a JSON array as a single
        # non-enumerated object, so @(...) would wrap it into a nested 1-element array. The
        # [object[]] cast flattens correctly in BOTH PS 5.1 and 7.
        $parsed = [object[]]($raw | ConvertFrom-Json -ErrorAction Stop)
        $flat = [System.Collections.Generic.List[object]]::new()
        foreach ($p in $parsed) {
            if ($null -eq $p) { continue }
            # Recover the legacy { value:[...]; Count:N } corruption an earlier nesting bug
            # could write: an entry with no Name but a 'value' payload wraps real profiles.
            # NOTE: use $p.value / $p.Name directly -- the .PSObject.Properties['value'] indexer
            # and $p.Count are unreliable on JSON objects under PS 5.1.
            if ([string]::IsNullOrEmpty([string]$p.Name) -and $null -ne $p.value) {
                foreach ($inner in @($p.value)) {
                    if ($null -ne $inner -and -not [string]::IsNullOrEmpty([string]$inner.Name)) { $flat.Add($inner) }
                }
            } else {
                $flat.Add($p)
            }
        }
        return @($flat.ToArray())
    } catch {
        Write-DATActivityLog "Could not read profiles: $($_.Exception.Message)" -Level Warn
        return @()
    }
}

function Save-DATProfilesFile {
    param ([Parameter(Mandatory)][AllowEmptyCollection()][array]$Profiles)
    $settingsDir = Join-Path $global:ScriptDirectory 'Settings'
    if (-not (Test-Path $settingsDir)) { New-Item -Path $settingsDir -ItemType Directory -Force | Out-Null }

    # Flatten any nested/corrupted entries before serialising so ConvertTo-Json always sees a
    # clean flat list of profile objects (avoids re-writing the {value:[...];Count:N} shape).
    $flat = [System.Collections.Generic.List[object]]::new()
    foreach ($p in $Profiles) {
        if ($null -eq $p) { continue }
        if ([string]::IsNullOrEmpty([string]$p.Name) -and $null -ne $p.value) {
            foreach ($inner in @($p.value)) {
                if ($null -ne $inner -and -not [string]::IsNullOrEmpty([string]$inner.Name)) { $flat.Add($inner) }
            }
        } elseif (($p -is [System.Collections.IEnumerable]) -and ($p -isnot [string])) {
            foreach ($inner in $p) { if ($null -ne $inner) { $flat.Add($inner) } }
        } else {
            $flat.Add($p)
        }
    }

    if ($flat.Count -eq 0) {
        Set-Content -Path (Get-DATProfilesPath) -Value '[]' -Encoding UTF8 -Force
        return
    }

    # -InputObject + explicit [object[]] forces a JSON array even for a single profile.
    $json = ConvertTo-Json -InputObject ([object[]]$flat.ToArray()) -Depth 6
    if ($json.TrimStart() -notmatch '^\[') { $json = "[`r`n$json`r`n]" }
    Set-Content -Path (Get-DATProfilesPath) -Value $json -Encoding UTF8 -Force
}

function Update-DATProfileDropdown {
    param ([string]$SelectName)
    $script:SuppressProfileSelect = $true
    try {
        $cmb_Profiles.Items.Clear()
        $placeholder = [System.Windows.Controls.ComboBoxItem]::new()
        $placeholder.Content = 'Select a profile...'
        $placeholder.Tag = '__placeholder__'
        [void]$cmb_Profiles.Items.Add($placeholder)
        foreach ($p in (Get-DATProfiles | Sort-Object Name)) {
            $item = [System.Windows.Controls.ComboBoxItem]::new()
            $item.Content = $p.Name
            [void]$cmb_Profiles.Items.Add($item)
        }
        $selected = $false
        if (-not [string]::IsNullOrEmpty($SelectName)) {
            foreach ($item in $cmb_Profiles.Items) {
                if ($item.Tag -ne '__placeholder__' -and $item.Content -eq $SelectName) {
                    $cmb_Profiles.SelectedItem = $item; $selected = $true; break
                }
            }
        }
        if (-not $selected) { $cmb_Profiles.SelectedIndex = 0 }
    } finally {
        $script:SuppressProfileSelect = $false
    }
    $hasSelection = ($cmb_Profiles.SelectedItem -and $cmb_Profiles.SelectedItem.Tag -ne '__placeholder__')
    $btn_DeleteProfile.IsEnabled = $hasSelection
    $btn_RenameProfile.IsEnabled = $hasSelection
    $btn_SaveProfile.IsEnabled = $hasSelection
    Update-DATProfilePlaceholderText
}

function Update-DATProfilePlaceholderText {
    # When a profile is active, the placeholder option lets the user return to a clean,
    # unsaved state -- label it "Create new profile". Otherwise it prompts to pick one.
    $hasSelection = ($cmb_Profiles.SelectedItem -and $cmb_Profiles.SelectedItem.Tag -ne '__placeholder__')
    foreach ($item in $cmb_Profiles.Items) {
        if ($item.Tag -eq '__placeholder__') {
            $item.Content = if ($hasSelection) { 'Create new profile' } else { 'Select a profile...' }
            break
        }
    }
}

function Get-DATCurrentSelectionProfile {
    # Captures the current filter + model selection state for a profile.
    $selectedModels = @($script:ModelData | Where-Object { $_.Selected } | ForEach-Object {
        [ordered]@{ OEM = $_.OEM; Model = $_.Model; Baseboards = $_.Baseboards; OS = $_.OS; Build = $_.Build }
    })
    # Enumerate the OS backing store directly into a flat string array. Do NOT use
    # @(Get-DATSelectedOSes) -- that helper returns the list via Write-Output -NoEnumerate
    # (a single array object), so wrapping it in @() yields a JAGGED array (e.g.
    # [["Windows 11 25H2"]]) which then breaks List[string].Add on load. (profiles)
    $osValues = [string[]]@($script:SelectedOSValues)
    [ordered]@{
        OEMs         = @(Get-DATSelectedOEMs)
        OS           = $osValues
        Architecture = if ($cmb_Architecture.SelectedItem) { [string]$cmb_Architecture.SelectedItem.Content } else { 'x64' }
        Platform     = if ($cmb_Platform.SelectedItem) { [string]$cmb_Platform.SelectedItem.Content } else { 'Download Only' }
        PackageType  = if ($cmb_PackageType.SelectedItem) { [string]$cmb_PackageType.SelectedItem.Content } else { 'Drivers' }
        Models       = $selectedModels
    }
}

function Save-DATCurrentProfile {
    # Save button: overwrite the currently-selected profile after a modal confirmation.
    $sel = $cmb_Profiles.SelectedItem
    if (-not $sel -or $sel.Tag -eq '__placeholder__') {
        # Nothing selected to overwrite -- fall back to the Save As (prompt) flow.
        Save-DATCurrentProfileAs
        return
    }
    if ((Get-DATSelectedOEMs).Count -eq 0 -or (Get-DATSelectedOSes).Count -eq 0) {
        Show-DATInfoDialog -Title 'Nothing to Save' -Type Warning `
            -Message 'Select at least one OEM and operating system before saving a profile.'
        return
    }
    $name = [string]$sel.Content
    if (-not (Show-DATConfirmDialog -Title 'Overwrite Profile?' `
            -Message "Overwrite the profile '$name' with the current selections?" -ConfirmLabel 'Overwrite')) {
        return
    }
    $profiles = @(Get-DATProfiles | Where-Object { $_.Name -ne $name })
    Write-DATProfileEntry -Name $name -Profiles $profiles
}

function Save-DATCurrentProfileAs {
    # Save As button: prompt for a name and save a new (or overwriting) profile.
    if ((Get-DATSelectedOEMs).Count -eq 0 -or (Get-DATSelectedOSes).Count -eq 0) {
        Show-DATInfoDialog -Title 'Nothing to Save' -Type Warning `
            -Message 'Select at least one OEM and operating system before saving a profile.'
        return
    }
    $name = Show-DATInputDialog -Title 'Save Profile As' `
        -Message 'Enter a name for this profile. Saving with an existing name overwrites it.' `
        -OkLabel 'Save'
    if ([string]::IsNullOrEmpty($name)) { return }

    $profiles = @(Get-DATProfiles)
    $existing = $profiles | Where-Object { $_.Name -eq $name }
    if ($existing) {
        if (-not (Show-DATConfirmDialog -Title 'Overwrite Profile?' `
                -Message "A profile named '$name' already exists. Overwrite it?" -ConfirmLabel 'Overwrite')) {
            return
        }
        $profiles = @($profiles | Where-Object { $_.Name -ne $name })
    }
    Write-DATProfileEntry -Name $name -Profiles $profiles
}

function Write-DATProfileEntry {
    # Shared writer: capture current selections under $Name, append to $Profiles, persist
    # and refresh the dropdown selecting the saved profile.
    param (
        [Parameter(Mandatory)][AllowEmptyString()][string]$Name,
        [Parameter(Mandatory)][AllowNull()]$Profiles
    )
    $profileList = @($Profiles)
    $profile = Get-DATCurrentSelectionProfile
    $profile['Name'] = $Name
    $profileList += [PSCustomObject]$profile
    Save-DATProfilesFile -Profiles $profileList
    Update-DATProfileDropdown -SelectName $Name
    Write-DATActivityLog "Saved profile '$Name' ($($profile.Models.Count) model(s))" -Level Success
    $txt_Status.Text = "Profile '$Name' saved."
}

function Invoke-DATApplyProfile {
    param ([Parameter(Mandatory)]$Profile)

    Write-DATActivityLog "Loading profile '$($Profile.Name)'..." -Level Info
    $script:SuppressModelRefresh = $true
    try {
        # OEMs -- capture the target set locally; the OEM change handler only sets a dirty
        # flag (refresh is suppressed), so no mid-loop mutation concern here.
        $targetOEMs = @($Profile.OEMs)
        foreach ($entry in $script:OEMCheckboxes.GetEnumerator()) {
            if ($entry.Value.IsEnabled) {
                $entry.Value.IsChecked = ($targetOEMs -contains $entry.Key)
            }
        }
        Update-DATOEMDisplayText
        Update-DATOEMSelectionHighlight

        # OS values -- suppress the checkbox change handler while we set states. Otherwise
        # each IsChecked change rebuilds $script:SelectedOSValues from the live (still-stale)
        # checkbox states, contaminating the loop condition and leaving previously-selected
        # OS builds checked (e.g. reloading a 25H2 profile kept 24H2 selected).
        # Flatten defensively: older profiles may have stored a jagged OS array
        # (e.g. [["Windows 11 25H2"]]); recurse one level and coerce each entry to a string.
        $targetOS = New-Object System.Collections.Generic.List[string]
        foreach ($o in @($Profile.OS)) {
            if ($null -ne $o -and $o -isnot [string] -and $o -is [System.Collections.IEnumerable]) {
                foreach ($inner in $o) {
                    $s = [string]$inner
                    if (-not [string]::IsNullOrEmpty($s)) { $targetOS.Add($s) }
                }
            } else {
                $s = [string]$o
                if (-not [string]::IsNullOrEmpty($s)) { $targetOS.Add($s) }
            }
        }
        $script:SuppressOSSync = $true
        try {
            foreach ($entry in $script:OSCheckboxes.GetEnumerator()) {
                if ($null -ne $entry.Value) { $entry.Value.IsChecked = ($targetOS -contains $entry.Key) }
            }
        } finally {
            $script:SuppressOSSync = $false
        }
        # Set the backing store explicitly from the profile (authoritative)
        $script:SelectedOSValues.Clear()
        foreach ($os in $targetOS) { $script:SelectedOSValues.Add($os) }
        Update-DATOSDisplayText
        Update-DATOSSelectionHighlight

        # Architecture / Platform / Package Type -- coalesce nulls to safe defaults so a
        # partially-populated profile never errors when written to the registry below.
        $profArch     = if (-not [string]::IsNullOrEmpty($Profile.Architecture)) { [string]$Profile.Architecture } else { 'x64' }
        $profPlatform = if (-not [string]::IsNullOrEmpty($Profile.Platform))     { [string]$Profile.Platform }     else { 'Download Only' }
        $profPkgType  = if (-not [string]::IsNullOrEmpty($Profile.PackageType))  { [string]$Profile.PackageType }  else { 'Drivers' }
        foreach ($pair in @(
            @{ Combo = $cmb_Architecture; Value = $profArch },
            @{ Combo = $cmb_Platform;     Value = $profPlatform },
            @{ Combo = $cmb_PackageType;  Value = $profPkgType }
        )) {
            foreach ($item in $pair.Combo.Items) {
                if ($item.Content -eq $pair.Value) { $pair.Combo.SelectedItem = $item; break }
            }
        }

        # Persist filter selections to registry (mirrors the Refresh button). All values are
        # guaranteed non-null here, so Set-DATRegistryValue's [String] param never rejects them.
        Set-DATRegistryValue -Name 'SelectedOEMs' -Value ((Get-DATSelectedOEMs) -join ',') -Type String
        Set-DATRegistryValue -Name 'OS' -Value ((Get-DATSelectedOSes) -join ';') -Type String
        Set-DATRegistryValue -Name 'Architecture' -Value $profArch -Type String
        Set-DATRegistryValue -Name 'Platform' -Value $profPlatform -Type String
        Set-DATRegistryValue -Name 'PackageType' -Value $profPkgType -Type String

        # Seed the profile's model list into SelectedModels.json so the post-refresh
        # restore selects exactly these models once the grid repopulates.
        $models = @($Profile.Models | ForEach-Object {
            @{ OEM = $_.OEM; Model = $_.Model; Baseboards = $_.Baseboards; OS = $_.OS; Build = $_.Build }
        })
        $settingsDir = Join-Path $global:ScriptDirectory 'Settings'
        if (-not (Test-Path $settingsDir)) { New-Item -Path $settingsDir -ItemType Directory -Force | Out-Null }
        $modelsJson = if ($models.Count -eq 0) { '[]' } else { ConvertTo-Json @($models) -Depth 3 -Compress }
        Set-Content -Path (Join-Path $settingsDir 'SelectedModels.json') -Value $modelsJson -Encoding UTF8 -Force
    } finally {
        $script:SuppressModelRefresh = $false
    }

    if ((Get-DATSelectedOEMs).Count -gt 0 -and (Get-DATSelectedOSes).Count -gt 0) {
        # Refresh runs in the background; its completion handler restores the seeded selections.
        Invoke-DATRefreshModelsClick
    }
}

function Reset-DATSelectionsForNewProfile {
    # Clears OEM/OS selections and the model grid so the user starts a fresh, unsaved profile.
    # Architecture/Platform/Package Type are left as-is (sensible carry-over defaults).
    $script:SuppressModelRefresh = $true
    try {
        foreach ($entry in $script:OEMCheckboxes.GetEnumerator()) {
            if ($entry.Value.IsEnabled) { $entry.Value.IsChecked = $false }
        }
        Update-DATOEMDisplayText
        Update-DATOEMSelectionHighlight

        $script:SuppressOSSync = $true
        try {
            foreach ($entry in $script:OSCheckboxes.GetEnumerator()) {
                if ($null -ne $entry.Value) { $entry.Value.IsChecked = $false }
            }
        } finally {
            $script:SuppressOSSync = $false
        }
        $script:SelectedOSValues.Clear()
        Update-DATOSDisplayText
        Update-DATOSSelectionHighlight

        Set-DATRegistryValue -Name 'SelectedOEMs' -Value '' -Type String
        Set-DATRegistryValue -Name 'OS' -Value '' -Type String

        if ($script:ModelData.Count -gt 0) { $script:ModelData.Clear() }
        $txt_ModelCount.Text = '0 models'
        $txt_Status.Text = 'Ready for a new profile -- select OEMs and an operating system.'
    } finally {
        $script:SuppressModelRefresh = $false
    }
    Update-DATBuildButtonState
}

if ($null -ne $cmb_Profiles) {
    $cmb_Profiles.Add_SelectionChanged({
        if ($script:SuppressProfileSelect) { return }
        $sel = $cmb_Profiles.SelectedItem
        $hasSelection = ($sel -and $sel.Tag -ne '__placeholder__')
        $btn_DeleteProfile.IsEnabled = $hasSelection
        $btn_RenameProfile.IsEnabled = $hasSelection
        $btn_SaveProfile.IsEnabled = $hasSelection
        # Relabel the placeholder with re-entrancy suppressed (mutating a ComboBoxItem's
        # Content can otherwise re-raise SelectionChanged).
        $script:SuppressProfileSelect = $true
        try { Update-DATProfilePlaceholderText } finally { $script:SuppressProfileSelect = $false }
        if (-not $hasSelection) {
            # User chose "Create new profile" -- clear the active selection for a blank slate.
            Reset-DATSelectionsForNewProfile
            return
        }
        $profile = Get-DATProfiles | Where-Object { $_.Name -eq $sel.Content } | Select-Object -First 1
        if ($profile) { Invoke-DATApplyProfile -Profile $profile }
    })

    $btn_SaveProfile.Add_Click({ Save-DATCurrentProfile })

    $btn_SaveAsProfile.Add_Click({ Save-DATCurrentProfileAs })

    $btn_RenameProfile.Add_Click({
        $sel = $cmb_Profiles.SelectedItem
        if (-not $sel -or $sel.Tag -eq '__placeholder__') { return }
        $oldName = [string]$sel.Content
        $newName = Show-DATInputDialog -Title 'Rename Profile' -Message "Enter a new name for '$oldName'." `
            -DefaultValue $oldName -OkLabel 'Rename'
        if ([string]::IsNullOrEmpty($newName) -or $newName -eq $oldName) { return }
        $profiles = @(Get-DATProfiles)
        if ($profiles | Where-Object { $_.Name -eq $newName }) {
            Show-DATInfoDialog -Title 'Name In Use' -Type Warning -Message "A profile named '$newName' already exists."
            return
        }
        foreach ($p in $profiles) { if ($p.Name -eq $oldName) { $p.Name = $newName } }
        Save-DATProfilesFile -Profiles $profiles
        Update-DATProfileDropdown -SelectName $newName
        Write-DATActivityLog "Renamed profile '$oldName' to '$newName'" -Level Success
    })

    $btn_DeleteProfile.Add_Click({
        $sel = $cmb_Profiles.SelectedItem
        if (-not $sel -or $sel.Tag -eq '__placeholder__') { return }
        $name = [string]$sel.Content
        if (-not (Show-DATConfirmDialog -Title 'Delete Profile?' `
                -Message "Delete the profile '$name'? This cannot be undone." -ConfirmLabel 'Delete')) {
            return
        }
        $profiles = @(Get-DATProfiles | Where-Object { $_.Name -ne $name })
        Save-DATProfilesFile -Profiles $profiles
        Update-DATProfileDropdown
        Write-DATActivityLog "Deleted profile '$name'" -Level Success
        $txt_Status.Text = "Profile '$name' deleted."
    })
}

#endregion Selection Profiles

#region Build Process

$btn_Build.Add_Click({
    # Check EULA acceptance before allowing build
    $eulaCheck = (Get-ItemProperty -Path $global:RegPath -Name "EULAAccepted" -ErrorAction SilentlyContinue).EULAAccepted
    if ($eulaCheck -ne "True") {
        # Navigate to About page and highlight the EULA requirement
        Set-DATActiveView -ViewName 'view_About' -NavButtonName 'nav_About'
        $txt_EulaWarning.Visibility = 'Visible'
        $txt_Status.Text = "Please accept the EULA to continue."
        Write-DATActivityLog "Build blocked -- EULA not yet accepted" -Level Warn
        return
    }

    # Guard: prevent a second build while one is already running
    if ($script:BuildPS -and $script:BuildAsyncResult -and -not $script:BuildAsyncResult.IsCompleted) {
        # If the previous build already finished (completion handled) but the runspace
        # hasn't been disposed yet, force cleanup instead of blocking the user
        if ($script:BuildCompletionHandled) {
            try { $script:BuildPS.Stop() } catch {}
            try { $script:BuildPS.EndInvoke($script:BuildAsyncResult) } catch {}
            try { $script:BuildPS.Dispose() } catch {}
            try { $script:BuildRunspace.Dispose() } catch {}
            $script:BuildAsyncResult = $null
            $script:BuildPS = $null
            $script:BuildRunspace = $null
            Write-DATActivityLog "Cleaned up stale build runspace from previous session" -Level Info
        } else {
            $txt_Status.Text = "A build is already in progress. Use Abort to stop it first."
            Write-DATActivityLog "Build blocked -- a build runspace is already running" -Level Warn
            return
        }
    }
    # Also clean up completed-but-undisposed runspace objects (timer may have stopped before cleanup)
    if ($script:BuildPS -and $script:BuildAsyncResult -and $script:BuildAsyncResult.IsCompleted) {
        try { $script:BuildPS.EndInvoke($script:BuildAsyncResult) } catch {}
        try { $script:BuildPS.Dispose() } catch {}
        try { $script:BuildRunspace.Dispose() } catch {}
        $script:BuildAsyncResult = $null
        $script:BuildPS = $null
        $script:BuildRunspace = $null
    }

    # Guard: ensure the target platform is connected before building
    $buildPlatform = if ($null -ne $cmb_Platform.SelectedItem) { $cmb_Platform.SelectedItem.Content } else { 'Download Only' }
    if ($buildPlatform -eq 'Configuration Manager' -and [string]::IsNullOrEmpty($global:SiteCode)) {
        Show-DATInfoDialog -Title 'ConfigMgr Not Connected' `
            -Message 'Please connect to Configuration Manager before building packages. Navigate to ConfigMgr Settings to configure the site server connection.' `
            -Type Warning -ButtonLabel 'OK'
        Write-DATActivityLog "Build blocked -- Configuration Manager not connected" -Level Warn
        return
    }
    if ($buildPlatform -eq 'Intune') {
        $authCheck = Get-DATIntuneAuthStatus
        if (-not $authCheck.IsAuthenticated) {
            Show-DATInfoDialog -Title 'Intune Not Connected' `
                -Message 'Please connect to Microsoft Intune before building packages. Navigate to Intune Settings > Environment to sign in.' `
                -Type Warning -ButtonLabel 'OK'
            Write-DATActivityLog "Build blocked -- Intune not connected" -Level Warn
            return
        }
    }

    $selectedModels = $script:ModelData | Where-Object { $_.Selected -eq $true }
    if ($selectedModels.Count -eq 0) {
        $txt_Status.Text = "No models selected."
        return
    }

    # Read package type early so we can guard against invalid combinations
    $buildPackageType = if ($null -ne $cmb_PackageType -and $null -ne $cmb_PackageType.SelectedItem) { $cmb_PackageType.SelectedItem.Content } else { 'Drivers' }

    # Guard: Microsoft models do not support standalone BIOS packages
    if ($buildPackageType -in @('BIOS', 'BIOS Pilot')) {
        $msModels = @($selectedModels | Where-Object { $_.OEM -eq 'Microsoft' })
        if ($msModels.Count -eq $selectedModels.Count) {
            # All selected models are Microsoft -- block the build entirely
            Show-DATInfoDialog -Title 'BIOS Packages Not Supported' `
                -Message "Microsoft Surface devices receive BIOS/firmware updates through the driver update process. Please select 'Drivers' or 'All' as the package type instead." `
                -Type Info -ButtonLabel 'OK'
            Write-DATActivityLog "Build blocked -- BIOS package type not supported for Microsoft models (firmware is included in driver updates)" -Level Warn
            return
        } elseif ($msModels.Count -gt 0) {
            # Mix of Microsoft and other OEMs -- warn and continue with non-Microsoft only
            $nonMsModels = @($selectedModels | Where-Object { $_.OEM -ne 'Microsoft' })
            $msNames = ($msModels | ForEach-Object { $_.Model }) -join ', '
            Show-DATInfoDialog -Title 'Microsoft Models Excluded' `
                -Message "Microsoft Surface devices receive BIOS/firmware updates through the driver update process. The following models will be skipped for BIOS packaging:`n`n$msNames`n`nProceeding with $($nonMsModels.Count) remaining model$(if ($nonMsModels.Count -ne 1) { 's' })." `
                -Type Warning -ButtonLabel 'Continue'
            Write-DATActivityLog "Microsoft models excluded from BIOS build: $msNames" -Level Warn
            # Replace selectedModels with non-Microsoft only
            $selectedModels = $nonMsModels
            if ($selectedModels.Count -eq 0) {
                $txt_Status.Text = "No eligible models remaining."
                return
            }
        }
    }

    # Pre-flight: validate that package storage path is configured and accessible
    # This must happen BEFORE showing the progress modal to avoid showing both warning and progress modals
    $regConfig = Get-ItemProperty -Path $global:RegPath -ErrorAction SilentlyContinue
    $packageStoragePath = if ($regConfig -and -not [string]::IsNullOrEmpty($regConfig.PackageStoragePath)) { $regConfig.PackageStoragePath } else { $null }
    if ([string]::IsNullOrEmpty($packageStoragePath) -or -not (Test-Path $packageStoragePath)) {
        Show-DATInfoDialog -Title 'Package Storage Path Required' `
            -Message 'A valid Package Storage Path must be specified before building packages. Please configure it in Common Settings > Storage Path Configuration.' `
            -Type Warning -ButtonLabel 'OK'
        Write-DATActivityLog "Build blocked -- Package Storage Path is not configured or does not exist" -Level Warn
        return
    }

    # Pre-flight: check for paths that may exceed MAX_PATH (260 chars)
    $pfSelectedOSes = Get-DATSelectedOSes
    $pfSelectedOS = if ($pfSelectedOSes.Count -gt 0) { $pfSelectedOSes[0] } else { 'Windows 11' }
    $pfMaxPathLimit = 260
    $pfNestedFileHeadroom = 80  # typical depth of driver INF subfolders inside the extraction
    # Use the user-configured temp storage path (same path the build actually uses)
    $pfRegConfig = Get-ItemProperty -Path $global:RegPath -ErrorAction SilentlyContinue
    $pfTempDir = if ($pfRegConfig -and -not [string]::IsNullOrEmpty($pfRegConfig.TempStoragePath)) { $pfRegConfig.TempStoragePath } else { $global:TempDirectory }

    # Warn if the temp storage path itself is excessively long
    if ($pfTempDir.Length -gt 100) {
        $pfTempMessage = "The temp storage path is $($pfTempDir.Length) characters long, which significantly increases the risk of exceeding the Windows 260-character path limit during driver extraction.`n`nCurrent path: $pfTempDir`n`nThis can cause driver extractions to fail silently or produce incomplete packages with missing files. If you continue, the resulting packages may not contain all expected drivers and could cause deployment issues.`n`nTo resolve this, shorten the temp storage path in Common Settings."
        $pfTempContinue = Show-DATConfirmDialog -Title 'Long Path Warning' `
            -Message $pfTempMessage -Type Warning -ConfirmLabel 'Continue Anyway' -CancelLabel 'Cancel Build'
        if (-not $pfTempContinue) {
            Write-DATActivityLog "Build cancelled by user -- temp storage path exceeds 100 chars ($($pfTempDir.Length) chars): $pfTempDir" -Level Warn
            return
        }
        Write-DATActivityLog "User acknowledged long temp storage path warning ($($pfTempDir.Length) chars)" -Level Warn
    }

    $pfLongModels = @()
    foreach ($m in $selectedModels) {
        $pfTestPath = Join-Path $pfTempDir "Build\$($m.OEM)\$($m.Model)\$pfSelectedOS\Extracted"
        if (($pfTestPath.Length + $pfNestedFileHeadroom) -ge $pfMaxPathLimit) {
            $pfLongModels += [PSCustomObject]@{
                Model      = "$($m.OEM) $($m.Model)"
                PathLength = $pfTestPath.Length
            }
        }
    }
    if ($pfLongModels.Count -gt 0) {
        $pfModelList = ($pfLongModels | ForEach-Object { "  - $($_.Model) ($($_.PathLength) chars)" }) -join "`n"
        $pfMessage = "The following model(s) have extraction paths that may exceed the Windows 260-character path limit:`n`n$pfModelList`n`nThis can cause driver extractions to fail silently or produce incomplete packages with missing files. If you continue, the resulting packages may not contain all expected drivers and could cause deployment issues.`n`nTo resolve this, shorten the temp storage path (currently: $pfTempDir)."
        $pfContinue = Show-DATConfirmDialog -Title 'Long Path Warning' `
            -Message $pfMessage -Type Warning -ConfirmLabel 'Continue Anyway' -CancelLabel 'Cancel Build'
        if (-not $pfContinue) {
            Write-DATActivityLog "Build cancelled by user -- extraction paths exceed MAX_PATH for $($pfLongModels.Count) model(s)" -Level Warn
            return
        }
        Write-DATActivityLog "User acknowledged long path warning for $($pfLongModels.Count) model(s)" -Level Warn
    }

    # Pre-flight: check available free space on the temp and package storage drives.
    # Estimate ~4 GB per selected model for driver extraction and packaging. UNC/network
    # paths are skipped -- their free space is managed remotely and DriveInfo is unreliable.
    $pfRequiredGB = $selectedModels.Count * 4
    $pfSpaceTargets = @(
        [PSCustomObject]@{ Label = 'Temp storage'; Path = $pfTempDir },
        [PSCustomObject]@{ Label = 'Package storage'; Path = $packageStoragePath }
    )
    $pfLowSpaceDrives = @()
    $pfSeenRoots = @{}
    foreach ($pfTarget in $pfSpaceTargets) {
        if ([string]::IsNullOrWhiteSpace($pfTarget.Path)) { continue }
        # Skip UNC / network paths
        if ($pfTarget.Path -match '^\\\\') { continue }
        try {
            $pfRoot = [System.IO.Path]::GetPathRoot($pfTarget.Path)
            if (-not $pfRoot -or $pfRoot.StartsWith('\\')) { continue }
            # Avoid checking the same physical drive twice (temp and package may share a drive)
            $pfRootKey = $pfRoot.ToUpperInvariant()
            if ($pfSeenRoots.ContainsKey($pfRootKey)) { continue }
            $pfSeenRoots[$pfRootKey] = $true
            $pfDrive = [System.IO.DriveInfo]::new($pfRoot)
            if (-not $pfDrive.IsReady) { continue }
            $pfFreeGB = [math]::Round($pfDrive.AvailableFreeSpace / 1GB, 1)
            if ($pfFreeGB -lt $pfRequiredGB) {
                $pfLowSpaceDrives += [PSCustomObject]@{
                    Label  = $pfTarget.Label
                    Root   = $pfRoot
                    FreeGB = $pfFreeGB
                }
            }
        } catch { }
    }
    if ($pfLowSpaceDrives.Count -gt 0) {
        $pfDriveList = ($pfLowSpaceDrives | ForEach-Object { "  - $($_.Label) ($($_.Root)): $($_.FreeGB) GB free" }) -join "`n"
        $pfModelPlural = if ($selectedModels.Count -ne 1) { 's' } else { '' }
        $pfDrivePhrase = if ($pfLowSpaceDrives.Count -ne 1) { 'these locations have' } else { 'this location has' }
        $pfSpaceMessage = "You are running low on disk space.`n`nBuilding $($selectedModels.Count) model$pfModelPlural needs an estimated $pfRequiredGB GB (approximately 4 GB per model), but $pfDrivePhrase less available:`n`n$pfDriveList`n`nIf you continue, the build might run out of space and may not complete, leaving packages incomplete.`n`nDo you want to continue anyway?"
        $pfSpaceContinue = Show-DATConfirmDialog -Title 'Low Disk Space' `
            -Message $pfSpaceMessage -Type Warning -ConfirmLabel 'Continue' -CancelLabel 'Cancel'
        if (-not $pfSpaceContinue) {
            Write-DATActivityLog "Build cancelled by user -- low disk space (required ~$pfRequiredGB GB; low: $(($pfLowSpaceDrives | ForEach-Object { "$($_.Root) $($_.FreeGB)GB" }) -join ', '))" -Level Warn
            return
        }
        Write-DATActivityLog "User acknowledged low disk space warning (required ~$pfRequiredGB GB; low: $(($pfLowSpaceDrives | ForEach-Object { "$($_.Root) $($_.FreeGB)GB" }) -join ', '))" -Level Warn
    }

    $btn_Build.IsEnabled = $false
    $btn_Abort.IsEnabled = $true
    $progress_Job.Visibility = 'Visible'
    $progress_Job.IsIndeterminate = $false
    $progress_Job.Maximum = $selectedModels.Count
    $progress_Job.Value = 0

    # Store selected configuration (null-safe -- #5)
    $selectedPlatform = if ($null -ne $cmb_Platform.SelectedItem) { $cmb_Platform.SelectedItem.Content } else { 'Download Only' }
    $selectedOSes = Get-DATSelectedOSes
    $selectedOS = $selectedOSes -join ';'
    $selectedArch = if ($null -ne $cmb_Architecture.SelectedItem) { $cmb_Architecture.SelectedItem.Content } else { 'x64' }

    Set-DATRegistryValue -Name "Platform" -Value "$selectedPlatform" -Type String
    Set-DATRegistryValue -Name "OS" -Value "$selectedOS" -Type String
    Set-DATRegistryValue -Name "Architecture" -Value "$selectedArch" -Type String

    $global:SelectedModels = [System.Collections.ArrayList]::new()
    foreach ($model in $selectedModels) {
        # Determine the OS label for package naming
        $osForPackage = if ($model.Build -eq 'All') {
            # Dell uses build-agnostic packages -- use the model's own OS property directly (e.g. "Windows 11")
            if (-not [string]::IsNullOrEmpty($model.OS)) {
                $model.OS
            } else {
                [array]$osArr = $selectedOSes
                ($osArr[0] -split '\s+')[0..1] -join ' '
            }
        } elseif ($model.OS -and $model.Build -and $model.Build -ne 'All') {
            # Specific build selected, use "OS Build" format
            "$($model.OS) $($model.Build)"
        } else {
            # Default: just the base OS version
            [array]$osArr = $selectedOSes
            ($osArr[0] -split '\s+')[0..1] -join ' '  # "Windows 11"
        }
        
        $modelObj = [PSCustomObject]@{
            OEM              = $model.OEM
            Model            = $model.Model
            Baseboards       = $model.Baseboards
            OS               = $osForPackage
            Architecture     = $selectedArch
            CustomDriverPath = $model.CustomDriverPath
            Version          = $model.Version
            BIOSVersion      = $(try { $model.BIOSVersion } catch { '' })
            ForceUpdate      = [bool]$model.ForceUpdate
            BIOSOnly         = $(try { [bool]$model.BIOSOnly } catch { $false })
            DownloadURL      = $(try { $model.DownloadURL } catch { '' })
        }
        $global:SelectedModels.Add($modelObj) | Out-Null
    }

    $global:SelectedModelCount = $global:SelectedModels.Count
    Save-DATModelSelections
    Set-DATRegistryValue -Name "SelectedModelCount" -Value "$($global:SelectedModelCount)" -Type String
    Set-DATRegistryValue -Name "TotalJobs" -Value "$($global:SelectedModelCount)" -Type String
    Set-DATRegistryValue -Name "CurrentJob" -Value "1" -Type String
    Set-DATRegistryValue -Name "CompletedJobs" -Value "0" -Type String
    Set-DATRegistryValue -Name "RunningState"  -Value "Starting" -Type String
    Set-DATRegistryValue -Name "RunningMode"   -Value "Download" -Type String
    Set-DATRegistryValue -Name "PackagePhase"  -Value "" -Type String
    Set-DATRegistryValue -Name "RunningMessage" -Value "Starting process. Checking pre-requisites..." -Type String
    Set-DATRegistryValue -Name "DownloadSize" -Value "---" -Type String
    Set-DATRegistryValue -Name "BytesTransferred" -Value "0" -Type String
    Set-DATRegistryValue -Name "DownloadBytes" -Value "0" -Type String
    Set-DATRegistryValue -Name "DownloadSpeed" -Value "---" -Type String

    $txt_Status.Text = "Building $($global:SelectedModelCount) packages..."
    $txt_Status.Foreground = [System.Windows.Media.SolidColorBrush]::new(
        [System.Windows.Media.ColorConverter]::ConvertFromString(
            (Get-DATTheme -ThemeName $script:CurrentTheme)['WindowForeground']))
    $txt_Status.Tag = 'WindowForeground'
    Write-DATActivityLog "Starting build for $($global:SelectedModelCount) models" -Level Info

    # Track elapsed time and show running status
    $script:BuildStartTime = Get-Date
    $pill_BuildStatus.Background = [System.Windows.Media.SolidColorBrush]::new(
        [System.Windows.Media.ColorConverter]::ConvertFromString(
            (Get-DATTheme -ThemeName $script:CurrentTheme)['AccentColor']))
    $txt_BuildStatusIcon.Text = [string][char]0xE916
    $txt_BuildStatusIcon.Foreground = [System.Windows.Media.Brushes]::White
    $txt_BuildStatusText.Text = "Running"
    $txt_BuildStatusText.Foreground = [System.Windows.Media.Brushes]::White
    $pill_BuildStatus.Visibility = 'Visible'
    $txt_BuildElapsed.Text = "00:00:00"
    $txt_BuildElapsed.Visibility = 'Visible'
    $script:BuildCompletionHandled = $false
    $script:BuildProgressLastJob = 0
    $script:BuildProgressLastCompletedJobs = 0
    $script:BuildLastLoggedMode = ''
    $script:BuildLastLoggedPct = -1

    # Show build progress panel
    $panel_BuildProgress.Visibility = 'Visible'
    $txt_BuildCurrentJob.Text = "1"
    $txt_BuildRemaining.Text = "$($global:SelectedModelCount)"
    $txt_BuildFileSize.Text = "---"
    $txt_BuildJobStatus.Text = "Starting process. Checking pre-requisites..."
    $progress_Download.Value = 0
    $txt_BuildDownloadPercent.Text = "0%"
    $txt_BuildDownloadSpeed.Text = ""
    $txt_BuildProgressLabel.Text = "Download:"

    # Show build progress modal with per-model pipeline stages
    Show-DATBuildProgressModal -Models $global:SelectedModels -Platform $selectedPlatform -PackageType $buildPackageType

    # Launch processing in a background job
    $script:BuildRunspace = [runspacefactory]::CreateRunspace()
    $script:BuildRunspace.ApartmentState = 'STA'
    $script:BuildRunspace.Open()
    $script:BuildPS = [powershell]::Create()
    $script:BuildPS.Runspace = $script:BuildRunspace
    [void]$script:BuildPS.AddScript({
        param($ModulePath, $ScriptDir, $RegPath, $RunningMode, $SelectedModels, $StoragePath, $PackagePath, $IntuneToken, $IntuneRefreshTok, $IntuneAuthClientIdParam, $IntuneTokenExpSec, $DisableToast, $DisableRestart, $SiteServer, $SiteCode, $PackageType, $DPGroups, $DPs, $DistPriority, $EnableBDR, $DebugBuildPath, $CustomBrandingPath, $HPPasswordBinPath, $ToastTimeoutAction, $MaxDeferrals, $BIOSRestartDelayMinutes, $TeamsWebhookUrl, $TeamsNotificationsEnabled, $CustomToastTextsJson, $ConsoleFolderID, $MaintenanceWindowsJson, $AlarmMode)
        try {
        Import-Module $ModulePath -Force
        $procParams = @{
            ScriptDirectory = $ScriptDir
            RegPath         = $RegPath
            RunningMode     = $RunningMode
            SelectedModels  = $SelectedModels
            StoragePath     = $StoragePath
            PackagePath     = $PackagePath
            IntuneAuthToken = $IntuneToken
        }
        if (-not [string]::IsNullOrEmpty($IntuneRefreshTok)) { $procParams['IntuneRefreshToken'] = $IntuneRefreshTok }
        if (-not [string]::IsNullOrEmpty($IntuneAuthClientIdParam)) { $procParams['IntuneAuthClientId'] = $IntuneAuthClientIdParam }
        if ($IntuneTokenExpSec -gt 0) { $procParams['IntuneTokenExpiresInSec'] = $IntuneTokenExpSec }
        if ($DisableToast) { $procParams['DisableToast'] = $true }
        if ($DisableRestart) { $procParams['DisableRestart'] = $true }
        if ($AlarmMode) { $procParams['AlarmMode'] = $true }
        if ($ToastTimeoutAction -ne 'RemindMeLater') { $procParams['ToastTimeoutAction'] = $ToastTimeoutAction }
        if ($MaxDeferrals -gt 0) { $procParams['MaxDeferrals'] = $MaxDeferrals }
        if ($BIOSRestartDelayMinutes -gt 0 -and $BIOSRestartDelayMinutes -ne 10) { $procParams['RestartDelaySeconds'] = $BIOSRestartDelayMinutes * 60 }
        if (-not [string]::IsNullOrEmpty($DebugBuildPath)) { $procParams['DebugBuildPath'] = $DebugBuildPath }
        if (-not [string]::IsNullOrEmpty($CustomBrandingPath)) { $procParams['CustomBrandingPath'] = $CustomBrandingPath }
        if (-not [string]::IsNullOrEmpty($HPPasswordBinPath)) { $procParams['HPPasswordBinPath'] = $HPPasswordBinPath }
        if (-not [string]::IsNullOrEmpty($CustomToastTextsJson)) { $procParams['CustomToastTextsJson'] = $CustomToastTextsJson }
        if (-not [string]::IsNullOrEmpty($MaintenanceWindowsJson)) { $procParams['MaintenanceWindowsJson'] = $MaintenanceWindowsJson }
        if (-not [string]::IsNullOrEmpty($SiteServer)) { $procParams['SiteServer'] = $SiteServer }
        if (-not [string]::IsNullOrEmpty($SiteCode)) { $procParams['SiteCode'] = $SiteCode }
        if (-not [string]::IsNullOrEmpty($PackageType)) { $procParams['PackageType'] = $PackageType }
        if ($DPGroups -and $DPGroups.Count -gt 0) { $procParams['DistributionPointGroups'] = $DPGroups }
        if ($DPs -and $DPs.Count -gt 0) { $procParams['DistributionPoints'] = $DPs }
        if (-not [string]::IsNullOrEmpty($DistPriority)) { $procParams['DistributionPriority'] = $DistPriority }
        if ($EnableBDR) { $procParams['EnableBinaryDeltaReplication'] = $true }
        if ($null -ne $ConsoleFolderID -and $ConsoleFolderID -ge 0) { $procParams['ConsoleFolderID'] = $ConsoleFolderID }
        if ($TeamsNotificationsEnabled -and -not [string]::IsNullOrEmpty($TeamsWebhookUrl)) {
            $procParams['TeamsNotificationsEnabled'] = $true
            $procParams['TeamsWebhookUrl'] = $TeamsWebhookUrl
        }
        Start-DATModelProcessing @procParams
        } catch [System.Management.Automation.PipelineStoppedException] {
            # Abort signal received -- set registry state and exit cleanly
            try { Set-ItemProperty -Path $RegPath -Name 'RunningState' -Value 'Aborted' -Force -ErrorAction SilentlyContinue } catch {}
        }
    })
    $modulePath = Join-Path $PSScriptRoot "..\Modules\DriverAutomationToolCore\DriverAutomationToolCore.psd1"

    # Read user-configured storage paths from registry (already validated above)
    $tempStoragePath = if ($regConfig -and -not [string]::IsNullOrEmpty($regConfig.TempStoragePath)) { $regConfig.TempStoragePath } else { Join-Path $global:ScriptDirectory 'Temp' }

    # Pass Intune auth token, refresh token, and real expiry for Intune mode
    $intuneToken = $null
    $intuneRefreshToken = $null
    $intuneAuthClientId = $null
    $intuneTokenExpSec = 0
    if ($selectedPlatform -eq 'Intune') {
        $authStatus = Get-DATIntuneAuthStatus
        if ($authStatus.IsAuthenticated) {
            $coreModule = Get-Module -Name DriverAutomationToolCore
            if ($coreModule) {
                $intuneToken = & $coreModule { $script:IntuneAuthToken }
                $intuneRefreshToken = & $coreModule { $script:IntuneRefreshToken }
                $intuneAuthClientId = & $coreModule { $script:IntuneAuthClientId }
                $intuneTokenExpSec = [math]::Max(0, [int]($authStatus.MinutesRemaining * 60))
            }
        } else {
            Write-DATActivityLog "Intune platform selected but not authenticated. Build aborted." -Level Warn
            $txt_Status.Text = "Please authenticate to Intune before building packages."
            $txt_Status.Foreground = [System.Windows.Media.SolidColorBrush]::new(
                [System.Windows.Media.ColorConverter]::ConvertFromString(
                    (Get-DATTheme -ThemeName $script:CurrentTheme)['StatusWarning']))
            $txt_Status.Tag = 'StatusWarning'
            $btn_Build.IsEnabled = $true
            $btn_Abort.IsEnabled = $false
            $progress_Job.Visibility = 'Collapsed'
            $pill_BuildStatus.Visibility = 'Collapsed'
            $txt_BuildElapsed.Visibility = 'Collapsed'
            $panel_BuildProgress.Visibility = 'Collapsed'
            return
        }
    }

    # Read the Disable Toast checkbox state (Intune only)
    $disableToast = ($selectedPlatform -eq 'Intune') -and ($chk_DisableToastPrompt.IsChecked -eq $true)

    # Read the Critical Notification (alarm mode) state (Intune only) -- bypasses Focus Assist / DND
    $alarmMode = ($selectedPlatform -eq 'Intune') -and ($chk_CriticalNotification.IsChecked -eq $true)

    # Read toast behaviour settings (Intune only)
    $biosTimeoutAction = if ($cmb_BIOSTimeoutAction.SelectedIndex -eq 1) { 'InstallNow' } else { 'RemindMeLater' }
    $biosMaxDeferrals  = if (($chk_EnableMaxDeferrals.IsChecked -eq $true) -and
        (-not [string]::IsNullOrEmpty($txt_MaxDeferrals.Text)) -and
        ($txt_MaxDeferrals.Text -match '^\d+$')) { [int]$txt_MaxDeferrals.Text } else { 0 }

    # Read the Debug Package Build state (Intune only)
    $debugBuildPath = if (($selectedPlatform -eq 'Intune') -and ($chk_DebugPackageBuild.IsChecked -eq $true) -and
        (-not [string]::IsNullOrEmpty($txt_DebugBuildPath.Text))) { $txt_DebugBuildPath.Text } else { $null }

    # Gather ConfigMgr settings for Configuration Manager mode
    $cmSiteServer = if ($regConfig -and -not [string]::IsNullOrEmpty($regConfig.SiteServer)) { $regConfig.SiteServer } else { $null }
    $cmSiteCode = $global:SiteCode
    $cmPackageType = if ($null -ne $cmb_PackageType -and $null -ne $cmb_PackageType.SelectedItem) { $cmb_PackageType.SelectedItem.Content } else { 'Drivers' }
    $cmDPGroups = if ($regConfig -and -not [string]::IsNullOrEmpty($regConfig.SelectedDPGroups)) { @($regConfig.SelectedDPGroups -split ';;') } else { @() }
    $cmDPs = if ($regConfig -and -not [string]::IsNullOrEmpty($regConfig.SelectedDPs)) { @($regConfig.SelectedDPs -split '\|') } else { @() }
    $cmDistPriority = if ($null -ne $cmb_DistPriority -and $null -ne $cmb_DistPriority.SelectedItem) { $cmb_DistPriority.SelectedItem.Content } else { 'Normal' }

    [void]$script:BuildPS.AddArgument((Resolve-Path $modulePath).Path)
    [void]$script:BuildPS.AddArgument($global:ScriptDirectory)
    [void]$script:BuildPS.AddArgument($global:RegPath)
    [void]$script:BuildPS.AddArgument($selectedPlatform)
    [void]$script:BuildPS.AddArgument($global:SelectedModels.ToArray())
    [void]$script:BuildPS.AddArgument($tempStoragePath)
    [void]$script:BuildPS.AddArgument($packageStoragePath)
    [void]$script:BuildPS.AddArgument($intuneToken)
    [void]$script:BuildPS.AddArgument($intuneRefreshToken)
    [void]$script:BuildPS.AddArgument($intuneAuthClientId)
    [void]$script:BuildPS.AddArgument($intuneTokenExpSec)
    [void]$script:BuildPS.AddArgument($disableToast)
    $disableRestart = ($selectedPlatform -eq 'Intune') -and ($chk_DisableBIOSRestart.IsChecked -eq $true)
    [void]$script:BuildPS.AddArgument($disableRestart)
    [void]$script:BuildPS.AddArgument($cmSiteServer)
    [void]$script:BuildPS.AddArgument($cmSiteCode)
    [void]$script:BuildPS.AddArgument($cmPackageType)
    [void]$script:BuildPS.AddArgument($cmDPGroups)
    [void]$script:BuildPS.AddArgument($cmDPs)
    [void]$script:BuildPS.AddArgument($cmDistPriority)
    $cmEnableBDR = ($chk_BinaryDiffReplication.IsChecked -eq $true)
    [void]$script:BuildPS.AddArgument($cmEnableBDR)
    [void]$script:BuildPS.AddArgument($debugBuildPath)
    [void]$script:BuildPS.AddArgument($script:CustomBrandingImagePath)
    [void]$script:BuildPS.AddArgument($script:HPPasswordBinPath)
    [void]$script:BuildPS.AddArgument($biosTimeoutAction)
    [void]$script:BuildPS.AddArgument($biosMaxDeferrals)
    $biosRestartDelay = if ((-not [string]::IsNullOrEmpty($txt_BIOSRestartDelay.Text)) -and
        ($txt_BIOSRestartDelay.Text -match '^\d+$')) { [int]$txt_BIOSRestartDelay.Text } else { 10 }
    [void]$script:BuildPS.AddArgument($biosRestartDelay)

    # Teams notification settings
    $teamsEnabled = $chk_TeamsNotifications.IsChecked -eq $true
    $teamsUrl = $txt_TeamsWebhookUrl.Text
    [void]$script:BuildPS.AddArgument($teamsUrl)
    [void]$script:BuildPS.AddArgument($teamsEnabled)

    # Custom toast text (Intune only) -- pass per-type custom texts as JSON
    $customToastTextsJson = $null
    if ($selectedPlatform -eq 'Intune') {
        $toastTexts = @{}
        foreach ($typeKey in @('Toast_Drivers', 'Toast_BIOS', 'Toast_Success', 'Toast_BIOSSuccess', 'Toast_Issues', 'Toast_BIOSIssues')) {
            $tTitle    = (Get-ItemProperty -Path $global:RegPath -Name "${typeKey}_Title" -ErrorAction SilentlyContinue)."${typeKey}_Title"
            $tBody     = (Get-ItemProperty -Path $global:RegPath -Name "${typeKey}_Body" -ErrorAction SilentlyContinue)."${typeKey}_Body"
            $tGreeting = (Get-ItemProperty -Path $global:RegPath -Name "${typeKey}_Greeting" -ErrorAction SilentlyContinue)."${typeKey}_Greeting"
            $tSubtitle = (Get-ItemProperty -Path $global:RegPath -Name "${typeKey}_Subtitle" -ErrorAction SilentlyContinue)."${typeKey}_Subtitle"
            $tActionBtn  = (Get-ItemProperty -Path $global:RegPath -Name "${typeKey}_ActionButton" -ErrorAction SilentlyContinue)."${typeKey}_ActionButton"
            $tDismissBtn = (Get-ItemProperty -Path $global:RegPath -Name "${typeKey}_DismissButton" -ErrorAction SilentlyContinue)."${typeKey}_DismissButton"
            if (-not [string]::IsNullOrEmpty($tTitle) -or -not [string]::IsNullOrEmpty($tBody) -or -not [string]::IsNullOrEmpty($tGreeting) -or -not [string]::IsNullOrEmpty($tSubtitle) -or -not [string]::IsNullOrEmpty($tActionBtn) -or -not [string]::IsNullOrEmpty($tDismissBtn)) {
                $toastTexts[$typeKey] = @{ Title = $tTitle; Body = $tBody; Greeting = $tGreeting; Subtitle = $tSubtitle; ActionButton = $tActionBtn; DismissButton = $tDismissBtn }
            }
        }
        if ($toastTexts.Count -gt 0) {
            $customToastTextsJson = ($toastTexts | ConvertTo-Json -Compress -Depth 3)
        }
    }
    [void]$script:BuildPS.AddArgument($customToastTextsJson)

    # Console Folder ID -- read from registry if custom folder is enabled
    $cmConsoleFolderID = [int]-1
    if ($chk_CustomConsoleFolder.IsChecked -eq $true) {
        $folderIdVal = (Get-ItemProperty -Path $global:RegPath -Name 'ConsoleFolderID' -ErrorAction SilentlyContinue).ConsoleFolderID
        if ($null -ne $folderIdVal) { $cmConsoleFolderID = [int]$folderIdVal }
    }
    [void]$script:BuildPS.AddArgument($cmConsoleFolderID)

    # Maintenance window schedule (Intune only) -- pass the stored JSON when the feature is enabled
    $maintenanceWindowsJson = $null
    if ($selectedPlatform -eq 'Intune') {
        $mwEnabledVal = (Get-ItemProperty -Path $global:RegPath -Name 'MaintenanceWindowEnabled' -ErrorAction SilentlyContinue).MaintenanceWindowEnabled
        if ($mwEnabledVal -eq 1) {
            $mwJsonReg = (Get-ItemProperty -Path $global:RegPath -Name 'MaintenanceWindows' -ErrorAction SilentlyContinue).MaintenanceWindows
            if (-not [string]::IsNullOrWhiteSpace($mwJsonReg)) { $maintenanceWindowsJson = $mwJsonReg }
        }
    }
    [void]$script:BuildPS.AddArgument($maintenanceWindowsJson)

    # Critical Notification / alarm mode (Intune only) -- last positional argument
    [void]$script:BuildPS.AddArgument($alarmMode)

    $script:BuildAsyncResult = $script:BuildPS.BeginInvoke()

    # Poll registry for progress updates (mirrors original timer_JobMonitor)
    $script:BuildProgressTimer = New-Object System.Windows.Threading.DispatcherTimer
    $script:BuildProgressTimer.Interval = [TimeSpan]::FromSeconds(1)
    $script:BuildProgressTimer.Add_Tick({
        # Guard against disposed-object access after window close (#14)
        if ($script:WindowClosing) { try { $script:BuildProgressTimer.Stop() } catch {}; return }
        try {

        # If completion already handled (normal finish or abort), just wait for runspace to fully stop
        if ($script:BuildCompletionHandled) {
            if ($null -eq $script:BuildAsyncResult -or $script:BuildAsyncResult.IsCompleted) {
                $script:BuildProgressTimer.Stop()
                if ($null -ne $script:BuildAsyncResult) {
                    try { $script:BuildPS.EndInvoke($script:BuildAsyncResult) } catch {
                        # Suppress expected abort noise -- "pipeline stopped" and "object disposed"
                        # are normal when the runspace was forcibly stopped by the Abort button
                        $msg = $_.Exception.Message
                        if ($msg -notmatch 'pipeline.*stopped|object.*disposed|disposed.*object') {
                            Write-DATActivityLog "Build error: $msg" -Level Error
                        }
                    }
                    try {
                        foreach ($streamErr in $script:BuildPS.Streams.Error) {
                            if ($streamErr.Exception.Message -notmatch 'pipeline.*stopped|object.*disposed') {
                                Write-DATActivityLog "Background error: $($streamErr.Exception.Message)" -Level Error
                            }
                        }
                    } catch {
                        # Runspace may already be disposed -- log only unexpected errors
                        if ($_.Exception.Message -notmatch 'object.*disposed|disposed.*object') {
                            Write-DATActivityLog "Error reading build stream: $($_.Exception.Message)" -Level Warn
                        }
                    }
                    try { $script:BuildPS.Dispose(); $script:BuildRunspace.Dispose() } catch { }
                    $script:BuildAsyncResult = $null
                    $script:BuildPS        = $null
                }
            }
            return
        }

        # Update elapsed time
        if ($script:BuildStartTime) {
            $elapsed = (Get-Date) - $script:BuildStartTime
            $txt_BuildElapsed.Text = "{0:hh\:mm\:ss}" -f $elapsed
        }

        # Update build progress modal from registry
        Update-DATBuildModalFromRegistry

        # Check if a Lenovo flash utility was auto-killed during extraction
        try {
            $flashKilled = (Get-ItemProperty -Path $global:RegPath -Name 'LenovoFlashKilled' -ErrorAction SilentlyContinue).LenovoFlashKilled
            if (-not [string]::IsNullOrEmpty($flashKilled)) {
                Remove-ItemProperty -Path $global:RegPath -Name 'LenovoFlashKilled' -ErrorAction SilentlyContinue
                Show-DATLenovoFlashKilledModal -ProcessName $flashKilled
            }
        } catch { }

        # Read registry for progress
        $regValues = $null
        try {
            $regValues = Get-ItemProperty -Path $global:RegPath -ErrorAction SilentlyContinue
        } catch { }

        if ($regValues) {
            $stateMessage = [string]$regValues.RunningMessage
            $fileSize = [string]$regValues.DownloadSize
            $fileBytesSize = [string]$regValues.DownloadBytes
            $bytesTransferred = [string]$regValues.BytesTransferred
            $downloadSpeed = [string]$regValues.DownloadSpeed
            $currentJob = $regValues.CurrentJob
            $completedJobs = $regValues.CompletedJobs
            $totalJobs = $regValues.TotalJobs

            # Update status text
            if (-not [string]::IsNullOrEmpty($stateMessage)) {
                $txt_BuildJobStatus.Text = $stateMessage
            }

            # Determine current phase label
            $runMode = [string]$regValues.RunningMode
            if ($runMode -like 'Intune*' -or $runMode -like 'Upload*') {
                $txt_BuildProgressLabel.Text = "Upload:"
            } else {
                $txt_BuildProgressLabel.Text = "Download:"
            }

            # Relay phase transitions and milestones to the activity log
            if (-not [string]::IsNullOrEmpty($runMode) -and $runMode -ne $script:BuildLastLoggedMode) {
                # Phase changed -- log the transition with the current message
                $logMsg = if (-not [string]::IsNullOrEmpty($stateMessage)) { $stateMessage } else { $runMode }
                Write-DATActivityLog $logMsg -Level Info
                $script:BuildLastLoggedMode = $runMode
                $script:BuildLastLoggedPct = -1
            }
            # Log upload/download progress at 25% intervals
            if (-not [string]::IsNullOrEmpty($stateMessage) -and $stateMessage -match '(\d+)%') {
                $msgPct = [int]$Matches[1]
                $pctMilestone = [math]::Floor($msgPct / 25) * 25
                if ($pctMilestone -gt 0 -and $pctMilestone -gt $script:BuildLastLoggedPct) {
                    Write-DATActivityLog $stateMessage -Level Info
                    $script:BuildLastLoggedPct = $pctMilestone
                }
            }

            # Update file size label
            if (-not [string]::IsNullOrEmpty($fileSize)) {
                $txt_BuildFileSize.Text = $fileSize
            }

            # Update download progress -- cast to [long] to avoid string comparison pitfalls
            $fileBytesLong     = [long]0
            $bytesTransferLong = [long]0
            $null = [long]::TryParse($fileBytesSize,     [ref]$fileBytesLong)
            $null = [long]::TryParse($bytesTransferred,  [ref]$bytesTransferLong)

            if ($fileBytesLong -gt 0 -and $bytesTransferLong -gt 0) {
                $downloadPct = [math]::Min(100, [math]::Round(($bytesTransferLong / $fileBytesLong) * 100, 0))
                $progress_Download.Value = $downloadPct
                $txt_BuildDownloadPercent.Text = "$downloadPct%"
            }

            # Update download speed label
            if (-not [string]::IsNullOrEmpty($downloadSpeed) -and $downloadSpeed -ne '---') {
                $txt_BuildDownloadSpeed.Text = $downloadSpeed
            } else {
                $txt_BuildDownloadSpeed.Text = ""
            }

            # Update counters and overall progress (#12 -- safe int parse)
            $completed = 0; $total = 0; $current = 0
            $hasJobs = $false
            if ($null -ne $completedJobs -and $null -ne $totalJobs) {
                $hasJobs = [int]::TryParse([string]$completedJobs, [ref]$completed) -and
                           [int]::TryParse([string]$totalJobs, [ref]$total)
            }
            if ($hasJobs -and $total -gt 0) {
                $null = [int]::TryParse([string]$currentJob, [ref]$current)
                if ($current -le 0) { $current = $completed + 1 }

                $txt_BuildCurrentJob.Text = "$current / $total"
                $txt_BuildRemaining.Text = "$([math]::Max(0, $total - $completed))"

                if ($completed -le $total) {
                    $progress_Job.Value = $completed
                }
            }
        }

        # Detect completion from registry state OR runspace completing
        $isRegistryComplete = $false
        if ($regValues) {
            $runState = [string]$regValues.RunningState
            $isRegistryComplete = ($runState -eq 'Completed' -or $runState -eq 'CompletedWithErrors')
            # If state is Aborted, the abort handler owns cleanup -- skip completion processing
            if ($runState -eq 'Aborted') {
                try { $script:BuildProgressTimer.Stop() } catch {}
                return
            }
        }
        $isRunspaceComplete = ($null -ne $script:BuildAsyncResult) -and $script:BuildAsyncResult.IsCompleted

        if ($isRegistryComplete -or $isRunspaceComplete) {
            $script:BuildCompletionHandled = $true

            # If runspace is done, clean it up now and stop the timer
            $streamErrors = @()
            if ($isRunspaceComplete) {
                $script:BuildProgressTimer.Stop()
                try { $script:BuildPS.EndInvoke($script:BuildAsyncResult) } catch {
                    # Only suppress expected pipeline/disposed noise (#3)
                    $msg = $_.Exception.Message
                    if ($msg -notmatch 'pipeline.*stopped|object.*disposed|disposed.*object') {
                        Write-DATActivityLog "Build error: $msg" -Level Error
                    }
                }
                $streamErrors = @($script:BuildPS.Streams.Error)
                foreach ($streamErr in $streamErrors) {
                    Write-DATActivityLog "Background error: $($streamErr.Exception.Message)" -Level Error
                }
                try { $script:BuildPS.Dispose(); $script:BuildRunspace.Dispose() } catch { }
            }
            # If only registry complete (runspace still running), timer continues for cleanup

            # Always re-read registry AFTER EndInvoke -- $regValues was captured at the start of
            # this tick and may be stale (the runspace writes its final state just before it exits,
            # so a tick that fires exactly on completion would see the old "Running" snapshot).
            $finalReg = Get-ItemProperty -Path $global:RegPath -ErrorAction SilentlyContinue
            $finalMessage = if ($finalReg -and -not [string]::IsNullOrEmpty($finalReg.RunningMessage)) {
                $finalReg.RunningMessage
            } else { "Build process completed." }

            # Freeze elapsed time
            $totalElapsed = if ($script:BuildStartTime) {
                $e = (Get-Date) - $script:BuildStartTime
                "{0:hh\:mm\:ss}" -f $e
            } else { "" }
            $txt_BuildElapsed.Text = $totalElapsed
            $script:BuildStartTime = $null

            # Determine success or failure (#12 -- safe int parse)
            $runningState = if ($finalReg) { [string]$finalReg.RunningState } else { "" }
            $fCompJobs = 0; $fTotalJobs = 1
            if ($finalReg -and $finalReg.CompletedJobs) { $null = [int]::TryParse([string]$finalReg.CompletedJobs, [ref]$fCompJobs) }
            if ($finalReg -and $finalReg.TotalJobs)     { $null = [int]::TryParse([string]$finalReg.TotalJobs, [ref]$fTotalJobs); if ($fTotalJobs -le 0) { $fTotalJobs = 1 } }
            $hadErrors = ($streamErrors.Count -gt 0) -or
                         ($finalMessage -match 'failed|error|aborted') -or
                         ($runningState -eq 'CompletedWithErrors') -or
                         ($fCompJobs -lt $fTotalJobs)
            $isNoMatch = ($runningState -eq 'CompletedNoMatch')
            if ($isNoMatch) {
                # BIOS-only build with no catalog matches -- show warning amber state
                $theme = Get-DATTheme -ThemeName $script:CurrentTheme
                $pill_BuildStatus.Background = [System.Windows.Media.SolidColorBrush]::new(
                    [System.Windows.Media.ColorConverter]::ConvertFromString($theme['StatusWarning']))
                $txt_BuildStatusIcon.Text = [string][char]0xE7BA  # Warning icon
                $txt_BuildStatusIcon.Foreground = [System.Windows.Media.Brushes]::Black
                $txt_BuildStatusText.Text = "No Match"
                $txt_BuildStatusText.Foreground = [System.Windows.Media.Brushes]::Black
                $txt_Status.Foreground = [System.Windows.Media.SolidColorBrush]::new(
                    [System.Windows.Media.ColorConverter]::ConvertFromString($theme['StatusWarning']))
                $txt_Status.Tag = 'StatusWarning'
            } elseif ($hadErrors) {
                $pill_BuildStatus.Background = [System.Windows.Media.SolidColorBrush]::new(
                    [System.Windows.Media.ColorConverter]::ConvertFromString(
                        (Get-DATTheme -ThemeName $script:CurrentTheme)['StatusError']))
                $txt_BuildStatusIcon.Text = [string][char]0xEA39
                $txt_BuildStatusIcon.Foreground = [System.Windows.Media.Brushes]::White
                $txt_BuildStatusText.Text = "Failed"
                $txt_BuildStatusText.Foreground = [System.Windows.Media.Brushes]::White
                $txt_Status.Foreground = [System.Windows.Media.SolidColorBrush]::new(
                    [System.Windows.Media.ColorConverter]::ConvertFromString(
                        (Get-DATTheme -ThemeName $script:CurrentTheme)['StatusError']))
                $txt_Status.Tag = 'StatusError'
            } else {
                $pill_BuildStatus.Background = [System.Windows.Media.SolidColorBrush]::new(
                    [System.Windows.Media.ColorConverter]::ConvertFromString(
                        (Get-DATTheme -ThemeName $script:CurrentTheme)['ButtonSuccess']))
                $txt_BuildStatusIcon.Text = [string][char]0xE73E
                $txt_BuildStatusIcon.Foreground = [System.Windows.Media.Brushes]::White
                $txt_BuildStatusText.Text = "Succeeded"
                $txt_BuildStatusText.Foreground = [System.Windows.Media.Brushes]::White
                $txt_Status.Foreground = [System.Windows.Media.SolidColorBrush]::new(
                    [System.Windows.Media.ColorConverter]::ConvertFromString(
                        (Get-DATTheme -ThemeName $script:CurrentTheme)['StatusSuccess']))
                $txt_Status.Tag = 'StatusSuccess'
            }

            $panel_BuildProgress.Visibility = 'Collapsed'
            $progress_Job.Visibility = 'Collapsed'
            $btn_Build.IsEnabled = $true
            $btn_Abort.IsEnabled = $false
            $txt_Status.Text = "$finalMessage ($totalElapsed)"
            Write-DATActivityLog "$finalMessage (elapsed: $totalElapsed)" -Level $(if ($hadErrors) { 'Error' } elseif ($isNoMatch) { 'Warn' } else { 'Success' })

            # Close build progress modal -- mark remaining as success if build succeeded (skip no-match)
            Close-DATBuildProgressModal -MarkAllSuccess:$(-not $hadErrors -and -not $isNoMatch)

            # Show build summary dialog with per-type success/fail counts
            try {
                $sumReg = Get-ItemProperty -Path $global:RegPath -ErrorAction SilentlyContinue
                $sumDriverPkgs = 0; $sumBiosPkgs = 0
                if ($sumReg.CompletedDriverPackages) { [int]::TryParse($sumReg.CompletedDriverPackages, [ref]$sumDriverPkgs) | Out-Null }
                if ($sumReg.CompletedBiosPackages) { [int]::TryParse($sumReg.CompletedBiosPackages, [ref]$sumBiosPkgs) | Out-Null }
                $sumPkgType = if ($sumReg.PackageType) { [string]$sumReg.PackageType } else { 'Drivers' }
                Show-DATBuildSummaryDialog -TotalModels $fTotalJobs `
                    -DriverSuccess $sumDriverPkgs -BiosSuccess $sumBiosPkgs `
                    -PackageType $sumPkgType -Elapsed $totalElapsed -HadErrors $hadErrors
            } catch {
                Write-DATLogEntry -Value "[UI] Build summary dialog error: $($_.Exception.Message)" -Severity 2
            }

            # Submit telemetry summary for this build session
            try {
                $telePlatform = if ($null -ne $cmb_Platform.SelectedItem) { $cmb_Platform.SelectedItem.Content } else { 'Unknown' }
                $fDriverPkgs = 0
                $fBiosPkgs = 0
                $finalReg = Get-ItemProperty -Path $global:RegPath -ErrorAction SilentlyContinue
                if ($finalReg.CompletedDriverPackages) { [int]::TryParse($finalReg.CompletedDriverPackages, [ref]$fDriverPkgs) | Out-Null }
                if ($finalReg.CompletedBiosPackages) { [int]::TryParse($finalReg.CompletedBiosPackages, [ref]$fBiosPkgs) | Out-Null }
                Send-DATSummaryReport -DriverPackagesCreated $fDriverPkgs `
                    -BiosPackagesCreated $fBiosPkgs `
                    -ModelsProcessed $fTotalJobs `
                    -Platform $telePlatform `
                    -ExecutionMode $global:ExecutionMode
            } catch {
                Write-DATLogEntry -Value "[Telemetry] Summary report failed: $($_.Exception.Message)" -Severity 2
            }

            # Package retention post-run cleanup
            if (-not $hadErrors -and -not $isNoMatch -and
                $null -ne $chk_PackageRetentionEnabled -and $chk_PackageRetentionEnabled.IsChecked) {
                try {
                    # Build the list of model keys from the selected models grid
                    $retainCount = 0
                    if ($null -ne $cmb_RetentionCount -and $cmb_RetentionCount.SelectedItem) {
                        $retainCount = [int]$cmb_RetentionCount.SelectedItem.Content
                    }
                    $platform = if ($null -ne $cmb_Platform.SelectedItem) { $cmb_Platform.SelectedItem.Content } else { '' }
                    $isIntune  = $platform -match 'Intune'
                    $isCM      = $platform -match 'ConfigMgr|SCCM|MECM'
                    $selectedOS   = if ($null -ne $cmb_OperatingSystem.SelectedItem) { $cmb_OperatingSystem.SelectedItem.Content } else { 'Windows 11' }
                    $selectedArch = if ($null -ne $cmb_Architecture.SelectedItem)     { $cmb_Architecture.SelectedItem.Content }     else { 'x64' }
                    $modelKeys = @()
                    if ($null -ne $script:SelectedModels) {
                        $modelKeys = @($script:SelectedModels | ForEach-Object {
                            "$($_.OEM)|$($_.Model)|$selectedOS|$selectedArch|$($_.PackageType)"
                        })
                    }
                    if ($modelKeys.Count -gt 0) {
                        $retentionParams = @{
                            ModelKeys   = $modelKeys
                            RetainCount = $retainCount
                        }
                        if ($isCM) {
                            $cmSiteServer = if ($null -ne $txt_SiteServer) { $txt_SiteServer.Text } else { '' }
                            $cmSiteCode   = if ($null -ne $txt_SiteCode)   { $txt_SiteCode.Text }   else { '' }
                            if ($cmSiteServer -and $cmSiteCode) {
                                $retentionParams['SiteServer'] = $cmSiteServer
                                $retentionParams['SiteCode']   = $cmSiteCode
                            }
                        }
                        if ($isIntune) { $retentionParams['Intune'] = $true }
                        Show-DATPackageRetentionModal @retentionParams
                    }
                } catch {
                    Write-DATLogEntry -Value "[Retention] Post-build cleanup error: $($_.Exception.Message)" -Severity 2
                }
            }
        }
        } catch {
            # Safety net -- prevent timer tick exceptions from crashing the WPF app
            try { $script:BuildProgressTimer.Stop() } catch {}
        }
    })
    $script:BuildProgressTimer.Start()
})

$btn_Abort.Add_Click({
    try {
        # Update UI immediately -- do NOT block the UI thread with Stop()/EndInvoke()
        $txt_Status.Text = "Aborting..."

        # Stop the progress timer so no more progress updates fire
        if ($script:BuildProgressTimer) {
            try { $script:BuildProgressTimer.Stop() } catch {}
        }

        # Signal abort via registry FIRST -- the monitoring loop checks this and exits early
        Set-DATRegistryValue -Name "RunningState" -Type String -Value "Aborted"

        # Kill child processes inline on the UI thread.  Process kills are sub-millisecond
        # each, so they will NOT freeze the UI.  The previous ThreadPool approach shared the
        # PowerShell session state with the UI thread -- concurrent cmdlet execution from two
        # threads corrupted the session state and crashed the process seconds later.

        # Kill any child process registered in the registry (curl / DISM)
        try {
            $RegProps = Get-ItemProperty -Path $global:RegPath -ErrorAction SilentlyContinue
            $RunningProcessID   = $RegProps.RunningProcessID
            $RunningProcessName = $RegProps.RunningProcess
            $pidVal = 0
            if (-not [string]::IsNullOrEmpty($RunningProcessID) -and [int]::TryParse($RunningProcessID, [ref]$pidVal)) {
                if ($pidVal -gt 0 -and $pidVal -ne $PID) {
                    Stop-Process -Id $pidVal -Force -ErrorAction SilentlyContinue
                }
            } elseif (-not [string]::IsNullOrEmpty($RunningProcessName) -and
                      $RunningProcessName -notmatch '^(powershell|pwsh)$') {
                Get-Process -Name $RunningProcessName -ErrorAction SilentlyContinue | Stop-Process -Force -ErrorAction SilentlyContinue
            }
        } catch {}

        # Kill orphaned DISM/dismhost processes
        foreach ($procName in @('dismhost', 'dism')) {
            Get-Process -Name $procName -ErrorAction SilentlyContinue | ForEach-Object {
                try { $_.Kill() } catch {}
            }
        }

        # Kill any running HP SoftPaq self-extracting processes (SP*.exe)
        Get-Process -ErrorAction SilentlyContinue | Where-Object {
            $_.ProcessName -match '^SP\d+$'
        } | ForEach-Object {
            try { $_.Kill() } catch {}
        }

        # Kill any running curl processes spawned by the tool
        Get-Process -Name 'curl' -ErrorAction SilentlyContinue | ForEach-Object {
            try { $_.Kill() } catch {}
        }

        # Signal the runspace to stop -- BeginStop is fire-and-forget, does NOT block the UI thread.
        # The runspace will complete asynchronously; CleanupTimer below handles Dispose once done.
        if ($script:BuildPS) {
            try { [void]$script:BuildPS.BeginStop($null, $null) } catch {}
        }

        # Fire-and-forget DISM cleanup -- runs in a separate process so no session state conflict.
        # The Window.Closing handler also does this, but we want to clean up promptly after abort.
        try {
            Start-Process -FilePath "$env:SystemRoot\System32\dism.exe" `
                -ArgumentList '/Cleanup-Wim' -WindowStyle Hidden
        } catch {}

        # Close build progress modal without marking remaining as success
        if ($script:BuildModal) {
            try { $script:BuildModal.Close() } catch { }
            $script:BuildModal = $null
            $script:BuildModalRows = @{}
        }

        $panel_BuildProgress.Visibility = 'Collapsed'
        $progress_Job.Visibility = 'Collapsed'
        $btn_Build.IsEnabled = $true
        $btn_Abort.IsEnabled = $false

        # Show aborted status with elapsed time
        $totalElapsed = if ($script:BuildStartTime) {
            $e = (Get-Date) - $script:BuildStartTime
            "{0:hh\:mm\:ss}" -f $e
        } else { "" }
        $txt_BuildElapsed.Text = $totalElapsed
        $pill_BuildStatus.Background = [System.Windows.Media.SolidColorBrush]::new(
            [System.Windows.Media.ColorConverter]::ConvertFromString(
                (Get-DATTheme -ThemeName $script:CurrentTheme)['StatusWarning']))
        $txt_BuildStatusIcon.Text = [string][char]0xE7BA
        $txt_BuildStatusIcon.Foreground = [System.Windows.Media.Brushes]::Black
        $txt_BuildStatusText.Text = "Aborted"
        $txt_BuildStatusText.Foreground = [System.Windows.Media.Brushes]::Black
        $txt_Status.Text = "Build process aborted ($totalElapsed)"
    } catch {
        # Catch-all for the abort handler -- prevents unhandled exceptions from crashing WPF
        try { $txt_Status.Text = "Abort encountered an error: $($_.Exception.Message)" } catch {}
    } finally {
        $script:BuildStartTime = $null
        $script:BuildCompletionHandled = $true

        # Start a lightweight cleanup timer that waits for the runspace to fully stop,
        # then disposes it -- all off the UI thread (just a polling check every 500ms).
        $script:CleanupTimer = New-Object System.Windows.Threading.DispatcherTimer
        $script:CleanupTimer.Interval = [TimeSpan]::FromMilliseconds(500)
        $script:CleanupTimer.Add_Tick({
            try {
                if ($null -eq $script:BuildAsyncResult -or $script:BuildAsyncResult.IsCompleted) {
                    $script:CleanupTimer.Stop()
                    if ($script:BuildAsyncResult) {
                        try { $script:BuildPS.EndInvoke($script:BuildAsyncResult) } catch {}
                    }
                    try { $script:BuildPS.Dispose()      } catch {}
                    try { $script:BuildRunspace.Dispose() } catch {}

                    # Kill any DISM/dismhost processes orphaned by the now-stopped runspace
                    foreach ($procName in @('dismhost', 'dism')) {
                        Get-Process -Name $procName -ErrorAction SilentlyContinue | ForEach-Object {
                            try { $_.Kill() } catch {}
                        }
                    }
                    $script:BuildAsyncResult = $null
                    $script:BuildPS          = $null
                    $script:BuildRunspace    = $null
                }
            } catch {
                # Safety net -- prevent timer tick exceptions from crashing the app
                try { $script:CleanupTimer.Stop() } catch {}
            }
        })
        $script:CleanupTimer.Start()
    }
})

