function Update-DATIntuneChartFromApps {
    # Populate the Intune donut charts from $script:IntuneAppsData
    $apps = $script:IntuneAppsData
    $total = ($apps | Measure-Object).Count
    if ($total -eq 0) {
        $panel_IntuneChart.Visibility = 'Collapsed'
        return
    }

    $driverCount = ($apps | Where-Object { $_.DisplayName -like 'Drivers -*' } | Measure-Object).Count
    $biosCount = ($apps | Where-Object { $_.DisplayName -like 'BIOS -*' -or $_.DisplayName -like 'Bios Update -*' } | Measure-Object).Count
    $otherCount = $total - $driverCount - $biosCount

    Update-DATIntunePackageDonutChart -DriverCount $driverCount -BiosCount $biosCount -OtherCount $otherCount

    $mfrCounts = @{
        'Dell'      = ($apps | Where-Object { $_.DisplayName -match '- Dell ' } | Measure-Object).Count
        'HP'        = ($apps | Where-Object { $_.DisplayName -match '- HP ' -or $_.DisplayName -match '- Hewlett-Packard ' } | Measure-Object).Count
        'Lenovo'    = ($apps | Where-Object { $_.DisplayName -match '- Lenovo ' } | Measure-Object).Count
        'Microsoft' = ($apps | Where-Object { $_.DisplayName -match '- Microsoft ' } | Measure-Object).Count
        'Acer'      = ($apps | Where-Object { $_.DisplayName -match '- Acer ' } | Measure-Object).Count
    }
    $mfrCounts['Other'] = $total - ($mfrCounts.Values | Measure-Object -Sum).Sum

    Update-DATIntuneManufacturerDonutChart -Counts $mfrCounts
    $panel_IntuneChart.Visibility = 'Visible'
}

function Reset-DATSiteServerInfoPanel {
    $txt_ServerIP.Text = [char]0x2014
    $txt_ServerSiteCode.Text = [char]0x2014
    $txt_ServerCMVersion.Text = [char]0x2014
    $txt_ServerOSVersion.Text = [char]0x2014
    $txt_ServerPackageCount.Text = [char]0x2014
    $panel_SiteServerInfo.Visibility = 'Collapsed'
    $panel_PackageChart.Visibility = 'Collapsed'
}

function Invoke-DATConfigMgrConnect {
    param ([string]$SiteServer, [bool]$UseSSL)

    if ([string]::IsNullOrEmpty($SiteServer)) {
        $txt_SiteCode.Foreground = $Window.FindResource('StatusWarning')
        $txt_SiteCode.Text = "Please enter a site server."
        Reset-DATSiteServerInfoPanel
        return
    }

    # Show attempting status
    $txt_SiteCode.Foreground = $Window.FindResource('StatusInfo')
    $txt_SiteCode.Text = "Attempting connection..."
    Reset-DATSiteServerInfoPanel
    # Clear stale connection globals before attempting new connection
    $global:SiteCode = $null
    $global:SiteServer = $null
    $global:ConfigMgrValidation = $false
    if ($global:DATCimSession) {
        Remove-CimSession -CimSession $global:DATCimSession -ErrorAction SilentlyContinue
        $global:DATCimSession = $null
    }
    $Window.Dispatcher.Invoke([System.Windows.Threading.DispatcherPriority]::Render, [action]{})

    try {
        Connect-DATConfigMgr -SiteServer $SiteServer | Out-Null
        if (-not [string]::IsNullOrEmpty($global:SiteCode)) {
            $txt_SiteCode.Foreground = $Window.FindResource('StatusSuccess')
            $txt_SiteCode.Text = "Connected - Site Code: $($global:SiteCode)"
            Set-DATRegistryValue -Name "SiteServer" -Value $SiteServer -Type String
            Set-DATRegistryValue -Name "WinRMSSL" -Value ([int]$UseSSL) -Type DWord

            # Populate site server information panel
            $txt_ServerSiteCode.Text = $global:SiteCode

            # IP Address
            try {
                $ipAddresses = [System.Net.Dns]::GetHostAddresses($SiteServer) |
                    Where-Object { $_.AddressFamily -eq 'InterNetwork' } |
                    Select-Object -ExpandProperty IPAddressToString
                $txt_ServerIP.Text = if ($ipAddresses) { ($ipAddresses -join ', ') } else { 'Unable to resolve' }
            } catch {
                $txt_ServerIP.Text = 'Unable to resolve'
            }

            # ConfigMgr Version
            try {
                Write-DATActivityLog "[WMI] \\$SiteServer\root\SMS\Site_$($global:SiteCode) : SMS_Site" -Level Info
                $cmVersion = Invoke-DATRemoteQuery -CimSession $global:DATCimSession -ComputerName $SiteServer `
                    -Namespace "root\SMS\Site_$($global:SiteCode)" -ClassName SMS_Site |
                    Select-Object -ExpandProperty Version
                $txt_ServerCMVersion.Text = if ($cmVersion) { $cmVersion } else { 'Not available' }
                Write-DATActivityLog "[WMI] ConfigMgr version: $cmVersion" -Level Info
            } catch {
                $txt_ServerCMVersion.Text = 'Not available'
            }

            # Server OS Version
            try {
                Write-DATActivityLog "[WMI] \\$SiteServer\root\cimv2 : Win32_OperatingSystem" -Level Info
                $osInfo = Invoke-DATRemoteQuery -CimSession $global:DATCimSession -ComputerName $SiteServer `
                    -Namespace "root\cimv2" -ClassName Win32_OperatingSystem
                $txt_ServerOSVersion.Text = if ($osInfo) { "$($osInfo.Caption) ($($osInfo.Version))" } else { 'Not available' }
                Write-DATActivityLog "[WMI] Site server OS: $($osInfo.Caption) ($($osInfo.Version))" -Level Info
            } catch {
                $txt_ServerOSVersion.Text = 'Not available'
            }

            # Package Count and Breakdown
            try {
                Write-DATActivityLog "[WMI] \\$SiteServer\root\SMS\Site_$($global:SiteCode) : SMS_Package (all packages)" -Level Info
                $allPackages = Invoke-DATRemoteQuery -CimSession $global:DATCimSession -ComputerName $SiteServer `
                    -Namespace "root\SMS\Site_$($global:SiteCode)" -ClassName SMS_Package
                $packageCount = ($allPackages | Measure-Object).Count
                $txt_ServerPackageCount.Text = $packageCount.ToString('N0')

                # Count packages by naming convention
                Write-DATActivityLog "[WMI] SMS_Package query returned $packageCount package(s)" -Level Info
                $driverCount = ($allPackages | Where-Object { $_.Name -like 'Drivers -*' } | Measure-Object).Count
                $biosCount = ($allPackages | Where-Object { $_.Name -like 'Bios Update -*' } | Measure-Object).Count
                $otherCount = $packageCount - $driverCount - $biosCount
                Write-DATActivityLog "[WMI] Package breakdown: $driverCount driver, $biosCount BIOS, $otherCount other" -Level Info

                Update-DATPackageDonutChart -DriverCount $driverCount -BiosCount $biosCount -OtherCount $otherCount

                # Count packages by manufacturer
                $mfrCounts = @{
                    'Dell'      = ($allPackages | Where-Object { $_.Name -match '- Dell ' } | Measure-Object).Count
                    'HP'        = ($allPackages | Where-Object { $_.Name -match '- HP ' -or $_.Name -match '- Hewlett-Packard ' } | Measure-Object).Count
                    'Lenovo'    = ($allPackages | Where-Object { $_.Name -match '- Lenovo ' } | Measure-Object).Count
                    'Microsoft' = ($allPackages | Where-Object { $_.Name -match '- Microsoft ' } | Measure-Object).Count
                    'Acer'      = ($allPackages | Where-Object { $_.Name -match '- Acer ' } | Measure-Object).Count
                }
                $mfrCounts['Other'] = $packageCount - ($mfrCounts.Values | Measure-Object -Sum).Sum

                Update-DATManufacturerDonutChart -Counts $mfrCounts
                $panel_PackageChart.Visibility = 'Visible'
            } catch {
                $txt_ServerPackageCount.Text = 'Not available'
            }

            # Repair driver packages with incorrect naming (multi-build format)
            try {
                Write-DATActivityLog "[Package Repair] Starting driver package name repair scan..." -Level Info
                $repairResults = Repair-DATDriverPackageNames -SiteServer $SiteServer -SiteCode $global:SiteCode
                $successCount = ($repairResults | Where-Object { $_.Status -eq 'Renamed' } | Measure-Object).Count
                if ($successCount -gt 0) {
                    Write-DATActivityLog "[Package Repair] Repaired $successCount driver package(s)" -Level Info
                    Show-DATInfoDialog -Title 'Driver Packages Repaired' `
                        -Message "Fixed $successCount driver package name$(if ($successCount -ne 1) { 's' }) that were using the old naming format with multiple build versions.`n`nPackage names have been updated to use the base Windows version only (e.g., 'Windows 11' instead of 'Windows 11 24H2;Windows 11 23H2')." `
                        -Type Success -ButtonLabel 'OK'
                } else {
                    Write-DATActivityLog "[Package Repair] No driver packages needing repair found" -Level Info
                }
            } catch {
                Write-DATActivityLog "[Package Repair] Error scanning for repairs: $($_.Exception.Message)" -Level Warn
            }

            # Resolve duplicate BIOS packages -- scan first, then prompt for opt-in before removing
            try {
                Write-DATActivityLog "[BIOS Duplicate] Scanning for duplicate BIOS packages..." -Level Info
                $scanResults = Remove-DATBiosDuplicatePackages -SiteServer $SiteServer -SiteCode $global:SiteCode -ScanOnly
                $wouldRemoveCount = ($scanResults | Where-Object { $_.Status -eq 'WouldRemove' } | Measure-Object).Count
                if ($wouldRemoveCount -gt 0) {
                    Write-DATActivityLog "[BIOS Duplicate] Found $wouldRemoveCount duplicate BIOS package(s) -- prompting user" -Level Info
                    $userConfirmed = Show-DATConfirmDialog `
                        -Title 'Duplicate BIOS Packages Found' `
                        -Message "Found $wouldRemoveCount duplicate BIOS package$(if ($wouldRemoveCount -ne 1) { 's' }) in ConfigMgr. The newest version of each model will be kept and stale duplicates removed.`n`nDo you want to clean up the duplicate packages now?" `
                        -Type Warning `
                        -ConfirmLabel 'Remove Duplicates' `
                        -CancelLabel 'Skip'
                    if ($userConfirmed) {
                        $duplicateResults = Remove-DATBiosDuplicatePackages -SiteServer $SiteServer -SiteCode $global:SiteCode
                        $removedCount = ($duplicateResults | Where-Object { $_.Status -eq 'Removed' } | Measure-Object).Count
                        if ($removedCount -gt 0) {
                            Write-DATActivityLog "[BIOS Duplicate] Removed $removedCount duplicate BIOS package(s)" -Level Info
                            Show-DATInfoDialog -Title 'Duplicate BIOS Packages Removed' `
                                -Message "Cleaned up $removedCount duplicate BIOS package$(if ($removedCount -ne 1) { 's' }) by keeping the newest BIOS version and removing stale duplicates.`n`nRemoved packages and their source folders have been deleted from Configuration Manager." `
                                -Type Success -ButtonLabel 'OK'
                        } else {
                            Write-DATActivityLog "[BIOS Duplicate] Removal run completed with no removals (may have already been cleaned)" -Level Info
                        }
                    } else {
                        Write-DATActivityLog "[BIOS Duplicate] User opted to skip duplicate removal" -Level Info
                    }
                } else {
                    Write-DATActivityLog "[BIOS Duplicate] No duplicate BIOS packages found" -Level Info
                }
            } catch {
                Write-DATActivityLog "[BIOS Duplicate] Error scanning for duplicates: $($_.Exception.Message)" -Level Warn
            }

            $panel_SiteServerInfo.Visibility = 'Visible'

            # Check for insufficient ConfigMgr permissions
            # If site code resolved but SMS_Site and SMS_Package returned nothing, the user lacks RBAC rights
            $noVersion = ([string]::IsNullOrEmpty($cmVersion))
            $noPkgs = ($null -eq $allPackages -or @($allPackages).Count -eq 0)
            if ($noVersion -and $noPkgs) {
                $panel_PackageChart.Visibility = 'Collapsed'
                $currentUser = [System.Security.Principal.WindowsIdentity]::GetCurrent().Name
                Show-DATInfoDialog -Title 'Insufficient Permissions' `
                    -Message "Connected to site $($global:SiteCode) on $($global:SiteServer), but the current account ($currentUser) does not have sufficient ConfigMgr permissions to read site data or packages.`n`nPlease ensure the account has at least the Read-only Analyst security role in Configuration Manager." `
                    -Type Warning -ButtonLabel 'OK'
            }

            # Populate Distribution Points and DP Groups
            $savedDPs = @()
            $savedDPGroups = @()
            try {
                $dpConfig = Get-ItemProperty -Path $global:RegPath -ErrorAction SilentlyContinue
                if (-not [string]::IsNullOrEmpty($dpConfig.SelectedDPs)) {
                    $savedDPs = @($dpConfig.SelectedDPs -split '\|')
                }
                if (-not [string]::IsNullOrEmpty($dpConfig.SelectedDPGroups)) {
                    # Support both old '|' delimiter and new ';;' delimiter for backwards compatibility
                    $savedDPGroups = if ($dpConfig.SelectedDPGroups -match ';;') {
                        @($dpConfig.SelectedDPGroups -split ';;')
                    } else {
                        @($dpConfig.SelectedDPGroups -split [regex]::Escape('|'))
                    }
                }
            } catch { }

            try {
                Write-DATActivityLog "[WMI] \\$SiteServer\root\SMS\Site_$($global:SiteCode) : SMS_SystemResourceList (Distribution Points)" -Level Info
                $script:DPData.Clear()
                $dpList = Get-DATDistributionPoints -SiteCode $global:SiteCode -SiteServer $SiteServer
                Write-DATActivityLog "[WMI] Distribution Points found: $(@($dpList).Count)" -Level Info
                foreach ($dp in $dpList) {
                    $script:DPData.Add([PSCustomObject]@{ Selected = ($dp -in $savedDPs); Name = $dp })
                }
            } catch {
                Write-DATLogEntry -Value "[Warning] - Failed to query distribution points: $($_.Exception.Message)" -Severity 2
            }

            try {
                Write-DATActivityLog "[WMI] \\$SiteServer\root\SMS\Site_$($global:SiteCode) : SMS_DistributionPointGroup" -Level Info
                $script:DPGroupData.Clear()
                $dpGroups = Get-DATDistributionPointGroups -SiteCode $global:SiteCode -SiteServer $SiteServer
                Write-DATActivityLog "[WMI] DP Groups found: $(@($dpGroups).Count)" -Level Info
                foreach ($grp in $dpGroups) {
                    $script:DPGroupData.Add([PSCustomObject]@{ Selected = ($grp -in $savedDPGroups); Name = $grp })
                }
            } catch {
                Write-DATLogEntry -Value "[Warning] - Failed to query DP groups: $($_.Exception.Message)" -Severity 2
            }

            # Enable ConfigMgr known model lookup if toggle is on
            if ($chk_KnownModels.IsChecked) {
                $btn_ConfigMgrKnownModelLookup.IsEnabled = $true
                Invoke-DATConfigMgrKnownModelLookup
            }
        } else {
            $txt_SiteCode.Foreground = $Window.FindResource('StatusWarning')
            $txt_SiteCode.Text = "Connection failed - no site code returned."
        }
    } catch {
        $txt_SiteCode.Foreground = $Window.FindResource('StatusError')
        $txt_SiteCode.Text = "Error: $($_.Exception.Message)"
    }
}

$btn_ConnectConfigMgr.Add_Click({
    Invoke-DATConfigMgrConnect -SiteServer $txt_SiteServer.Text -UseSSL $chk_WinRMSSL.IsChecked
})

$chk_WinRMSSL.Add_Checked({
    Set-DATRegistryValue -Name 'WinRMSSL' -Value 1 -Type DWord
})
$chk_WinRMSSL.Add_Unchecked({
    Set-DATRegistryValue -Name 'WinRMSSL' -Value 0 -Type DWord
})

$txt_SiteServer.Add_TextChanged({
    $val = $txt_SiteServer.Text.Trim()
    $btn_ConnectConfigMgr.IsEnabled = ($val.Length -gt 0)
})

