    if (-not [string]::IsNullOrEmpty($global:SiteCode)) {
        $btn_ConfigMgrKnownModelLookup.IsEnabled = $true
        Invoke-DATConfigMgrKnownModelLookup
    }
})
$chk_KnownModels.Add_Unchecked({
