# Row-click checkbox toggle for Packages grid
$grid_Packages.Add_PreviewMouseLeftButtonDown({
    param($s, $e)
    $dep = $e.OriginalSource
    $inCheckboxCol = $false
    while ($null -ne $dep -and $dep -isnot [System.Windows.Controls.DataGridRow]) {
        if ($dep -is [System.Windows.Controls.Primitives.DataGridColumnHeader]) { return }
        if ($dep -is [System.Windows.Controls.DataGridCell] -and
            $dep.Column -is [System.Windows.Controls.DataGridCheckBoxColumn]) {
            $inCheckboxCol = $true
        }
        $dep = [System.Windows.Media.VisualTreeHelper]::GetParent($dep)
    }
    if ($null -ne $dep -and -not $inCheckboxCol) {
        $item = $dep.DataContext
        if ($null -ne $item -and $item.PSObject.Properties['Selected']) {
            $item.Selected = -not $item.Selected
            $Window.Dispatcher.BeginInvoke([System.Windows.Threading.DispatcherPriority]::Background, [action]{
                Update-DATCmDeleteSelectedState
            })
        }
    }
})

# Space bar: toggle the currently selected row.
$grid_Packages.Add_PreviewKeyDown({
    param($s, $e)
    if ($e.Key -ne [System.Windows.Input.Key]::Space) { return }
    $row = $grid_Packages.ItemContainerGenerator.ContainerFromItem($grid_Packages.SelectedItem)
    if ($null -ne $row) {
        $checkbox = Find-DATVisualChild -Parent $row -TypeName 'CheckBox'
        if ($null -ne $checkbox) {
            $checkbox.IsChecked = -not $checkbox.IsChecked
            $Window.Dispatcher.BeginInvoke([System.Windows.Threading.DispatcherPriority]::Background, [action]{
                Update-DATCmDeleteSelectedState
            })
        }
    }
    $e.Handled = $true
})

function Invoke-DATPackageRefresh {
    if ([string]::IsNullOrEmpty($global:SiteCode) -or [string]::IsNullOrEmpty($global:SiteServer)) {
        $txt_PkgStatus.Foreground = $Window.FindResource('StatusWarning')
        $txt_PkgStatus.Text = "Not connected to ConfigMgr. Please connect first."
        $txt_PkgStatus.Visibility = 'Visible'
        Write-DATLogEntry -Value "[Warning] - Not connected to ConfigMgr. Cannot refresh packages." -Severity 2
        return
    }

    # Prevent overlapping refreshes
    if ($null -ne $script:PkgRefreshTimer -and $script:PkgRefreshTimer.IsEnabled) { return }

    $script:PackageData.Clear()

    $pkgType = if ($null -ne $cmb_PkgPackageType.SelectedItem) { $cmb_PkgPackageType.SelectedItem.Content } else { 'Drivers' }
    $deployState = if ($null -ne $cmb_DeploymentState.SelectedItem) { $cmb_DeploymentState.SelectedItem.Content } else { 'Production' }

    # Build the name prefix: "Drivers -", "Drivers Pilot -", "BIOS Update Retired -", etc.
    $typePrefix = switch ($pkgType) {
        'BIOS Update'    { 'BIOS Update' }
        'Drivers Pilot'  { 'Drivers Pilot' }
        'BIOS Pilot'     { 'BIOS Update Pilot' }
        default          { 'Drivers' }
    }
    # For pilot package types, skip the deployment state infix (pilot is already in the type)
    $isPilotType = $pkgType -like '* Pilot'
    $stateInfix = if ($isPilotType) { '' } else {
        switch ($deployState) {
            'Pilot'   { ' Pilot' }
            'Retired' { ' Retired' }
            default   { '' }
        }
    }
    # Handle "All Pilot" - query both prefixes
    if ($pkgType -eq 'All Pilot') {
        $namePrefix = $null  # Signal to query both
        $namePrefixes = @('Drivers Pilot -*', 'BIOS Update Pilot -*')
    } else {
        $namePrefix = "$typePrefix$stateInfix -*"
        $namePrefixes = @($namePrefix)
    }
    $displayLabel = if ($stateInfix) { "$pkgType ($deployState)" } else { $pkgType }

    $txt_PkgStatus.Foreground = $Window.FindResource('StatusInfo')
    $txt_PkgStatus.Text = "Querying $displayLabel packages..."
    $txt_PkgStatus.Visibility = 'Visible'
    $btn_RefreshPkgs.IsEnabled = $false

    # Run WMI query in a background runspace to keep the UI responsive
    $script:PkgRefreshRunspace = [runspacefactory]::CreateRunspace()
    $script:PkgRefreshRunspace.ApartmentState = 'STA'
    $script:PkgRefreshRunspace.Open()

    $script:PkgRefreshPS = [powershell]::Create()
    $script:PkgRefreshPS.Runspace = $script:PkgRefreshRunspace
    [void]$script:PkgRefreshPS.AddScript({
        param($SiteServer, $SiteCode, $NamePrefixes)
        try {
            # Create CIM session with DCOM/short-name/WMI fallback (module not available in runspace)
            $cimSess = $null
            $useLegacyWmi = $false
            try { $cimSess = New-CimSession -ComputerName $SiteServer -OperationTimeoutSec 15 -ErrorAction Stop }
            catch {
                try { $cimSess = New-CimSession -ComputerName $SiteServer -SessionOption (New-CimSessionOption -Protocol Dcom) -ErrorAction Stop }
                catch {
                    if ($SiteServer -match '\.') {
                        $shortName = $SiteServer.Split('.')[0]
                        try { $cimSess = New-CimSession -ComputerName $shortName -OperationTimeoutSec 15 -ErrorAction Stop }
                        catch {
                            try { $cimSess = New-CimSession -ComputerName $shortName -SessionOption (New-CimSessionOption -Protocol Dcom) -ErrorAction Stop }
                            catch { $useLegacyWmi = $true }
                        }
                    } else { $useLegacyWmi = $true }
                }
            }
            $results = @()
            foreach ($NamePrefix in $NamePrefixes) {
            $wqlSafe = $NamePrefix.Replace("'", "''").Replace('[', '[[').Replace('_', '[_]').Replace('*', '%')
            $wmiFilter = "Name LIKE '$wqlSafe'"
            if ($useLegacyWmi) {
                $packages = Get-WmiObject -ComputerName $SiteServer -Namespace "root\SMS\Site_$SiteCode" -Query "SELECT * FROM SMS_Package WHERE $wmiFilter" -ErrorAction Stop
            } else {
                $packages = Get-CimInstance -CimSession $cimSess -Namespace "root\SMS\Site_$SiteCode" -ClassName SMS_Package -Filter $wmiFilter -ErrorAction Stop
            }
            foreach ($pkg in $packages) {
                $pkgModel = ''
                if ($pkg.Name -match '^(?:Drivers|BIOS Update)(?:\s+(?:Pilot|Retired))?\s*-\s*(.+)$') {
                    $pkgModel = $Matches[1].Trim()
                }
                $results += [PSCustomObject]@{
                    Selected        = $false
                    Name            = $pkg.Name
                    Version         = $pkg.Version
                    PackageID       = $pkg.PackageID
                    SourceDate      = if ($pkg.SourceDate) { try { [Management.ManagementDateTimeConverter]::ToDateTime($pkg.SourceDate).ToString('yyyy-MM-dd HH:mm') } catch { '' } } else { '' }
                    Manufacturer    = if ($pkg.Manufacturer) { $pkg.Manufacturer } else { '' }
                    Model           = $pkgModel
                    OperatingSystem = if ($pkg.MIFVersion) { ($pkg.MIFVersion -replace '\s+(x64|Arm64)$','').Trim() } else { '' }
                }
            }
            }
            return $results
        } catch {
            return [PSCustomObject]@{ _Error = $_.Exception.Message }
        }
    })
    [void]$script:PkgRefreshPS.AddArgument($global:SiteServer)
    [void]$script:PkgRefreshPS.AddArgument($global:SiteCode)
    [void]$script:PkgRefreshPS.AddArgument($namePrefixes)

    $script:PkgRefreshAsyncResult = $script:PkgRefreshPS.BeginInvoke()

    # Poll for completion via DispatcherTimer (keeps UI responsive)
    $script:PkgRefreshDisplayLabel = $displayLabel
    $script:PkgRefreshTimer = New-Object System.Windows.Threading.DispatcherTimer
    $script:PkgRefreshTimer.Interval = [TimeSpan]::FromMilliseconds(250)
    $script:PkgRefreshTimer.Add_Tick({
        if ($script:PkgRefreshAsyncResult.IsCompleted) {
            $script:PkgRefreshTimer.Stop()

            try {
                $results = $script:PkgRefreshPS.EndInvoke($script:PkgRefreshAsyncResult)

                # Check for error object
                $errorResult = $results | Where-Object { $_ -is [PSCustomObject] -and $_._Error }
                if ($errorResult) {
                    $txt_PkgStatus.Foreground = $Window.FindResource('StatusError')
                    $txt_PkgStatus.Text = "Error: $($errorResult._Error)"
                    Write-DATLogEntry -Value "[Error] - Failed to query packages: $($errorResult._Error)" -Severity 3
                } else {
                    foreach ($item in $results) {
                        if ($null -ne $item -and $null -eq $item._Error) {
                            $script:PackageData.Add($item)
                        }
                    }

                    $label = $script:PkgRefreshDisplayLabel
                    $txt_PkgStatus.Foreground = $Window.FindResource('StatusSuccess')
                    $txt_PkgStatus.Text = "Loaded $($script:PackageData.Count) $label package$(if ($script:PackageData.Count -ne 1) { 's' })"
                    Write-DATLogEntry -Value "- Loaded $($script:PackageData.Count) packages matching '$label'" -Severity 1

                    # Apply warning highlighting to reported packages
                    Update-DATPackageRowHighlighting -DataGrid $grid_Packages -ItemsSource $script:PackageData -MakeProperty 'Manufacturer' -ModelProperty 'Model' -VersionProperty 'Version'

                    # Populate the OS filter dropdown: merge static builds with distinct values from loaded data
                    $staticBuilds = @('Windows 11 25H2', 'Windows 11 24H2', 'Windows 11 23H2', 'Windows 11 22H2', 'Windows 11 21H2')
                    $packageOSValues = $script:PackageData | Where-Object { -not [string]::IsNullOrEmpty($_.OperatingSystem) } |
                        Select-Object -ExpandProperty OperatingSystem -Unique
                    $allOSValues = @($staticBuilds) + @($packageOSValues) | Select-Object -Unique | Sort-Object
                    $prevOS = if ($null -ne $cmb_CmPkgOS.SelectedItem) { $cmb_CmPkgOS.SelectedItem.Content } else { 'All' }
                    $cmb_CmPkgOS.Items.Clear()
                    $allItem = [System.Windows.Controls.ComboBoxItem]::new()
                    $allItem.Content = 'All'
                    $cmb_CmPkgOS.Items.Add($allItem) | Out-Null
                    foreach ($osVal in $allOSValues) {
                        $osItem = [System.Windows.Controls.ComboBoxItem]::new()
                        $osItem.Content = $osVal
                        $cmb_CmPkgOS.Items.Add($osItem) | Out-Null
                    }
                    $restore = $cmb_CmPkgOS.Items | Where-Object { $_.Content -eq $prevOS }
                    $cmb_CmPkgOS.SelectedItem = if ($restore) { $restore } else { $cmb_CmPkgOS.Items[0] }
                }
            } catch {
                $txt_PkgStatus.Foreground = $Window.FindResource('StatusError')
                $txt_PkgStatus.Text = "Error: $($_.Exception.Message)"
                Write-DATLogEntry -Value "[Error] - Failed to query packages: $($_.Exception.Message)" -Severity 3
            } finally {
                $script:PkgRefreshPS.Dispose()
                $script:PkgRefreshRunspace.Dispose()
                $btn_RefreshPkgs.IsEnabled = $true
            }

            # Detect old-format BIOS package names AFTER cleanup so any subsequent
            # Invoke-DATPackageRefresh does not conflict with the disposed runspace
            Invoke-DATCmBiosNameCheck
        }
    })
    $script:PkgRefreshTimer.Start()
}

$btn_RefreshPkgs.Add_Click({ Invoke-DATPackageRefresh })

# Check loaded ConfigMgr BIOS packages for old-format names and prompt if needed
function Invoke-DATCmBiosNameCheck {
    if ($script:PackageData.Count -eq 0) { return }
    $oldBiosNames = @($script:PackageData | Where-Object {
        $_.Name -match '^BIOS Update' -and $_.Name -match '\s*-\s*(x64|Arm64)\s*$'
    })
    if ($oldBiosNames.Count -gt 0) {
        $fixNow = Show-DATBiosNamePromptModal -Platform 'ConfigMgr' -Count $oldBiosNames.Count
        if ($fixNow) {
            Show-DATBiosNameRepairModal -Platform 'ConfigMgr'
            Invoke-DATPackageRefresh
        }
    }
}

$cmb_PkgPackageType.Add_SelectionChanged({
    $pkgType = if ($null -ne $cmb_PkgPackageType.SelectedItem) { $cmb_PkgPackageType.SelectedItem.Content } else { 'Drivers' }
    $isBios = ($pkgType -eq 'BIOS Update')
    $osVisibility = if ($isBios) { 'Collapsed' } else { 'Visible' }
    $cmb_CmPkgOS.Visibility = $osVisibility
    $lbl_CmPkgOS.Visibility = $osVisibility
    if ($isBios) { $cmb_CmPkgOS.SelectedIndex = 0 }
    Invoke-DATPackageRefresh
})
$cmb_DeploymentState.Add_SelectionChanged({ Invoke-DATPackageRefresh })

# Combined filter for ConfigMgr packages: OEM + OS + search text
function Update-DATCmPackageFilter {
    $view = [System.Windows.Data.CollectionViewSource]::GetDefaultView($grid_Packages.ItemsSource)
    if ($null -eq $view) { return }

    $pkgType = if ($null -ne $cmb_PkgPackageType.SelectedItem) { $cmb_PkgPackageType.SelectedItem.Content } else { 'Drivers' }
    $oemFilter = if ($null -ne $cmb_CmPkgOEM.SelectedItem) { $cmb_CmPkgOEM.SelectedItem.Content } else { 'All' }
    $osFilter = if ($null -ne $cmb_CmPkgOS.SelectedItem) { $cmb_CmPkgOS.SelectedItem.Content } else { 'All' }
    $searchText = $txt_CmPkgSearch.Text

    $isBios = ($pkgType -eq 'BIOS Update')
    $hasOem = ($oemFilter -ne 'All')
    $hasOs = (-not $isBios -and $osFilter -ne 'All')
    $hasSearch = (-not [string]::IsNullOrEmpty($searchText))

    if (-not $hasOem -and -not $hasOs -and -not $hasSearch) {
        $view.Filter = $null
    } else {
        $view.Filter = [System.Predicate[object]]{
            param($item)
            if ($hasOem -and $item.Manufacturer -ne $oemFilter) { return $false }
            if ($hasOs -and $item.OperatingSystem -ne $osFilter) { return $false }
            if ($hasSearch) {
                if ($item.Name -notlike "*$searchText*" -and
                    $item.PackageID -notlike "*$searchText*" -and
                    $item.Version -notlike "*$searchText*") { return $false }
            }
            return $true
        }
    }
}

$txt_CmPkgSearch = $Window.FindName('txt_CmPkgSearch')
$txt_CmPkgSearch.Add_TextChanged({ Update-DATCmPackageFilter })
$cmb_CmPkgOEM.Add_SelectionChanged({ Update-DATCmPackageFilter })
$cmb_CmPkgOS.Add_SelectionChanged({ Update-DATCmPackageFilter })

